window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["k"]={"Krzysztof": "<b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Kamil": "<b>Kamil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od rzymskiego imienia i <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognomenu</a> <i>Camillus</i> (słowo to jest tłumaczone z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> jako „pomocnik kapłana” bądź „zrodzony z wolnych rodziców”, „szlachetny chłopiec”).", "Kazimierz": "<b>Kazimierz</b> – współcześnie przyjęta forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> męskiego <b>Kazimir</b> (z odmiankami <b>Kazimirz</b>, <b>Kazimiar</b>, <b>Kazimier</b>, <b>Kaźmir</b>, <b>Kaźmisz</b>), składającego się z członów: <i>Kazi-</i> („niszcz, psuj, niwecz” od <i>kazić</i> „niszczyć, psuć”, porównaj współczesne <i>od-kazić</i> „od-psuć”) i <i>-mir</i> („pokój, spokój”). Oznacza „ten, który (niech) niszczy pokój” – niszcz pokój! = kaź mir! (staropolskie kazi mir!).", "Kacper": "<b>Kacper</b>, <b>Kasper</b>, <b>Kaspar</b>, <b>Gaspar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, oboczności powstałe jako przekształcenie imienia Kasper, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> <i>ganzabara</i> („strażnik skarbca”) od <i>*ganzah</i> (“skarb”) + <i>*barah</i> (“brzemię”), od praindoeuropejskiego <i>*bʰer-</i> („brać”).", "Karol": "<b>Karol</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankijskiego</a> oznaczające człowieka mężnego lub wojownika. Staroskandynawskie znaczenie – „człowiek, mąż”. Imię jest również rozpowszechnione w krajach latynoskich.", "Krystian": "<b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Konrad": "<b>Konrad</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od staroniemieckiego słowa <i>kuoni</i> oznaczającego „odważny”, „śmiały”, „silny” oraz staroniemieckiego <i>rath</i> oznaczającego „radę”. Oznacza więc kogoś dającego dobre rady, dobrego doradcę. Imię rycerzy i książąt, przywędrowało do Polski w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a> z <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">Niemiec</a>.", "Ksawery": "<b>Ksawery</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Pochodzi od nazwy miejscowości, z której pochodził <a href=\"https://pl.wikipedia.org/wiki/Franciszek_Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszek Ksawery</a> (<i>Javier</i>). Początkowo używane tylko w złożeniu z Franciszkiem (analogicznie do <a href=\"https://pl.wikipedia.org/wiki/Jan_Kanty\" target=\"_blank\" rel=\"noopener noreferrer\">Kantego</a>). Oboczna, bardziej archaiczna pisownia – <b>Xawery</b>.", "Kajetan": "<b>Kajetan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pierwotnie oznaczało „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Gaeta\" target=\"_blank\" rel=\"noopener noreferrer\">Caiety</a>”, miasta w <a href=\"https://pl.wikipedia.org/wiki/Italia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Italii</a>. Na Kresach imię to cieszyło się szczególną popularnością wśród mniejszości <a href=\"https://pl.wikipedia.org/wiki/Ormianie_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiej</a>.", "Kornel": "<b>Kornel</b>, <b>Korneliusz</b>, <b>Korneli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Cornelii</i> (<i>Korneliuszy</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusze Cynna</a>). Istnieją różne hipotezy pochodzenia wspomnianej nazwy rodowej; wywodzi się ją bądź to ze słowa <i>cornu</i> („róg”), bądź to <i>cornus</i> („<a href=\"https://pl.wikipedia.org/wiki/Dere%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dereń</a>”), bądź to od nazwy pola <i>Corne</i> w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. W dawnej Polsce zapisywane od <a href=\"https://pl.wikipedia.org/wiki/1402\" target=\"_blank\" rel=\"noopener noreferrer\">1402</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> formie <i>Cornelius</i> oraz od <a href=\"https://pl.wikipedia.org/wiki/1412\" target=\"_blank\" rel=\"noopener noreferrer\">1412</a> roku w formach pochodnych Kornosz, Kornasz, Korna (masc.), Kornosza (masc.), Kornoszek i ze zdrobnieniami Nela (masc.), Nelka (masc.), Nelko.", "Konstanty": "<b>Konstanty</b>, <b>Konstantyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> przydomka <i>Constantinus</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>constans</em> znaczącego „stały, stateczny, konsekwentny”. Żeńskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Konstantyna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantyna</a> lub <a href=\"https://pl.wikipedia.org/wiki/Konstancja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Konstancja</a>. W Polsce imię znane co najmniej od XV wieku.", "Kostiantyn": "<p>Kostyantyn lub Kostiantyn to imię. Znanymi osobami z nazwiska są: Kostyantyn Balabanov (ur. 1982), ukraiński piłkarz koszykówki Kostyantyin Bocharov (ur., 1997), ukraiński piosenkarz i autor utworów Kostyantin Dankevych (1905-1984), ukraińskiego kompozytora i nauczyciela muzycznego Kostyantyna Doroshenko (ur. 1972), krytyka sztuki Ukrainy, kurator współczesnej sztuki, menedżer mediów, nadawca radiowy stacji rozmowy Radio Vesti (Ukraina) Kostyantyny...</p>", "Klaudiusz": "<b>Klaudiusz</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a>, pochodzące od nazwy <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskich</a> rodów <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudiuszy</a>; nazwa ta zaś wywodzi się od nazwy miasta <i>Clausus</i>, skąd oba rody Klaudiuszy wzięły początek. W Polsce imię Klaudiusz jest znane od <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>.", "Kevin": "<p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kordian": "<b>Kordian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone przez <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a>. Oznacza <i>dający serce</i>. Kordian obchodzi imieniny <a href=\"https://pl.wikipedia.org/wiki/22_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">22 października</a>.", "Klemens": "<b>Klemens</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „człowiek o łagodnym usposobieniu”, „delikatny”, „pobłażliwy”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Klemencja\" target=\"_blank\" rel=\"noopener noreferrer\">Klemencja</a>.", "Kewin": "<b>Kewin</b> – imię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, powstałe od imienia <i>Caoimhín</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroirlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">st. irl.</a> <i>Coemgen</i>), oznaczającego „ładny, przystojny”.", "Kasper": "<b>Kacper</b>, <b>Kasper</b>, <b>Kaspar</b>, <b>Gaspar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, oboczności powstałe jako przekształcenie imienia Kasper, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> <i>ganzabara</i> („strażnik skarbca”) od <i>*ganzah</i> (“skarb”) + <i>*barah</i> (“brzemię”), od praindoeuropejskiego <i>*bʰer-</i> („brać”).", "Korneliusz": "Polska forma imienia obecna w tekście <i><a href=\"https://pl.wikipedia.org/wiki/Dzieje_Apostolskie\" target=\"_blank\" rel=\"noopener noreferrer\">Dziejów Apostolskich</a></i> jako imię <a href=\"https://pl.wikipedia.org/wiki/Korneliusz_(setnik_rzymski)\" target=\"_blank\" rel=\"noopener noreferrer\">setnika</a> z Cezarei (rozdz. 10): Korneliusz (<i><a href=\"https://pl.wikipedia.org/wiki/Biblia_Jakuba_Wujka\" target=\"_blank\" rel=\"noopener noreferrer\">Biblia Wujka</a></i>, 1599), Kornelijusz (<i><a href=\"https://pl.wikipedia.org/wiki/Biblia_gda%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Biblia gdańska</a></i>, 1632). Łacińska forma imienia <i>Cornēlius</i> została utrwalona w tekście greckim <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowego Testamentu</a> jako <i>Κορνήλιος</i> (<a href=\"https://pl.wikipedia.org/wiki/Koine\" target=\"_blank\" rel=\"noopener noreferrer\">koine</a>). Imię w tej formie wywodzi się od nazwy rzymskiego rodu <i>Cornelia</i> (<a href=\"https://pl.wikipedia.org/wiki/Gens\" target=\"_blank\" rel=\"noopener noreferrer\">gens</a> Cornelia). <i><a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">Nomen gentilicium</a></i> pochodziło od nazwy pola „Corne” w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. Podawane jest też w opracowaniach pochodzenie od <i>cornu</i> w znaczeniu „róg”. Wówczas imię oznaczałoby „słoneczny” (symbol królewski).", "Kiryl": "<p>Mężczyzna Cyril (lub Kiril lub Кирилл) jest powszechną nazwą w świecie prawosławskich słowiańskich, zwłaszcza w Bułgarii, Macedonii Północnej i Rosji. Jest również dobrze znany w Grecji, ale w różnych formach, takich jak Kyriakos.</p>", "Kryspin": "<b>Kryspin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotnie stanowiące zdrobnienie od łac. imienia męskiego <i>Crispus</i>, które powstało z przymiotnika oznaczającego „kędzierzawy”. Kryspin po raz pierwszy został poświadczony w Polsce w <a href=\"https://pl.wikipedia.org/wiki/1226\" target=\"_blank\" rel=\"noopener noreferrer\">1226</a> roku, w formach <i><b>Krzyszpin</b></i> i <i><b>Kryspin</b></i>. Możliwe staropolskie zdrobnienia to: Krzysz, Krzysza, Krzyszcz, Krzyszczek, Krzyszczko, Krzyszczk, Krzyszek, Krzyszka, Krzyszko, Krzyszna, Krzych, Krzychna.", "Kiril": "<p>Mężczyzna Cyril (lub Kiril lub Кирилл) jest powszechną nazwą w świecie prawosławskich słowiańskich, zwłaszcza w Bułgarii, Macedonii Północnej i Rosji. Jest również dobrze znany w Grecji, ale w różnych formach, takich jak Kyriakos.</p>", "Kosma": "<b>Kosma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;κόσμος oznaczającego „porządek, ład”, „ozdobić”. Często wiązane z imieniem <a href=\"https://pl.wikipedia.org/wiki/Damian\" target=\"_blank\" rel=\"noopener noreferrer\">Damian</a> – od śś. <a href=\"https://pl.wikipedia.org/wiki/Kosma_i_Damian\" target=\"_blank\" rel=\"noopener noreferrer\">Kosmy i Damiana</a> (†283).", "Kasjan": "<b>Kasjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">rodu</a> <a href=\"https://pl.wikipedia.org/wiki/Republika_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> <i>Cassianus</i>. Imię to nosiło około dwunastu <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty\" target=\"_blank\" rel=\"noopener noreferrer\">świętych</a> lub <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ogos%C5%82awiony\" target=\"_blank\" rel=\"noopener noreferrer\">błogosławionych</a>. W Polsce imię wystąpiło w 1445 roku jako Cassianus (Kasyjan). Później było rzadkie i ma niewielką popularność. W 2015 r. imię to nadano 27 chłopcom, w 2016 r. – 43, w 2017 r. – 61. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 1476 mężczyzn o imieniu Kasjan nadanym jako imię pierwsze.", "Kyryl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cyryl</b>.</p><b>Cyryl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>. Wywodzi się ze słowa κύριος znaczącego „pan”, „władca”. W Polsce używane było rzadko, częściej natomiast na Rusi Czerwonej.", "Kai": "<b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Kirill": "<p>Kirill (rosyjski: Кирилл) rosyjskie imię męskie, pochodzące od greckiego imienia Κύριλλος (Kyrillos), które z kolei pochodzą z greckiego κύριος (kyrios) \"pan\". Istnieje wiele wariantów nazwy: Cyryl, Cyrill, Kyrill, Kiryl, Kirillos, Kyryl, Kiril, Kyrylo, Kiro.</p>", "Karim": "<b>Karim</b> (<b>كريم</b>) – imię pochodzenia arabskiego, jest czterdziestym trzecim z „Najpiękniejszych imion Allaha”. Oznacza dosłownie „hojny”.", "Karl": "<p>Karl Kurzwazje (niem. Karl Fr.</p>", "Kristian": "<b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Krzesimir": "W Polsce imię Krzesimir jest łączone z chorwackim imieniem <b>Krešimir</b> lub <a href=\"https://pl.wikipedia.org/wiki/Hipokorystyk\" target=\"_blank\" rel=\"noopener noreferrer\">hipokorystycznie</a> <b>Krešo</b>, o podobnym lub takim samym pochodzeniu: od <i>kres-</i> (\"iskra, płomień, światło, ognisko\"). Niekiedy jednak przypisuje się mu nieco inną etymologię: od <i>kresiti</i>, czyli <i><a href=\"https://pl.wiktionary.org/wiki/krasiti\" target=\"_blank\" rel=\"noopener noreferrer\">krasiti</a></i>: 'ozdabiać, stroić'. W sensie przenośnym imię miało wyrażać życzenie rodziców, aby dziecko było spokojne, opanowane, zadowolone i cieszyło się pokojem. Czasem czasownik <i>krešati</i> tłumaczy się jako <i>walczyć</i>, a znaczenie całego imienia jako 'wojownik i władca'. Jeszcze indziej imię wiąże się z kultem świętego <a href=\"https://pl.wikipedia.org/wiki/Chryzogon_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">Krševana</a> (por. <a href=\"https://pl.wikipedia.org/wiki/Kr%C5%A1evan_Santini\" target=\"_blank\" rel=\"noopener noreferrer\">Krševan Santini</a>, <a href=\"https://pl.wikipedia.org/wiki/Chryzogon\" target=\"_blank\" rel=\"noopener noreferrer\">Chryzogon</a>).", "Krystyn": "<b>Krystyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> wywodzące się od wyrazu <a href=\"https://pl.wikipedia.org/wiki/Pomazaniec\" target=\"_blank\" rel=\"noopener noreferrer\">Pomazaniec</a> (<i>Chrystus</i>), do którego dodano przyrostek <i>-inus</i> wskazujący na zależność lub pochodzenie (<i>Christinus</i>, 'należący do Chrystusa, Chrystusowy'). W dokumentach polskich poświadczone w XI wieku w formie łacińskiej, a od XII w. w formie spolszczonej <i>Krystyn</i>.", "Karen": "<p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kenneth": "<p>Kenneth może odnosić się do: Kenneth Arrow Kenneth Pitzer Kenneth Pitzer</p>", "Krishna": "<p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Kamal": "<p>Kamal (Martin Engels, Martin Engels, urodzony 18 kwietnia 1956 roku w Bilefeld, Niemcy) - niemiecki muzykiem i reżyserem dźwięku. Studiował muzykę w Düsseldorf, później pracował w Bielefeld.</p>", "Kakhaber": "<p>Kakhaber (georgijski: კახაბერ) to gruzińskie imię męskie i odnosi się do: Kakhaber Aladashvili (ur. 1983), gruziński piłkarz Kakhaber Gogichaishvili (ur., 1968), gruzińskiego piłkarza Kakha Kaladze (ur. 1978), gruzińskiego piłkarze Kakhaber Tskhadadze (ur. 1968), gruzyńskiego piłki nożnej Kakhaber Zhvania, gruzińskiej bokserki</p>", "Khvicha": "<p>Khvicha (georgijski: ხვიჩა) to męska gruzińska nazwisko, które może odnosić się do: Khvicha Kvaratskhelia, gruziński piłkarz Khvicha Jakhaia, gruzińskiego piłkarza polo wodnego Khvicha Bichinashvili, azerbajdżanskiego walczyciela pochodzenia gruzińskiej Khvicha Supatashvili, gruzińskiego szachowca</p>", "Kostyantyn": "<p>Kostyantyn lub Kostiantyn to imię. Znanymi osobami z nazwiska są: Kostyantyn Balabanov (ur. 1982), ukraiński piłkarz koszykówki Kostyantyin Bocharov (ur., 1997), ukraiński piosenkarz i autor utworów Kostyantin Dankevych (1905-1984), ukraińskiego kompozytora i nauczyciela muzycznego Kostyantyna Doroshenko (ur. 1972), krytyka sztuki Ukrainy, kurator współczesnej sztuki, menedżer mediów, nadawca radiowy stacji rozmowy Radio Vesti (Ukraina) Kostyantyny...</p>", "Kaj": "Na starożytność tego imienia wskazuje <a href=\"https://pl.wikipedia.org/wiki/Ortografia\" target=\"_blank\" rel=\"noopener noreferrer\">pisownia</a> jego skrótu, którym tradycyjnie było <i>C.</i> <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">Litera</a> ta pierwotnie oznaczała głoskę <i>g</i>, gdyż pochodziła ona od greckiej <i><a href=\"https://pl.wikipedia.org/wiki/Gamma\" target=\"_blank\" rel=\"noopener noreferrer\">Γ</a></i> (zaś litera <i>K</i> oznaczała głoskę <i>k</i>). Te dwie litery stosowano w ten właśnie sposób do roku <a href=\"https://pl.wikipedia.org/wiki/312_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">312 p.n.e.</a>, kiedy cenzor <a href=\"https://pl.wikipedia.org/wiki/Appiusz_Klaudiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Appiusz Klaudiusz</a> zmienił pisownię, wprowadzając literę <i>G</i> powstałą z przekształcenia <i>C</i>, a literze <i>C</i> nadał wartość głoski <i>k</i>. Oznacza to, że pisownia skrótu imienia <i>Gaius</i> utrwaliła się jeszcze przed reformą, a więc i samo imię musi pochodzić sprzed <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>", "Kemal": "<p>Mustafa Kemal Atatürk (Turkish pronunciation: [musˈtafa ceˈmal ataˈtyɾk]; (19 maja 1881 - 10 listopada 1938) był oficerem wojskowym, rewolucjonistą i patriotą, a także pierwszym prezydentem Republiki Turcji. Atatürk był znany z uznania za sztuczną w czasie I wojny światowej.</p>", "Khaled": "<p>Khaled Haj Ibrahim (arabski خالد حاج إبراهيم; 29 lutego 1960, Oran, Algier) - algierski piosenkarz i muzykiem w stylu raji - mieszanki muzyki berberskiej i południowoeuropejskiej.</p>", "Konstantinos": "<p>Konstantinos lub Constantinos (Κωνσταντίνος, Konstantínos) to greckie imię męskie. Konstantinos \"Kosta\" Barbarouses (ur. 1990), nowozelandski piłkarz Konstantinos Chalkias (ur. 1974), grecki piłkarze Konstadinos Gatsioudis (ur. 1973), grecki sportowca Konstantinos Gavras (ur. 1933, znany profesjonalnie jako \"Costa-Gavras\"), grecko-francuski filmowiec Konstantinos Kanaris (1790-1877), grecki admirał i człowiek stanu, były premier...</p>", "Kilian": "<b>Kilian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, etymologicznie wiążące się ze słowem <i>gillean</i> „mnich”. Angielska, polska i niemiecka forma imienia <i>Cillian</i> pochodzi od słowa <i>ceallach</i> oznaczającego „wojna” lub <i>ceall</i> oznaczającego „kościół”. Istnieją zapisy tego imienia w Polsce pochodzące jeszcze ze średniowiecza.", "Khalid": "<p>Khalid Donnel Robinson - amerykański piosenkarz, laureat i nominac wielu nagród muzycznych.</p>", "Kenan": "Księga Jubileuszów (rozdział 4) podaje również imię jego matki – Noam, imię jego żony i zarazem siostry – Melelet, oraz syna – Rasujal.", "Khasan": "<p>Khasan (rosyjski: Хасан) to miejscowość miastna (urbanizacja) w dzielnicy Khasansky w regionie Primorsky Krai, Rosja. Znajduje się niedaleko przejścia rzeki Dżomon, gdzie graniczą trzy kraje: Rosja, Chiny i Republika Demokratyczna Ludowa Korei.</p>", "Kim": "<p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Konstantine": "<p>Konstantine to męskie imię. Do wybitnych osób z nazwą należą: Kote Abchazi (1867 - 1923), książę gruziński, generał major, polityk i antysowjetyczny nacjonalista Konstantyn Andronikachvili (1876 - 1937), georgijski polityk, członek antysowjówskiego oporu Konstantyn Bagration z Mukhrani (1838-1903), gruziński szlachetnik i oficer wojskowy Konstantyn Bagration z Mukhrani 1889-1915), georgian książę Konstantyn Dadeshkeliani ...</p>", "Kirilo": "<p>Mężczyzna imieniem Kirilo (Serbski cyrylski: Кирило) jest pierwsze imię powszechnie stosowane wśród Serbów i innych Słowian Południowych, głównie w Serbii, Czarnogórii i Bośni i Hercegowinie. Pochodzące z niego, jest to greckie imię (grecki: Κύριλλος).</p>", "Karel": "<p>Karel to język nauczania programowania, stworzony w 1981 roku przez Richarda Pattisa w swojej książce Karel The Robot: A Gentle Introduction to the Art of Programming. Pattice używał tego języka w swoich kursach na Uniwersytecie Stanfordzkim.</p>", "Kristof": "<p>Kristof, Krištof lub Kristóf mogą być zarówno nazwiskiem, jak i nazwiskiem. Do wybitnych osób z tym nazwiskiem należą:</p>", "Kakhaberi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kakhaber</b>.</p><p>Kakhaber (georgijski: კახაბერ) to gruzińskie imię męskie i odnosi się do: Kakhaber Aladashvili (ur. 1983), gruziński piłkarz Kakhaber Gogichaishvili (ur., 1968), gruzińskiego piłkarza Kakha Kaladze (ur. 1978), gruzińskiego piłkarze Kakhaber Tskhadadze (ur. 1968), gruzyńskiego piłki nożnej Kakhaber Zhvania, gruzińskiej bokserki</p>", "Kris": "<p>Chris (pol. Kris; prawdziwe imię - Kshshштоf Piotrovski, płeć.</p>", "Krasimir": "<p>Krasimir (bułgarski: Красимир) jest powszechną nazwą męską w Bułgarii. Pochodzi od słów krasi \"piękno, ozdoba\" i mir \"pokój\" lub \"świat\".</p>", "Kelvin": "<p>Kelwin (ruckoznawstwo: K; międzynarodowe: K) - jednostka temperatury termodynazyjnej w Międzynarodowym Systemie Jednostek (SI), jedna z siedmiu podstawowych jednostek SI. Zaproponowana w 1848 roku.</p>", "Kyryll": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kyryl</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cyryl</b>.</p><b>Cyryl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>. Wywodzi się ze słowa κύριος znaczącego „pan”, „władca”. W Polsce używane było rzadko, częściej natomiast na Rusi Czerwonej.", "Kalikst": "<b>Kalikst</b>, <b>Kalist</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od przymiotnika gr. 'kalós' (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Callistus, Callixtus</i>). Forma 'kállistos' oznacza 'bardzo dobry, bardzo piękny'.", "Kristoffer": "<p>Kristoffer to męskie imię. Nazwa jest czasami skrócona jako Kris lub alternatywnie pisowana jako Kristofer.</p>", "Karan": "<p>Koran: Koran jest znakem dyakrytycznym tajskiego pisma. Koran - stanowisko w Siłach Achemeniódów.</p>", "Kamel": "<p>Kamel (arabski: كامل) to imię, które oznacza doskonałe lub doskonałe. Może odnosić się do:</p>", "Kingsley": "<p>Kingsley, Kingsley (ang. Kingsley) - nazwa i nazwisko.</p>", "Kaleb": "<b>Kaleb</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> כָּלֵב) – postać biblijna ze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Jefunne_(potomek_Judy)\" target=\"_blank\" rel=\"noopener noreferrer\">Jefunnego</a>, ojciec Ira, Eli, Naama i Aksy. Był członkiem <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">izraelskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Pokolenie_Judy\" target=\"_blank\" rel=\"noopener noreferrer\">pokolenia Judy</a>, jedynym człowiekiem w wieku powyżej dwudziestu lat oprócz <a href=\"https://pl.wikipedia.org/wiki/Jozue\" target=\"_blank\" rel=\"noopener noreferrer\">Jozuego</a>, który w czasie czterdziestoletniej wędrówki do <a href=\"https://pl.wikipedia.org/wiki/Kanaan\" target=\"_blank\" rel=\"noopener noreferrer\">Kanaanu</a> opisanej w <a href=\"https://pl.wikipedia.org/wiki/Tora\" target=\"_blank\" rel=\"noopener noreferrer\">Torze</a> ani razu nie sprzeniewierzył się <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g_Ojciec\" target=\"_blank\" rel=\"noopener noreferrer\">Bogu</a>. Nagrodą za to był wstęp do <a href=\"https://pl.wikipedia.org/wiki/Ziemia_Obiecana_(Biblia)\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi Obiecanej</a> i przydział okolic <a href=\"https://pl.wikipedia.org/wiki/Hebron\" target=\"_blank\" rel=\"noopener noreferrer\">Hebronu</a> w dziedzictwo. Żył prawdopodobnie w <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">XIII</a>-<a href=\"https://pl.wikipedia.org/wiki/XII_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku p.n.e.</a> <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblia</a> nie podaje żadnych informacji o jego śmierci. Według tradycji żydowskiej umarł w mieście Jozuego Timnat-Serach. Od Kaleba pochodzi ród Kalebitów.", "Karthik": "<p>Karthik lub Kartik może odnosić się do:</p>", "Ken": "<p>Ken może oznaczać: Familia Ken, Guru (prawdziwe imię - Wadym Aleksanderovich Ponomarew; ur. 1969) - rosyjski dziennikarz muzyczny, krytyka i artyst, kolumnista, radiożurnalista.</p>", "Kuzma": "<p>Szasy Formuły-1, które uczestniczyły tylko w Indy-500 - to samochody używane przez amerykańskich kierowców do udziału w słynnym wyścigu ⁇ Indianapolis-500 ⁇ w latach 1950 - 1960, kiedy formalnie chodziło do zaliczenia mistrzostwa świata Formuły-1. Na początku historii Formuły 1 przez 11 sezonów (1950 - 1960) słynny amerykański wyścig na autodromie Indianapolis-500 był uważany za etap mistrzostw świata.</p>", "Kareem": "<p>Kareem (alternatywnie pisane Karim, Kerim lub Karem) (arabickie: کریم) to nazwisko i nazwisko pochodzenia arabskiego, które oznacza \"oddzielne\", \"noble\", \"uczciwe\". Jest to również jedno z Imion Bożych.</p>", "Khurshid": "<p>Khorshīd lub Khorshēd (perskie: خورشید [xoɾˈʃid], co oznacza Słońce lub \"Słońce promieniowane\"), również pisowniane jako Khurshed i Khurshid, jest perskim nazwiskiem. W dzisiejszych czasach, jak również w historycznym Iranie, Turcji i Azerbejdżanie, ale także w irackim Kurdystanie, Egipcie, Azji Środkowej i Azji Południowej, jest to głównie imię dla chłopców.</p>", "Kasjusz": "<b>Kasjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodu</a>; ta z kolei być może stanowiła pierwotnie skrót z imienia złożonego takiego, jak <i>Cassignatus</i>, <i>Cassimara</i> czy <i>Cassisuratus</i>. Inną hipotezą jest pochodzenie tej nazwy rodowej od łacińskiego <i>cassus</i> – „pozbawiony czegoś, ogołocony z czegoś” lub też od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a> słowa, oznaczającego „biedny”. Imię to nosiło sześciu świętych.", "Kishor": "<p>Kishor (hindi: किशोर}) to nazwa używana głównie w Indiach i Nepalu. Pochodzi z sanskryckiego słowa kishora, co oznacza \"chłopa\" lub \"dziecko\".</p>", "Kadek": "<p>Kadek to męskie imię. Znanymi osobami z nazwiska są: Kadek Agung (ur. 1998), indonezyjski piłkarz średniobahrowy Kadek Arel (ur. 2005), indonezijski piłkownik środkowy back Kadek Devie (ur. 1985), indonezyjska aktorka i model Kadek Raditya (ur. 1999), indonezianski piłkowniczy środkowyback Kadek Dimas Satria (ur. 2001), indonezjski piłka nożna striker</p>", "Kristopher": "<p>Christopher to angielska wersja europejskiej nazwy pochodząca z greckiego imienia Χριστόφορος (Christophoros lub Christoforos). Jego części są Χριστός (Christós), \"Chrys\" lub \"Poświęty\" oraz φέρειν (phérein), \"nieść\"; stąd \"nieść Chrystusa\".</p>", "Khurshed": "<p>Khorshīd lub Khorshēd (perskie: خورشید [xoɾˈʃid], co oznacza Słońce lub \"Słońce promieniowane\"), również pisowniane jako Khurshed i Khurshid, jest perskim nazwiskiem. W dzisiejszych czasach, jak również w historycznym Iranie, Turcji i Azerbejdżanie, ale także w irackim Kurdystanie, Egipcie, Azji Środkowej i Azji Południowej, jest to głównie imię dla chłopców.</p>", "Kumara": "<p>Kumara (lat. Kumara) - rodzaj sukkulatów należących do rodziny Asphodeloideae i rosnących na terytorium Południowej Afryki, w szczególności w prowincji Kapskiej. Obecnie rodzaj obejmuje dwa gatunki, które wcześniej były klasyfikowane jako gatunki rodu Aloe (Aloe).</p>", "Karl-Heinz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karl</b>.</p><p>Karl Kurzwazje (niem. Karl Fr.</p>", "Kasimir": "<p>Casimir jest łacińską wersją polskiego męskiego imienia Kazimierz (polskie wymowa: [ka' ⁇ i.mjeʂ]). Oryginalną polską kobiecą formą jest Kazimiera, w łacińskim i innych językach tłumaczona jako Casimira.</p>", "Kieran": "<p>Ciarán (irlandzkie pisowni) lub Ciaran (szkocka gagelicka pisowni) jest tradycyjnie męskie nazwisko pochodzenia irlandzkiego i szkockiego. Oznacza to \"małe ciemne\" lub \"małe mrocznie włosne\", wytwarzane poprzez dodanie drobnego sufiksu do ciar (\"czarny\", \"ciemny\").</p>", "Kazim": "<p>Kazem (zwany również Kadim, Kadhem, Kadhim, Kazim, Qazim lub Cathum; napisany w języku arabskim: كاظم, w perskim: کاظِم) oznacza \"tolerancja\", \"przebawienie\" i \"mieć cierpliwość\" jest arabskim męskim nazwiskiem. Chociaż wymowa litery arabskiej Ẓāʾ jest często bliżej silnego dźwięku \"d\", biorąc pod uwagę rozpowszechnienie nazwy w Wielkim Iranie i późniejszych wymian kulturowych między Persją i subkontynentem indyjskim, Azją Środkową i Anatolii, litera...</p>", "Kiejstut": "<b>Kiejstut</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">lit.</a> <i>Kęstutis</i> – cierpliwy, wytrwały) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Litwa\" target=\"_blank\" rel=\"noopener noreferrer\">litewskiego</a>.", "Kostiantin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kostyantyn</b>.</p><p>Kostyantyn lub Kostiantyn to imię. Znanymi osobami z nazwiska są: Kostyantyn Balabanov (ur. 1982), ukraiński piłkarz koszykówki Kostyantyin Bocharov (ur., 1997), ukraiński piosenkarz i autor utworów Kostyantin Dankevych (1905-1984), ukraińskiego kompozytora i nauczyciela muzycznego Kostyantyna Doroshenko (ur. 1972), krytyka sztuki Ukrainy, kurator współczesnej sztuki, menedżer mediów, nadawca radiowy stacji rozmowy Radio Vesti (Ukraina) Kostyantyny...</p>", "Kleofas": "<b>Kleofas</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało ono przez skrócenie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Κλεοπατρος (Kleopatros), które stanowi złożenie członów κλεος (<i>kleos</i>) „chwała, sława” i πατρος (<i>patros</i>) „ojca, ojcowska” (zob. też <a href=\"https://pl.wikipedia.org/wiki/Kleopatra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kleopatra</a>).", "Kaspar": "<b>Kacper</b>, <b>Kasper</b>, <b>Kaspar</b>, <b>Gaspar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, oboczności powstałe jako przekształcenie imienia Kasper, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> <i>ganzabara</i> („strażnik skarbca”) od <i>*ganzah</i> (“skarb”) + <i>*barah</i> (“brzemię”), od praindoeuropejskiego <i>*bʰer-</i> („brać”).", "Kfir": "<p>Israel Aircraft Industries Kfir (Hebrew: כפיר, \"Lon Cub - Lwiec\") jest izraelskim lotniczym lotniczym, który jest w każdej pogodzie. Został on opracowany na podstawie ulepszeń w kadrze Dassault Mirage 5, z izraelskim systemem elektronicznym lotnictwa i wersją turbinowego silnika turbinowanego General Electric J79 zbudowanego w Izraelu.</p>", "Kabir": "<p>Kabir (hindi: कबीर, punjab: ਕਬੀਰ, urdu: کبیر) - średniowieczny indyjski poeta, wybitny reformator ruchu Bhakti, klasyczny autor literatury hindijskiej. W historii indyjskiej religii, Kabir zajmuje wyjątkowe miejsce.</p>", "Keshav": "<p>Keshav to małe imię z Azji Południowej, które jest nowoczesną formą imienia Keshava, jedno z wielu imion Pana Kryszny i Pana Wisnu. Wśród znanych osób z nazwiskiem są: Keshav Kashmiri (1410-1490), indyjski filozof Keshav Bansal (ur. 1991), indyjski przedsiębiorca Keshav Vaman Bhole (1896-1967), indyjskie kompozytor muzyczny Keshav Kumar Budhathoki, nepalski polityk Keshav Dutt (1925-2021), indyjska hokejistka Keshav Ginde (ur. 1942),...</p>", "Kasim": "<p>Kasim jako imię, wariant Qasim. Może odnosić się do:</p>", "Kent": "<p>Kent to marka papierosów. Marka Kent została uruchomiona do produkcji w marcu 1952 roku przez amerykańską firmę Lorillard.</p>", "Kenzo": "<p>Kenzo (⁇ ⁇ ⁇ ⁇ K ⁇ ⁇) - francuska marka odzieży, obuwia i innych wyrobów klasy ⁇ lux ⁇ . Dom mody został założony w 1970 roku przez japońskiego projektanta Kenzo Takada.</p>", "Kennedy": "<p>Kennedy (ang. Kennedy) - irlandzka, szkocka i angielska nazwisko, znane na całym świecie w szczególności dzięki 35-emu prezydentowi Stanów Zjednoczonych Johnowi Kennedy'emu i aktywnym politycznie i społecznie członkom jego rodziny.</p>", "Karapet": "<p>Karapet lub Garabet lub Garabed jest powszechną imieniem w języku armenijskim. Mogą odnosić się do: przedchrześcijańskiego armenijskiego bogów grzmotów, Karapet</p>", "Kristóf": "<p>Kristof, Krištof lub Kristóf mogą być zarówno nazwiskiem, jak i nazwiskiem. Do wybitnych osób z tym nazwiskiem należą:</p>", "Kapil": "<p>Kapil to męskie imię indyjskiego pochodzenia i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Klimek": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Klemens</b>.</p><b>Klemens</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „człowiek o łagodnym usposobieniu”, „delikatny”, „pobłażliwy”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Klemencja\" target=\"_blank\" rel=\"noopener noreferrer\">Klemencja</a>.", "Kirił": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kyryl</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cyryl</b>.</p><b>Cyryl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>. Wywodzi się ze słowa κύριος znaczącego „pan”, „władca”. W Polsce używane było rzadko, częściej natomiast na Rusi Czerwonej.", "Killian": "<p>Killian lub Kilian, jako nazwisko, jest angielskościową wersją irlandzkiego imienia Cillian. Nazwa Cillian nosiła kilku wczesnych świętych irlandzkich, w tym misjonarzy do Artois (Francja) i Frankonia (Niemcy) oraz autorka życia św. Brigid.</p>", "Kirył": "<b>Cyryl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>. Wywodzi się ze słowa κύριος znaczącego „pan”, „władca”. W Polsce używane było rzadko, częściej natomiast na Rusi Czerwonej.", "Kami̇l": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kamila</b>.</p><b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Karthikeyan": "<p>Karthikeyan (w skrócie Karthikeya, Karthik, Kartik) to indyjska męska nazwisko pochodzące od Pana Kartikeya.</p>", "Keanu": "<p>Keanu Charles Reeves (kiˈɑːnuː]; urodz.</p>", "Knut": "<p>Knut - matkor/słajg z Genewy, Szwajcaria, utworzony w 1994 roku. Muzyka grupy zawiera elementy slażu, postmetalu i post-hardkoru.</p>", "Kenji": "<b>Kenji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けんじ, ケンジ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kajus": "Na starożytność tego imienia wskazuje <a href=\"https://pl.wikipedia.org/wiki/Ortografia\" target=\"_blank\" rel=\"noopener noreferrer\">pisownia</a> jego skrótu, którym tradycyjnie było <i>C.</i> <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">Litera</a> ta pierwotnie oznaczała głoskę <i>g</i>, gdyż pochodziła ona od greckiej <i><a href=\"https://pl.wikipedia.org/wiki/Gamma\" target=\"_blank\" rel=\"noopener noreferrer\">Γ</a></i> (zaś litera <i>K</i> oznaczała głoskę <i>k</i>). Te dwie litery stosowano w ten właśnie sposób do roku <a href=\"https://pl.wikipedia.org/wiki/312_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">312 p.n.e.</a>, kiedy cenzor <a href=\"https://pl.wikipedia.org/wiki/Appiusz_Klaudiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Appiusz Klaudiusz</a> zmienił pisownię, wprowadzając literę <i>G</i> powstałą z przekształcenia <i>C</i>, a literze <i>C</i> nadał wartość głoski <i>k</i>. Oznacza to, że pisownia skrótu imienia <i>Gaius</i> utrwaliła się jeszcze przed reformą, a więc i samo imię musi pochodzić sprzed <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>", "Khanh": "<p>Khanh (czeski: 卿) lub Quan Khanh (czyciński: 卿), to urzędnik w historii wschodu starożytnego.</p>", "Kęstutis": "<p>Keystut (lit. Kęstutis; ok.</p>", "Kailash": "<p>Od tybetańskiej stolicy Lhasy ponad 1000 km na zachód jest święta góra Kailash, nazwana przez świat \"światlem duchowym\", gdzie buddyjski Tygman nazywa górę Tu Di, jest również jedynym w starożytności miejscem, gdzie buddy i 500 Alah poszedł. Kailash jest duchem, otoczony czterema górami czterech Buddów i Pięciu Pięć Czarnych, jaskiniami Ojca Milarepa, szczeniarstwem Ojca Miłosierdzia Sanh i jaskiniami Botota...</p>", "Khang": "<p>Khang (ang. 康县, przenośne: Kāng Xiàn, przenoszone: Khang District) jest okręgami kolonialnymi w mieście Walen Nam, prowincja Cam Tuc, w Chinach. Ogromnie liczy się 2958 km2, a jego populacja wynosi 200 000 mieszkańców.</p>", "Kelly": "<p>Kelly (ang. Kelly, Kelley, Kellie), początkowo O'Kelly (irl.</p>", "Kalman": "<p>Kalman - imię lub nazwisko, które występują u różnych narodów. Węgierskie imię lub nazwisko pochodzenia niemieckiego.</p>", "Khurram": "<p>Khurram, zwanego również Khorram, Khoram i Hürrem, jest męskim imieniem i nazwiskiem pochodzenia perskiego. Wśród znanych osób z tej nazwy są następujące:</p>", "Kais": "<p>Kais jest miastem w prowincji Khenchela w Algierii. W 2002 roku liczba ludności wynosiła 28 724 osób.</p>", "Kristián": "<p>Kristian jest nazwiskiem w kilku językach i jest wariantem pisowni chrześcijańskiej.</p>", "Kartik": "<p>Karthik lub Kartik może odnosić się do:</p>", "Krishna Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krishna</b>.</p><p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Karlen": "<p>Karlen lub Karlén to nazwisko. Do wybitnych osób z nazwiskiem należą:</p>", "Khánh": "<p>Kánh to popularne w Wietnamie imię, a także może być: Kánh, starożytny instrument kamienny lub miedziany, grubości, dźwięk Kánh, wietnamski DJ.</p>", "Kylian": "<p>Killian lub Kilian, jako nazwisko, jest angielskościową wersją irlandzkiego imienia Cillian. Nazwa Cillian nosiła kilku wczesnych świętych irlandzkich, w tym misjonarzy do Artois (Francja) i Frankonia (Niemcy) oraz autorka życia św. Brigid.</p>", "Klaas": "<p>Klas Gerling, znany bardziej jako Klaas - niemiecki DJ i producent muzyczny z Köln.</p>", "Kaya": "<p>Kaya - dziesiąty album studiowy jamajskiego zespołu reggae Bob Marley &amp; The Wailers, wydany w 1978 roku. Album składa się z kompozycji zapisanego w tym samym czasie z materiałem dla poprzedniego albumu Exodus.</p>", "Kakhi": "<p>Kakhi to męskie gruzyńskie imię i pseudonim. Wśród znanych osób z tym nazwiskiem są: Kakhi Asatiani (1947-2002), gruziński piłkarz i menedżer z zespołu, Kakhi Gogichaishvili (ur. 1968), gruziński futbolista, Kakhi Kakhiashvili (ur., 1969). Gruzyjsko-grecki ciężarostaj Kakhi Kaladze (ur. 1978), gruziński polityk i piłkarz Kakhi Kavsadze (1935-2021), gruziński i sowiecki aktor Kakhi...</p>", "Kayode": "<p>Kayode jest zarówno nazwiskiem jak i męskim nazwiskiem pochodzenia jorubańskiego. Nazwa oznacza \"Przyniesie z nim dużo szczęścia\".</p>", "Klaudius": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Claudius</b>.</p><p>Claudius - rzymski cesarz Claudius- monotypowy gatunek żółwiek z Ameryki Środkowej Claudius</p>", "Kwame": "<b>Kwame</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_twi\" target=\"_blank\" rel=\"noopener noreferrer\">języka twi</a> używanego w <a href=\"https://pl.wikipedia.org/wiki/Ghana\" target=\"_blank\" rel=\"noopener noreferrer\">Ghanie</a>.", "Kayden": "<p>Caden to nazwa w krajach anglojęzycznych, która najczęściej jest używana dla mężczyzn. W popularności wzrosła na początku lat 2000 z powodu popularności podobnie brzmiących nazw, takich jak Aidan, Braden, Hayden i Jadon.</p>", "Khalifa": "<p>Khalif, Khalifa (arabski: خليفة - наместник, zastępca) - nazwa najwyższego tytułu u muzułmanów.</p>", "Krystof": "<p>Kryštof to czeskie imię, równoważne angielskiej Christopher. Do wybitnych osób z tym nazwiskiem należą: Jan Kryštof Liška (kr.</p>", "Kastor": "<b>Kastor</b> – polska forma zlatynizowanego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Castor</i> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>kekasmai</i> oznaczającego \"świecić\". W <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> Kastor był synem <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>. Istnieją święci katoliccy o tym imieniu.", "Ksavery": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Xavery</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Xawery</b>.</p><b>Ksawery</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Pochodzi od nazwy miejscowości, z której pochodził <a href=\"https://pl.wikipedia.org/wiki/Franciszek_Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszek Ksawery</a> (<i>Javier</i>). Początkowo używane tylko w złożeniu z Franciszkiem (analogicznie do <a href=\"https://pl.wikipedia.org/wiki/Jan_Kanty\" target=\"_blank\" rel=\"noopener noreferrer\">Kantego</a>). Oboczna, bardziej archaiczna pisownia – <b>Xawery</b>.", "Kofi": "<p>Kofi jest męskim imieniem Akan wśród ludów Akan (takich jak Bono, Akyem, Akwamu, Ashanti i Fante) w Ghanie, które jest dane chłopcu urodzonemu w piątek. Tradycyjnie w Ghanie dziecko otrzymywało nazwę Akan podczas Outdooringu, osiem dni po urodzeniu.</p>", "Ke": "<b>Ќ</b>, <b>ќ</b> – litera <a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylicy</a> używana w alfabecie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka macedońskiego</a> oznaczająca /kj/. Często odpowiada <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackiemu</a> <a href=\"https://pl.wikipedia.org/wiki/%C4%86\" target=\"_blank\" rel=\"noopener noreferrer\">Ć</a>/<a href=\"https://pl.wikipedia.org/wiki/%D0%8B\" target=\"_blank\" rel=\"noopener noreferrer\">Ћ</a>, a niekiedy także np. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiemu</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskiemu</a> <a href=\"https://pl.wikipedia.org/wiki/C\" target=\"_blank\" rel=\"noopener noreferrer\">C</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">rosyjskiemu</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%A7\" target=\"_blank\" rel=\"noopener noreferrer\">Ч</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskiemu</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%A9\" target=\"_blank\" rel=\"noopener noreferrer\">Щ</a>.", "Kostyantin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kostyantyn</b>.</p><p>Kostyantyn lub Kostiantyn to imię. Znanymi osobami z nazwiska są: Kostyantyn Balabanov (ur. 1982), ukraiński piłkarz koszykówki Kostyantyin Bocharov (ur., 1997), ukraiński piosenkarz i autor utworów Kostyantin Dankevych (1905-1984), ukraińskiego kompozytora i nauczyciela muzycznego Kostyantyna Doroshenko (ur. 1972), krytyka sztuki Ukrainy, kurator współczesnej sztuki, menedżer mediów, nadawca radiowy stacji rozmowy Radio Vesti (Ukraina) Kostyantyny...</p>", "Kang": "Pierwszy znany piec typu kang, z jednym kanałem dymowym, pochodzi z I wieku n.e. z terenów prowincji <a href=\"https://pl.wikipedia.org/wiki/Heilongjiang\" target=\"_blank\" rel=\"noopener noreferrer\">Heilongjiang</a>.", "Kane": "<p>Kane, czasami Kane (ang. Cain, Caine, Cane, Kain, Kaine, Kane, Kayne; [keɪn], ale wall.</p>", "Karo": "W oficjalnych turniejowych taliach kart do gry w <a href=\"https://pl.wikipedia.org/wiki/Skat\" target=\"_blank\" rel=\"noopener noreferrer\">skata</a> kara są koloru <a href=\"https://pl.wikipedia.org/wiki/Barwa_%C5%BC%C3%B3%C5%82ta\" target=\"_blank\" rel=\"noopener noreferrer\">żółtego</a> lub <a href=\"https://pl.wikipedia.org/wiki/Barwa_pomara%C5%84czowa\" target=\"_blank\" rel=\"noopener noreferrer\">pomarańczowego</a> <a href=\"https://pl.wikipedia.org/wiki/Plik:SuitDiamonds4colors.svg\" target=\"_blank\" rel=\"noopener noreferrer\"></a>. Jest to spowodowane turniejową unifikacją dwóch rodzajów talii – typu francuskiego i <a href=\"https://pl.wikipedia.org/wiki/Karty_polskie\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a>, gdyż odpowiednik kar w tym drugim typie – dzwonek – jest oznaczany kolorowym (głównie <a href=\"https://pl.wikipedia.org/wiki/Barwa_z%C5%82ota\" target=\"_blank\" rel=\"noopener noreferrer\">złotym</a>) dzwonkiem.", "Kannan": "<p>Kannan (tamiłowa கண்ணன்) (malayalam: കണ്ണൻ) to męskie imię tamilowe i malayalamskie. Ze względu na tamilską tradycję używania nazwisk patronymicznych, może to być także nazwisko dla mężczyzn i kobiet.</p>", "Krishna Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krishna</b>.</p><p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Khazar": "<b>Chazarowie</b>, Kozarowie (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">tur.</a>&#160;<em>Hazarlar</em>) – <a href=\"https://pl.wikipedia.org/wiki/Koczownik\" target=\"_blank\" rel=\"noopener noreferrer\">lud koczowniczy</a> <a href=\"https://pl.wikipedia.org/wiki/Ludy_tureckie\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia tureckiego</a>, o którym pierwsze wzmianki pochodzą z VI wieku n.e. Tereny zajmowane przez Chazarów rozciągały się na <a href=\"https://pl.wikipedia.org/wiki/Step_Pontyjski\" target=\"_blank\" rel=\"noopener noreferrer\">Stepie Pontyjsko-Kaspijskim</a> między północnym <a href=\"https://pl.wikipedia.org/wiki/Kaukaz_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Kaukazem</a>, <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82wysep_Krymski\" target=\"_blank\" rel=\"noopener noreferrer\">Krymem</a>, <a href=\"https://pl.wikipedia.org/wiki/Morze_Kaspijskie\" target=\"_blank\" rel=\"noopener noreferrer\">Morzem Kaspijskim</a> a rzeką <a href=\"https://pl.wikipedia.org/wiki/Ural_(rzeka)\" target=\"_blank\" rel=\"noopener noreferrer\">Jaik</a> i <a href=\"https://pl.wikipedia.org/wiki/Samara_(dop%C5%82yw_Wo%C5%82gi)\" target=\"_blank\" rel=\"noopener noreferrer\">Samarą</a>. Trudnili się głównie pasterstwem i handlem, a bogacili na łupieskich wyprawach. Przez ich ziemie prowadziły największe szlaki handlowe z Chin do Europy (<a href=\"https://pl.wikipedia.org/wiki/Jedwabny_szlak\" target=\"_blank\" rel=\"noopener noreferrer\">jedwabny szlak</a>, szlak <a href=\"https://pl.wikipedia.org/wiki/Radanici\" target=\"_blank\" rel=\"noopener noreferrer\">radanitów</a>) oraz szlak północ-południe (<a href=\"https://pl.wikipedia.org/wiki/Od_Wareg%C3%B3w_do_Grek%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">od Waregów do Greków</a>).", "Kei": "<b>Kei</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けい, ケイ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>, coraz częściej stosowane jako żeńskie imię – jako skrót od <a href=\"https://pl.wikipedia.org/wiki/Keiko\" target=\"_blank\" rel=\"noopener noreferrer\">Keiko</a>.", "Kevin Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kentaro": "<p>Kentarō, Kentaro, Kentarou lub Kentaroh (pisanie z użyciem takich kanji jak 健太郎, 健太朗, 憲太郎,賢太郎,建太郎,拳太郎, humb太郎 lub 謙太朗) jest męskie japońskie imię. Do znanych osób z nazwiska należą: DJ Kentaro (ur. 1982), japoński DJ, remixer Kentaro Asahi (ur. 1975), japoński piłkarz siatkówki Kentarō Haneda (ur. 1949-2007), japoński kompozytor, pianista Kentaro Hashimoto (ur. 1980), japończyk bezbołowy Kentaro Hayashi (ur. ...</p>", "Kobe": "<p>Kobe (jap. 神戸市 Ko:be-si) - miasto, określonego przez układ rządu Japonii, położone na wyspie Honsyu, centrum administracyjnym prefektury Higo.</p>", "Kari": "<p>Macromonycha (lat.) - rodzaj żółwiek schildonoznosnych (Cassidini) z rodziny liściżerców. Trzy rodzaje.</p>", "Kaito": "<b>Kaito</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;海斗, 海翔, 海人, 快斗, 凱斗) lub <b>Kaitō</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;怪盗) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kader": "<p>Kader (開達) - jeden z największych światowych producentów modeli kolejowych i zabawek (poza tym firma ma zainteresowania w produkcji komponentów do elektroniki i w dziedzinie nieruchomości). Należy do Kader Group, która ma siedzibę w Hongkongu, jest zarejestrowana na Bermudziach i należy do rodziny Ting.</p>", "Kirk": "<p>Thomas Kirk (ang. Thomas Kirk, 18 stycznia 1828 - 8 marca 1898) - brytyjski nowozelandski botanik.</p>", "Ki": "<p>KI (drwa litera - główna ⁇ i ⁇) lub Ki może oznaczać: Kibi- (skr. Ki lub Ki) - podwójna przymowa, oznaczająca 210 (podobna do dziesięcioletniej przymowy ⁇ kil- ⁇).</p>", "Khairul": "<p>Khairul (خيرول) to męskie imię, które jest powszechnie stosowane w Malezji, Indonezji i Azji Południowej. Pochodzi od arabskiego słowa \"Khair\" (خير), co oznacza \"dobroty\", \"błogosławieństwo\" lub \"cnota\".</p>", "Kola": "<p>Kola (prawdziwe imię - Anastasia Olegovna Prudjus; ur. 19 października 1992, Kharkiw) - ukraińska piosenkarka, autorka i wykonawczyni własnych piosenek.</p>", "Kristiyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristian</b>.</p><b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Kiriłł": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kiril</b>.</p><p>Mężczyzna Cyril (lub Kiril lub Кирилл) jest powszechną nazwą w świecie prawosławskich słowiańskich, zwłaszcza w Bułgarii, Macedonii Północnej i Rosji. Jest również dobrze znany w Grecji, ale w różnych formach, takich jak Kyriakos.</p>", "Kalyan": "<p>Kalyan (Marathi: कल्याण) to miasto w dzielnicy Thane w Maharashtra, jest przecinkiem linii kolejowej blisko Mumbai, India. To jest stolica Kalyan Taluka, jednostki administracyjnej okręgu.</p>", "Karthick": "<p>Karthik lub Kartik może odnosić się do:</p>", "Kristoff": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristof</b>.</p><p>Kristof, Krištof lub Kristóf mogą być zarówno nazwiskiem, jak i nazwiskiem. Do wybitnych osób z tym nazwiskiem należą:</p>", "Khoi": "<p>Khoikhoi (\"ludzi\" lub \"prawdziwi ludzie\") lub Khoi, pisane jako Khoekhoe w standardowym Khoekhoe/Nama literacku, to grupa ludności rodzinną w południowo-zachodniej Afryce. W przeciwieństwie do sąsiednich Sanów, którzy polowali i zbierali ryby, Khoikhoi mieli tradycję hodowli bydła.</p>", "King": "<p>King: King - skrócie botaniczne, oznaczające, że autorem taksyny jest King, George (biolog). King Musical Instruments - amerykański producent instrumentów muzycznych i ich sprzętów.</p>", "Koichi": "<p>Kōichi, Koichi, Kouichi lub Kohichi to męskie japońskie imię.</p>", "Keisuke": "<b>Keisuke</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けいすけ, ケイスケ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Kastriot": "<p>Kastriot jest gminą w okręgu Dibër w okręgcie Dibër w Albanii. W 2005 roku liczba ludności wynosiła 8517.</p>", "Kobi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Koby</b>.</p><p>Coby lub Koby to imię męskie i żeńskie, nazwisko lub ksywkę pochodzące od nazwiska \"Jakob\" lub \"Jakob\".</p>", "Kornelius": "<p>Cornelius to pierwotnie rzymskie imię męskie. Nie jest pewne, co się z niego wzięło, ale podejrzewa się, że pochodzi z łacińskiego cornu, \"roga\".</p>", "Kiryll": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kiryl</b>.</p><p>Mężczyzna Cyril (lub Kiril lub Кирилл) jest powszechną nazwą w świecie prawosławskich słowiańskich, zwłaszcza w Bułgarii, Macedonii Północnej i Rosji. Jest również dobrze znany w Grecji, ale w różnych formach, takich jak Kyriakos.</p>", "Khoren": "<p>Khoren (armeńska: Խորեն) to armenijska nazwa. Do wybitnych osób z nazwiskiem należą: Khoren Abrahamyan (1930-2004), armenijski aktor i reżyser Khoren Bayramyan (ur. 1992), rosyjski profesjonalny piłkarz z pochodzenia armenijskiego Khoren Kalashyan (ur., 1984), armenijski agent piłkarski Khoren Gevor (ur. 1980), armenijsko-niemiecki profesjonalny bokser Khoren I Paroian (1914-1983), katolicz Katolicz Krzesła Świętego w Kilicyji, od 1963 do 1983...</p>", "Kiriakos": "<p>Kyriakos (grecki: Κυριάκος) jest nazwiskiem chrześcijańskiego świętego Cyrykusza Anchorytów (lub Kyriakos). Alternatywną transliteraturą i pisownią są Kyriacos i Cyriacus.</p>", "Kaji": "<p>Kazimir (Casimir) Hnatow (francuski: Kazimir; 9 listopada 1929, Kryun (Mrt i Mosel) - 16 grudnia 2010, Wue (Dio-Sevr)) - francuski piłkarz, półobrony.</p>", "Kreshnik": "<p>Kreshnik to albanska nazwa. Nazywane Kreshnik Bahtiri (ur. 1992), kosowski piłkarz Kreshnik Çipi (ur. 1958), albanianki polityk Kreshnik Gjata (ur. 1983), albanianski pływacz Kreshnik Hajrizi (ur. 1999), kosowskiego piłkarza Kreshnik Ivanaj (ur. 1982), albanian football player Kreshnik Krasniqi (ur. 2000), kosowsko-norweski piłkarze Kreshnik Qato (ur. 1978), albanian boxer Kreshnik Sinanaj (ur., 1986), albanian piłkarzem...</p>", "Khai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Chai</b>.</p>Polska nazwa <i>herbata</i> to <a href=\"https://pl.wikipedia.org/wiki/Zbitka_wyrazowa\" target=\"_blank\" rel=\"noopener noreferrer\">zbitka</a> pochodząca od łac. <i>herba thea</i> (gdzie pierwszy wyraz <i>herba</i> oznacza „ziele”, a drugi – <i>thea</i> – jest zlatynizowaną postacią chińskiej nazwy tejże rośliny). W Chinach znak określający herbatę: 茶 jest różnie czytany w zależności od dialektu: tê – dialekt <a href=\"https://pl.wikipedia.org/wiki/Hokkien\" target=\"_blank\" rel=\"noopener noreferrer\">hokkien</a> (skąd pochodzą określenia w językach zachodniej Europy) oraz chá, w dialektach <a href=\"https://pl.wikipedia.org/wiki/Standardowy_j%C4%99zyk_kanto%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kantońskim</a> i <a href=\"https://pl.wikipedia.org/wiki/Standardowy_j%C4%99zyk_mandary%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">mandaryńskim</a> (z odmianami tej wymowy popularnymi na Wschodzie – w państwach takich jak <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indie</a>, <a href=\"https://pl.wikipedia.org/wiki/Iran\" target=\"_blank\" rel=\"noopener noreferrer\">Iran</a>, <a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcja</a>, <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosja</a>, <a href=\"https://pl.wikipedia.org/wiki/Czechy\" target=\"_blank\" rel=\"noopener noreferrer\">Czechy</a>).", "Karym": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karim</b>.</p><b>Karim</b> (<b>كريم</b>) – imię pochodzenia arabskiego, jest czterdziestym trzecim z „Najpiękniejszych imion Allaha”. Oznacza dosłownie „hojny”.", "Kantilal": "<p>Kantilal to indyjska nazwa i może odnosić się do Kantilal Amrutiya, indyjskiego polityka Kantilal Bhuria, indyjski polityk Kantilal Ghia, indyjska polityka Kantilala Hastimal Sancheti, lekarz ortopedyczny Kantilal Jivan, Guru Kantilal Kanjee, zimbabwskiego kryketa Kantilal Mardia, indyskiego statystyka Kantilal Ranchhodji Desai, indyjskich kryketa Kantiala Thakoredas Desai, byłego sędziego w Sądzie Najwyższym Gujarat</p>", "Kyu": "W go różnica 1 kyū oznacza 1 kamień <a href=\"https://pl.wikipedia.org/wiki/Handicap_(go)\" target=\"_blank\" rel=\"noopener noreferrer\">handicapu</a> dla słabszego gracza.", "Krzysław": "<b>Krzesisław</b>, <b>Krzecsław</b>, <b>Krzesław</b>, <b>Krzysław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sław</i> („sława”). Znaczenie imienia: „odnawiający sławę”.", "Kush": "<p>⁇ Kush ⁇ - single amerykańskiego repera Dr. Dre, wydany 18 listopada 2010 roku.</p>", "Krisztian": "<p>Krisztián to imię. Do wybitnych osób z nazwiskiem należą: Krisztián Adorján (ur. 1993), węgierski piłkarz Krisztiàn Balázs (ur. 2002), węgarski gimnast Krisztiân Bártfai (ur. 1974), węgarski sprint-kanoista Krisztijan Berki (ur. 1985), węgrski gimnast artystyczny Krisztiān Budovinszky (ur. 1976), węgianki piłka nożna KrisztiAN Cser (ur. 1977), węgiański piosenkarz opery i fizyk Krisztian Csillag (ur. 1975), węginski...</p>", "Kujtim": "<p>Kujtim jest albanskim męskim imieniem, co oznacza \"pamięć, pamięć\" w języku albanskim. Zmiana kobieca nazwy to Kujtime.</p>", "Korneli": "<b>Kornel</b>, <b>Korneliusz</b>, <b>Korneli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Cornelii</i> (<i>Korneliuszy</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusze Cynna</a>). Istnieją różne hipotezy pochodzenia wspomnianej nazwy rodowej; wywodzi się ją bądź to ze słowa <i>cornu</i> („róg”), bądź to <i>cornus</i> („<a href=\"https://pl.wikipedia.org/wiki/Dere%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dereń</a>”), bądź to od nazwy pola <i>Corne</i> w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. W dawnej Polsce zapisywane od <a href=\"https://pl.wikipedia.org/wiki/1402\" target=\"_blank\" rel=\"noopener noreferrer\">1402</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> formie <i>Cornelius</i> oraz od <a href=\"https://pl.wikipedia.org/wiki/1412\" target=\"_blank\" rel=\"noopener noreferrer\">1412</a> roku w formach pochodnych Kornosz, Kornasz, Korna (masc.), Kornosza (masc.), Kornoszek i ze zdrobnieniami Nela (masc.), Nelka (masc.), Nelko.", "Kliment": "<p>Kliment (cyrylicki: Климент) to męskie imię, słowiańska forma późnolatynskiej nazwy Klement. Klim jest formą mniejszą.</p>", "Konstancjusz": "<b>Konstancjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>constans</i> oznaczającego „stały”, „prawidłowy”. Jego patronem jest św. Konstancjusz, biskup (<a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wiek</a>).", "Kara": "<p>Kara może być: Kara, jednostka mierząca czystość metałów szlachetnych</p>", "Kazuki": "<b>Kazuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずき, カズキ) – głównie męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, rzadko noszone przez kobiety.", "Kotaro": "<p>Kotaro, Kōtarō lub Koutarou (pisanie: 耕太郎, 孝太郎,康太郎, 光太郎,功太郎, ⁇ 太郎,幸太郎, ??太郎,興太郎, Znanymi osobami z nazwiska są: Kotaro Azuse (東瀬 耕太郎; ur. 1967), japoński piłkarz baseballu Kotaro Honda (本多 光太郎; 1870-1954), japoński naukowiec i wynalazca Kōtarō Iizawa (飯沢 耕太 Taro; ur. 1954), japowski krytycz fotografii i pisarz Kotaro Ikeda (池田 幸太郎; 1895-1976), japończyk malarz Kōtarō...</p>", "Krzesisław": "<b>Krzesisław</b>, <b>Krzecsław</b>, <b>Krzesław</b>, <b>Krzysław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sław</i> („sława”). Znaczenie imienia: „odnawiający sławę”.", "Kiriło": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kiril</b>.</p><p>Mężczyzna Cyril (lub Kiril lub Кирилл) jest powszechną nazwą w świecie prawosławskich słowiańskich, zwłaszcza w Bułgarii, Macedonii Północnej i Rosji. Jest również dobrze znany w Grecji, ale w różnych formach, takich jak Kyriakos.</p>", "Kornelii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Korneli</b>.</p><b>Kornel</b>, <b>Korneliusz</b>, <b>Korneli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Cornelii</i> (<i>Korneliuszy</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusze Cynna</a>). Istnieją różne hipotezy pochodzenia wspomnianej nazwy rodowej; wywodzi się ją bądź to ze słowa <i>cornu</i> („róg”), bądź to <i>cornus</i> („<a href=\"https://pl.wikipedia.org/wiki/Dere%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dereń</a>”), bądź to od nazwy pola <i>Corne</i> w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. W dawnej Polsce zapisywane od <a href=\"https://pl.wikipedia.org/wiki/1402\" target=\"_blank\" rel=\"noopener noreferrer\">1402</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> formie <i>Cornelius</i> oraz od <a href=\"https://pl.wikipedia.org/wiki/1412\" target=\"_blank\" rel=\"noopener noreferrer\">1412</a> roku w formach pochodnych Kornosz, Kornasz, Korna (masc.), Kornosza (masc.), Kornoszek i ze zdrobnieniami Nela (masc.), Nelka (masc.), Nelko.", "Krzesław": "<b>Krzesisław</b>, <b>Krzecsław</b>, <b>Krzesław</b>, <b>Krzysław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sław</i> („sława”). Znaczenie imienia: „odnawiający sławę”.", "Kartal": "<p>Kartal jest dzielnicą w prowincji Istanbul w Turcji. Ogromnie obszarzyła 34 km2 i liczba ludności w 2007 roku wynosiła 54 1209 osób, a jego gęstość wynosi 15918 osób/km2.</p>", "Kwasi": "<p>Kwasi to imię Akanów, które w Ghanie nadaje się chłopcu urodzonemu w niedzielę (Kwasiada). Wśród znanych osób z tym nazwiskiem są: Kwasi Sintim Aboagye, ghanański nauczyciel, biznesmen i polityk lat 50 i 60 Kwasi Kwarfo Adarkwa, ghanajski akademik, wice-kanclerz Kwame Nkrumah University of Science and Technology 2006-2010 Kwasi Boateng Adjei (ur. 1954), ghanański polityk Kwasi Ameyaw-Cheremeh (ur. 1966), ghanajski polityk Kwosi...</p>", "Kavin": "<p>Kavin (/kəvɪn/) (tamilska கவின்) to unisex, co jest tamilskim dla \"piękno\", \"gracja\", \"sprawiedliwość\" lub \"piękna\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Klaudian": "<b>Klaudian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od nazwy rzymskiego rodu <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudiuszów</a> przy pomocy <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ianus</i>, oznaczającego przynależność lub pochodzenie. Patronem tego imienia jest św. Klaudian, wspominany razem ze św. Wiktorem, Wiktorynem, Papiaszem, Serapionem, Dioskurem i Niceforem.", "Kento": "<p>Kento może być: 賢斗 (Hiya) Japoński piłkarz Momota Kento (桃田賢斗) 賢人 (Hiya), japoński aktor i model Yamazaki Kento (山 ⁇ 賢人) ⁇ 都 (Huyun Do) Japończyk Umeki Kento (梅木 ⁇ 都) 健斗 (Hya) Japoński piłkarze Hyodo Kento (兵藤健斗) Japowski piłkarzem Misao Kento (三 ⁇ 健斗) 健人 (Kuku) Japońskiego piłkarza Fukuda Kento (福田健人) Japocki piłkarzysta Hori Kento (⁇ 健人)...</p>", "Kwaku": "<p>Kwaku (Kweku, Kuuku, Korku, Kɔku, Kouakou), to imię Akan dla chłopców urodzonych w środę w etnicznych grupach Akan i Ewe. Nazwa urodzin Akanów wiąże się z nazwami, które wskazują charakter ludzi urodzonych w takie dni.</p>", "Kahraman": "<p>Kahraman (z tureckiego - ⁇ Heroy ⁇) - czwarty studiowy i pierwszy turkojęzyczny album belgijsko-turkiej piosenkarki R&amp;B/pop-Hadis, wydany w 2009 roku.</p>", "Klyment": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kliment</b>.</p><p>Kliment (cyrylicki: Климент) to męskie imię, słowiańska forma późnolatynskiej nazwy Klement. Klim jest formą mniejszą.</p>", "Karoly": "<p>Károly to powszechne węgierskie imię męskie. Czasami znajduje się również jako węgierska nazwisko.</p>", "Kornél": "<p>Kornél lub Kornel to imię i nazwisko. Wśród znanych osób z tej nazwy są: Kornél Ábrányi (1822-1903), węgierski pianista, pisarz muzyczny, teoretycznik, kompozytor Kornél Bardóczky (ur. 1978), emerytowany tenista z Węgier Kornél Béke (ur. 1998), węgarski kanosik Kornél Csernik (ur. 1998, węgierki piłkarz Kornél Dávid (ur. 1971), emerytowana węgierka korzysta z koszykówki Kornel Filipowicz...</p>", "Kwan": "<p>Kwan - finski kolektyw muzyczny utworzony w Helsinkach w 2000 roku. Najbardziej zauważalnymi uczestnikami są wokalistki Mariko (Marie Liisa Paялаchty) i Tydjan (Ossy Bach Tydjan).</p>", "Karun": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karuna</b>.</p>W <a href=\"https://pl.wikipedia.org/wiki/Emocja\" target=\"_blank\" rel=\"noopener noreferrer\">emocjonalnym</a> rozumieniu ma znaczenie <a href=\"https://pl.wikipedia.org/wiki/Empatia\" target=\"_blank\" rel=\"noopener noreferrer\">empatycznej</a> <a href=\"https://pl.wikipedia.org/wiki/Dobro\" target=\"_blank\" rel=\"noopener noreferrer\">dobroci</a> okazywanej <a href=\"https://pl.wikipedia.org/wiki/Cierpienie\" target=\"_blank\" rel=\"noopener noreferrer\">cierpiącym</a>. W rozumieniu funkcjonalnym jest szlachetną aktywnością, jedną z <a href=\"https://pl.wikipedia.org/wiki/Paramita\" target=\"_blank\" rel=\"noopener noreferrer\">dziesięciu paramit</a> pochodzących z buddyjskiej szkoły <a href=\"https://pl.wikipedia.org/wiki/Theravada\" target=\"_blank\" rel=\"noopener noreferrer\">therawady</a>. Na duchowym poziomie jest konsekwencją i uzupełnieniem szlachetnego stanu umysłu określanego jako <a href=\"https://pl.wikipedia.org/wiki/Metta\" target=\"_blank\" rel=\"noopener noreferrer\">kochająca życzliwość</a>.", "Krum": "<b>Krum</b> (Korum) <b>Zwycięzca</b> lub <b>Straszny</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułg.</a> Кана Субиги Крум Страшни (ur.&#160;?, zm. <a href=\"https://pl.wikipedia.org/wiki/814\" target=\"_blank\" rel=\"noopener noreferrer\">814</a>) – kolejny władca <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a> po <a href=\"https://pl.wikipedia.org/wiki/Chan_(w%C5%82adca)\" target=\"_blank\" rel=\"noopener noreferrer\">chanie</a> <a href=\"https://pl.wikipedia.org/wiki/Kardam\" target=\"_blank\" rel=\"noopener noreferrer\">Kardamie</a> oraz założyciel nowej dynastii. Jego ród prawdopodobnie wywodził się z <a href=\"https://pl.wikipedia.org/wiki/Protobu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">Protobułgarów</a> <a href=\"https://pl.wikipedia.org/wiki/Panonia\" target=\"_blank\" rel=\"noopener noreferrer\">panońskich</a>. Był pierwszym władcą noszącym tytuł <i>chan subigi</i>.", "Kaz": "<p>Kazimieras Gediminas ⁇ Kaz ⁇ Prapuolenis (ang. Kazimieras Gedigiminas ?? Kaz ⁇ Prapuolenis; 31 lipca 1959, Hoboken) - amerykański artysta, ilustrator i scenarzysta pochodzenia litewskiego.</p>", "Kaleem": "<p>Kaleem to nazwisko i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Kyryło": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kyryl</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cyryl</b>.</p><b>Cyryl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>. Wywodzi się ze słowa κύριος znaczącego „pan”, „władca”. W Polsce używane było rzadko, częściej natomiast na Rusi Czerwonej.", "Khusrav": "<p>Khosrow (persk: خسرو) to męskie imię pochodzenia irańskiego, używane również jako tytuł. Khosrow może również odnosić się do:</p>", "Karlis": "<p>Kārlis lub Karlis to imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Kazuo": "<b>Kazuo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずお, カズオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Knud": "<p>Knut (norweski i szwedzki), Knud (danowski) lub Knútur (islandiiński) to skandynawskie i niemieckie imię, z którego angliczowaną formą jest Canute. W Niemczech używane są zarówno \"Knut\", jak i \"Knud\".</p>", "Koby": "<p>Coby lub Koby to imię męskie i żeńskie, nazwisko lub ksywkę pochodzące od nazwiska \"Jakob\" lub \"Jakob\".</p>", "Kwadwo": "<p>Kwadwo/Kwadjo/Kojo (Kwadwo w Ghanie) jest męskim imieniem pochodzącym od ludu Akan, co oznacza urodzony w poniedziałek. Jako nazwisko Akan, z Akans jest duża grupa etniczna składająca się z różnych plemion takich jak Fante, Asante, Akuapem, Bono, Akyem, między innymi, Kwadwo / Kwadjo jest czasami napisany jako \"Kojo\", Kwadwo lub Kwadjo i jest również mniej często używany jako nazwisko rodziny (patrz nazwisko Akan).</p>", "Kalvin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kalwin</b>.</p><b>Jan Kalwin</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a>&#160;<em>Jean Cauvin</em> albo również <i>Jean Calvin</i>; ur. <a href=\"https://pl.wikipedia.org/wiki/10_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">10 lipca</a> <a href=\"https://pl.wikipedia.org/wiki/1509\" target=\"_blank\" rel=\"noopener noreferrer\">1509</a> w <a href=\"https://pl.wikipedia.org/wiki/Noyon\" target=\"_blank\" rel=\"noopener noreferrer\">Noyon</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/27_maja\" target=\"_blank\" rel=\"noopener noreferrer\">27 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1564\" target=\"_blank\" rel=\"noopener noreferrer\">1564</a> w <a href=\"https://pl.wikipedia.org/wiki/Genewa\" target=\"_blank\" rel=\"noopener noreferrer\">Genewie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Francuzi\" target=\"_blank\" rel=\"noopener noreferrer\">francuski</a> <a href=\"https://pl.wikipedia.org/wiki/Teolog\" target=\"_blank\" rel=\"noopener noreferrer\">teolog</a> protestancki, reformator, <a href=\"https://pl.wikipedia.org/wiki/Kaznodzieja\" target=\"_blank\" rel=\"noopener noreferrer\">kaznodzieja</a>, <a href=\"https://pl.wikipedia.org/wiki/Humanista\" target=\"_blank\" rel=\"noopener noreferrer\">humanista</a>, <a href=\"https://pl.wikipedia.org/wiki/Pisarz\" target=\"_blank\" rel=\"noopener noreferrer\">pisarz</a> i organizator życia duchowego w <a href=\"https://pl.wikipedia.org/wiki/Szwajcaria\" target=\"_blank\" rel=\"noopener noreferrer\">Szwajcarii</a> w okresie <a href=\"https://pl.wikipedia.org/wiki/Reformacja\" target=\"_blank\" rel=\"noopener noreferrer\">reformacji</a>. Twórca jednej z doktryn religijnych – <a href=\"https://pl.wikipedia.org/wiki/Kalwinizm\" target=\"_blank\" rel=\"noopener noreferrer\">ewangelicyzmu reformowanego</a> (od jego nazwiska nazywanej kalwinizmem), przyjętej przez <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bcio%C5%82y_ewangelicko-reformowane\" target=\"_blank\" rel=\"noopener noreferrer\">Kościoły ewangelicko-reformowane</a>, <a href=\"https://pl.wikipedia.org/wiki/Prezbiterianizm\" target=\"_blank\" rel=\"noopener noreferrer\">prezbiteriańskie</a>, a następnie przez część <a href=\"https://pl.wikipedia.org/wiki/Kongregacjonalizm\" target=\"_blank\" rel=\"noopener noreferrer\">kongregacjonalnych</a>, opierającej się głównie na nauce o <a href=\"https://pl.wikipedia.org/wiki/Predestynacja\" target=\"_blank\" rel=\"noopener noreferrer\">predestynacji</a> oraz nauce o realnej i duchowej obecności <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a> w <a href=\"https://pl.wikipedia.org/wiki/Eucharystia_(sakrament)\" target=\"_blank\" rel=\"noopener noreferrer\">Wieczerzy Pańskiej</a>, w odróżnieniu od poglądu powszechnie panującego w <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościele katolickim</a> (obecności realnej i cielesnej). Nazywany przez swych zwolenników „teologiem <a href=\"https://pl.wikipedia.org/wiki/Par_excellence\" target=\"_blank\" rel=\"noopener noreferrer\">par excellence</a>”; „Arystotelesem Reformacji”; „Akwinatą Kościoła reformowanego”; „najbardziej chrześcijańskim mężem swej epoki” czy też „drugim patriarchą reformacji”.", "Klajdi": "<p>Klajdi to albaniańska męska nazwa i może odnosić się do: Klajdi Broshka (ur. 1993), albanianki piłkarz Klajdi Kuka (ur. 1990), albanianski piłkarze Klajdi Toska (ur. 1994), albanianka piłkarza</p>", "Kingston": "<p>Kingston Technology (ˈkɪŋstən tɛkˈnɑlədʒi) - amerykańska prywatna korporacja, która opracowuje, produkuje i sprzedaje flash-memory i inne komputera związane z pamięcią. W 2023 roku była 25-tą największą prywatną firmą USA według Forbes.</p>", "Krešimir": "<p>Krešimir to chorwackie imię męskie. Znani ludzie z nazwą używaną w mononimie obejmują: Krešimir I z Chorwacji, król Królestwa Chorwackiego od 935 do śmierci w 945 roku Michał Krešimir II z Chorwacją (zmarł 969), król Chorwacji od 949 do śmierci w 969 roku Krešimir III z Chorwacja (zmarła 1030), król Choracji w latach 1000-1030 z rodu Trpimirović i założyciel kadetów jego linii Dom Krešimirović Piotr Krešimir IV z Chorwac...</p>", "Krisna": "<p>Krisna (lat.) - rodzaj skaczących cykaczek (Cicadellidae) z podrodzin Iassinae (stryb Krisnini).</p>", "Kyril": "<p>Nazwa Cyril lub Kyrill to imię męskie, pochodzące od greckiej nazwy Κύριλλος (Kýrillos), która z kolei pochodzi od greckiego κύριος (kýrios) \"pan\". Istnieje wiele wariantów nazwy: Cyryl, Cyrill, Cy, Kiril, Kirill, Kiro, Kiryl, Kyryl, Kirillos, Kyrillo, Kyrylo.</p>", "Kavkaz": "<p>Kavkaz (armenska: Կովկաս, azerbaińska: Qafqaz, gruzińska: კავკასია (K'avk'asia), rosyjska: Кавка́з, adygea: Къэфкъас, osetiańska: Кавказ, chechnya: Кавкаz) jest regionem geograficznym znajdującym się na granicy między Azją a Europą, głównie na terytorium Gruzji, Azerbejdżanu, Armenii i części na południowej Rosji. Tu znajdują się Kaukazy, w których znajduje się najwyższa w Europie góra Elbrus.</p>", "Kwon": "<p>Kwon jest jedną z najpopularniejszych nazwisk Korejczyków.</p>", "Kazuma": "<b>Kazuma</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずま, カズマ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Ksawer": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ksawera</b>.</p><b>Ksawera</b>, <b>Ksaweryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">Ksawery</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Franciszka_Ksawera\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszka Ksawera</a> Cabrini.", "Kwabena": "<p>Kwabena jest męskim imieniem Akan wśród ludu Akan (tj. Ashanti, Akuapem, Akyem, Bono, Akwamu, Fante) w Ghanie, co oznacza \"narodzony w wtorek\" w języku Akan, zgodnie z ich systemem nazwań dnia.</p>", "Koichiro": "<p>Kōichirō, Koichiro, Kouichirou lub Kohichiroh to męskie japońskie imię.</p>", "Keiran": "<p>Ciarán (irlandzkie pisowni) lub Ciaran (szkocka gagelicka pisowni) jest tradycyjnie męskie nazwisko pochodzenia irlandzkiego i szkockiego. Oznacza to \"małe ciemne\" lub \"małe mrocznie włosne\", wytwarzane poprzez dodanie drobnego sufiksu do ciar (\"czarny\", \"ciemny\").</p>", "Kelwin": "<b>Kelwin</b> – jednostka <a href=\"https://pl.wikipedia.org/wiki/Temperatura\" target=\"_blank\" rel=\"noopener noreferrer\">temperatury</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">układzie SI</a>, oznaczana symbolem <b>K</b>. Nazwa pochodzi od brytyjskiego fizyka <a href=\"https://pl.wikipedia.org/wiki/William_Thomson\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Thomsona, lorda Kelvina</a>.", "Kenedy": "<p>Ogród Kennedy (ang. Kenedy county) - okręg stanu Texas w Stanach Zjednoczonych Ameryki.</p>", "Kajan": "<p>Kajan jest gminą w hrabstwie Elbasan w hrabstwa Elbasan w Albanii. W 2005 roku liczba ludności wynosiła 6225 osób.</p>", "Kwesi": "<p>Kwesi to męskie imię z Ghana. W tradycji ghanańskiej \"nazwa dni\" odnosi się do dzieci urodzonych w niedzielę.</p>", "Kaushal": "<p>Kaushal to hinduskie imię i nazwisko powszechne w Indiach, Sri Lance i Nepalu.</p>", "Krishna Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krishna</b>.</p><p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Kanti": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kant</b>.</p>Kant otwiera poczet klasycznych <a href=\"https://pl.wikipedia.org/wiki/Idealizm_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">idealistów niemieckich</a>; do kantyzmu odwoływały się też <a href=\"https://pl.wikipedia.org/wiki/Neokantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">neokantyzm</a> (kontynuacja), <a href=\"https://pl.wikipedia.org/wiki/Fenomenologia\" target=\"_blank\" rel=\"noopener noreferrer\">fenomenologia</a> (rewizja) oraz <a href=\"https://pl.wikipedia.org/wiki/Pozytywizm_logiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pozytywizm logiczny</a> (opozycja). Z tego ostatniego wywodzi się bliższy Kantowi <a href=\"https://pl.wikipedia.org/wiki/Popperyzm\" target=\"_blank\" rel=\"noopener noreferrer\">popperyzm</a> znany też jako <a href=\"https://pl.wikipedia.org/wiki/Krytyczny_racjonalizm\" target=\"_blank\" rel=\"noopener noreferrer\">krytyczny racjonalizm</a>. Kantyzm wywarł też wpływ na szkoły i kierunki, z którymi kontrastował; tomizm to <a href=\"https://pl.wikipedia.org/wiki/System_filozoficzny\" target=\"_blank\" rel=\"noopener noreferrer\">system filozoficzny</a> oparty na epistemologii realistycznej i dążący do wiedzy drogą metafizyki, jednak jedną z postaci <a href=\"https://pl.wikipedia.org/wiki/Neotomizm\" target=\"_blank\" rel=\"noopener noreferrer\">neotomizmu</a> jest <a href=\"https://pl.wikipedia.org/wiki/Tomizm_transcendentalizuj%C4%85cy\" target=\"_blank\" rel=\"noopener noreferrer\">tomizm transcendentalizujący</a>.", "Kali": "<p>Kali (lat. Kali) - rodzaj promieniowanych ryb z rodziny żółtych (Chiasmodontidae).</p>", "Kazuhiro": "<b>Kazuhiro</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずひろ, カズヒロ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Kamal Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kamal</b>.</p><p>Kamal (Martin Engels, Martin Engels, urodzony 18 kwietnia 1956 roku w Bilefeld, Niemcy) - niemiecki muzykiem i reżyserem dźwięku. Studiował muzykę w Düsseldorf, później pracował w Bielefeld.</p>", "Keiichi": "<b>Keiichi</b> lub <b>Kei'ichi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けいいち, ケイイチ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Karin": "<p>Karin (jap. かりん Karin) - 24-seryjny anime-serial, nadawany w Japonii od 3 listopada 2005 r. do 11 maja 2006 r.</p>", "Kabil": "Kabil pochodził z <a href=\"https://pl.wikipedia.org/wiki/Plemi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">plemienia</a> <a href=\"https://pl.wikipedia.org/wiki/Banu\" target=\"_blank\" rel=\"noopener noreferrer\">Banu</a>. Jego historia podana została w dziele <a href=\"https://pl.wikipedia.org/wiki/Hiszam_Ibn_Al-Kalbi\" target=\"_blank\" rel=\"noopener noreferrer\">Ibn al-Kalbiego</a>.", "Keven": "<p>Kevin to angielska forma irlandzkiego męskiego nazwiska Caoimhín . Składa się z caomh \"drogi; szlachetny\"; Staroirlandzkiego cóem i -gin (\"narodziny\"; Staro Irlandzkiego gein).</p>", "Kosmo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cosmo</b>.</p><p>Benjamin Gideon (węgierski)  Benjamin Gedeon; rod.</p>", "Kyan": "<p>Kyan jest nazwiskiem i nazwiskiem, co oznacza \"starożytne\" lub \"trwałe\". Jest to alternatywne pisownię nazwy Kian, która jest wariantem starożytnego irlandzkiego Cian.</p>", "Kourosh": "<b>Kourosh</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;کوروش، کورش&#8206;, wymawiany również Koorosh lub Kurosh) – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie popularne na terenie <a href=\"https://pl.wikipedia.org/wiki/Iran\" target=\"_blank\" rel=\"noopener noreferrer\">Iranu</a>. Pochodzi od imienia <a href=\"https://pl.wikipedia.org/wiki/Cyrus\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrus</a>.", "Kasym": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kasim</b>.</p><p>Kasim jako imię, wariant Qasim. Może odnosić się do:</p>", "Klimentii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Klimenti</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kliment</b>.</p><p>Kliment (cyrylicki: Климент) to męskie imię, słowiańska forma późnolatynskiej nazwy Klement. Klim jest formą mniejszą.</p>", "Kamron": "<p>Kamran (perskie: کامران Kāmrān) to perskie imię męskie oznaczające \"dobry, szczęśliwy\". Nazwa ta jest powszechnie używana w Iranie i Azerbejdżanie, a także w Bangladeszu, Tadżykistanie, Afganistanie, Uzbekistanie i Pakistanie.</p>", "Kalistrate": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kalistrat</b>.</p><b>Kalistrat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się ze złożenia słów <i>kalios</i> i <i>stratos</i> oznaczających kolejno \"piękno\" i \"armia\". Imię to nosiło kilku świętych katolickich.", "Karma": "<p>Przedsiębiorstwo, zawód, kariera, dziennik, dziennikarz lub wywiad to pojęcie o działalności, działaniu lub pracy i jej skutkach lub konsekwencjach. W Indiach odnosi się do duchowych zasad w religii, gdy intencje i działania jednostki mogą wpływać na nią w przyszłości.</p>", "Kenta": "<b>Kenta</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けんた, ケンタ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kamal Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kamal</b>.</p><p>Kamal (Martin Engels, Martin Engels, urodzony 18 kwietnia 1956 roku w Bilefeld, Niemcy) - niemiecki muzykiem i reżyserem dźwięku. Studiował muzykę w Düsseldorf, później pracował w Bielefeld.</p>", "Kevin Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kant": "Kant otwiera poczet klasycznych <a href=\"https://pl.wikipedia.org/wiki/Idealizm_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">idealistów niemieckich</a>; do kantyzmu odwoływały się też <a href=\"https://pl.wikipedia.org/wiki/Neokantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">neokantyzm</a> (kontynuacja), <a href=\"https://pl.wikipedia.org/wiki/Fenomenologia\" target=\"_blank\" rel=\"noopener noreferrer\">fenomenologia</a> (rewizja) oraz <a href=\"https://pl.wikipedia.org/wiki/Pozytywizm_logiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pozytywizm logiczny</a> (opozycja). Z tego ostatniego wywodzi się bliższy Kantowi <a href=\"https://pl.wikipedia.org/wiki/Popperyzm\" target=\"_blank\" rel=\"noopener noreferrer\">popperyzm</a> znany też jako <a href=\"https://pl.wikipedia.org/wiki/Krytyczny_racjonalizm\" target=\"_blank\" rel=\"noopener noreferrer\">krytyczny racjonalizm</a>. Kantyzm wywarł też wpływ na szkoły i kierunki, z którymi kontrastował; tomizm to <a href=\"https://pl.wikipedia.org/wiki/System_filozoficzny\" target=\"_blank\" rel=\"noopener noreferrer\">system filozoficzny</a> oparty na epistemologii realistycznej i dążący do wiedzy drogą metafizyki, jednak jedną z postaci <a href=\"https://pl.wikipedia.org/wiki/Neotomizm\" target=\"_blank\" rel=\"noopener noreferrer\">neotomizmu</a> jest <a href=\"https://pl.wikipedia.org/wiki/Tomizm_transcendentalizuj%C4%85cy\" target=\"_blank\" rel=\"noopener noreferrer\">tomizm transcendentalizujący</a>.", "Kasum": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kasumi</b>.</p><b>Kasumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かすみ, カスミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kyrył": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cyryl</b>.</p><b>Cyryl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>. Wywodzi się ze słowa κύριος znaczącego „pan”, „władca”. W Polsce używane było rzadko, częściej natomiast na Rusi Czerwonej.", "Kunibert": "<b>Kunibert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „dzielny i lśniący, jaśniejący”, od germ. <i>kuoni</i> – „dzielny, odważny”, i <i>beraht</i> – „jasny, lśniący”. Patronem tego imienia jest św. Kunibert, biskup <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (VII wiek).", "Kaio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Caio</b>.</p><p>Caio (lat. - rodzaj szczurów skrzydeł z rodziny pawińoczczęści z podrodzin Arsenurinae.</p>", "Kevin Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kaustubh": "<p>Kaustubh może odnosić się do Kaustubha, boskiego kamienia szlachetnego przypisany boskości Wisnu Kaustubh Khade (urodzony 1987), indyjski kajak Kaustubh Pawar (urodzona 1990), indyjskiego kryketa</p>", "Koriun": "<b>Koriun</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiański</a> Կորյուն lub Կորիւն) – pierwszy dziejopisarz używający języka ormiańskiego. Jego dzieło <i>Żywot Mesropa</i> zawiera wiele informacji dotyczących ewangelizacji <a href=\"https://pl.wikipedia.org/wiki/Armenia\" target=\"_blank\" rel=\"noopener noreferrer\">Armenii</a> i stworzenia <a href=\"https://pl.wikipedia.org/wiki/Alfabet\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiego</a>. Niektórzy współcześni historycy uważają, że Koriun był z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gruzini\" target=\"_blank\" rel=\"noopener noreferrer\">Gruzinem</a> (<a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Iberii\" target=\"_blank\" rel=\"noopener noreferrer\">Iberia Kaukaska</a> lub miał mieszane pochodzenie, gruzińsko- <a href=\"https://pl.wikipedia.org/wiki/Ormianie\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskie</a>. Koriun był wychowankiem <a href=\"https://pl.wikipedia.org/wiki/Mesrop_Masztoc\" target=\"_blank\" rel=\"noopener noreferrer\">Mesropa Masztoca</a>. Wiadomo że nauki pobierał również w <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Bizancjum</a> a do Armenii powrócił w 432 roku. Był bliskim przyjacielem Eznika z Kolb. Został mianowany biskupem Iberii i oprócz pracy duszpasterskiej i misjonarskiej zajmował się także przekładami na język ormiański. Przypisuje mu się przetłumaczenie trzech, <a href=\"https://pl.wikipedia.org/wiki/Apokryf\" target=\"_blank\" rel=\"noopener noreferrer\">apokryficznych</a> ksiąg <a href=\"https://pl.wikipedia.org/wiki/Machabeusze\" target=\"_blank\" rel=\"noopener noreferrer\">Machabeuszy</a>. Koriun jako pierwszy podał informację jakoby Mesrop Mesztoc był twórcą <a href=\"https://pl.wikipedia.org/wiki/Alfabet_gruzi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu gruzińskiego</a>. Po śmierci Masztoca Koriun współpracował z Howsepem, jednym z najważniejszych, ormiańskich liderów duchownych. Na jego polecenie zaczął spisywać biografię Mesropa. Zakończył prace jeszcze przed <a href=\"https://pl.wikipedia.org/wiki/Bitwa_pod_Awarajr\" target=\"_blank\" rel=\"noopener noreferrer\">bitwą pod Awarajr</a>, którą datuje się na 451 rok i która doprowadziła do znacznych zmian w regionie. Prace Koriuna zostały przetłumaczone między innymi na <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">rosyjski</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielski</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuski</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecki</a>.", "Kirollos": "<p>Cyryl (zwany również Cyryllem lub Cyryllem) jest męskim imieniem. Pochodzi z greckiego imienia Κύριλλος (Kýrillos), co oznacza \"władca, mistrzowczy\", co z kolei pochodzi z greckiej κυριος (kýrios) \"pan\".</p>", "Klodian": "Klodion był na poły legendarnym królem <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">Franków</a> salickich. Uważa się go za ojca <a href=\"https://pl.wikipedia.org/wiki/Meroweusz\" target=\"_blank\" rel=\"noopener noreferrer\">Meroweusza</a> (łac. <i>Merovechus</i> lub <i>Meroveus</i>). Miał być synem <a href=\"https://pl.wikipedia.org/wiki/Faramund\" target=\"_blank\" rel=\"noopener noreferrer\">Faramunda</a> (łac. <i>Pharamundus</i>) i Argotty, pochodzącej z <a href=\"https://pl.wikipedia.org/wiki/Turyngia\" target=\"_blank\" rel=\"noopener noreferrer\">Turyngii</a>. Tym samym był prawdopodobnym następcą <a href=\"https://pl.wikipedia.org/wiki/Markomer\" target=\"_blank\" rel=\"noopener noreferrer\">Markomera</a> (łac. <i>Marcomerus</i> lub <i>Marcomirus</i>), nieznanego bliżej władcy Franków salickich. W czasie panowania rezydował w Tornacum, obecnie <a href=\"https://pl.wikipedia.org/wiki/Tournai\" target=\"_blank\" rel=\"noopener noreferrer\">Tournai</a> w <a href=\"https://pl.wikipedia.org/wiki/Belgia\" target=\"_blank\" rel=\"noopener noreferrer\">Belgii</a>.", "Kevin David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kazuya": "<b>Kazuya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずや, カズヤ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Klement": "<b>Klemens</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „człowiek o łagodnym usposobieniu”, „delikatny”, „pobłażliwy”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Klemencja\" target=\"_blank\" rel=\"noopener noreferrer\">Klemencja</a>.", "Kurian": "<p>Kurian (zwany również Kurien) jest nazwą św. Tomasa Chrześcijan i syryjskiego chrześcijaństwa pochodzącego z syryjskiej aramejskiej lub greckiej pochodzenia, przypuszczalnie pochodzącą z nazwy Quriaqos (⁇) lub greckiego Kyrios lub kurios (w starożytnym grecku κύριος) oznaczając Pana, mistrza, władzę lub władzę, i jest bardzo popularny wśród chrześcijan w Kerala zarówno jako imię i nazwisko. Starożytna rzymska nazwa \"Cyriacus\" jest uważana za odpowiednik greckiego...</p>", "Khassan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khasan</b>.</p><p>Khasan (rosyjski: Хасан) to miejscowość miastna (urbanizacja) w dzielnicy Khasansky w regionie Primorsky Krai, Rosja. Znajduje się niedaleko przejścia rzeki Dżomon, gdzie graniczą trzy kraje: Rosja, Chiny i Republika Demokratyczna Ludowa Korei.</p>", "Kadhim": "<p>Kazem (zwany również Kadim, Kadhem, Kadhim, Kazim, Qazim lub Cathum; napisany w języku arabskim: كاظم, w perskim: کاظِم) oznacza \"tolerancja\", \"przebawienie\" i \"mieć cierpliwość\" jest arabskim męskim nazwiskiem. Chociaż wymowa litery arabskiej Ẓāʾ jest często bliżej silnego dźwięku \"d\", biorąc pod uwagę rozpowszechnienie nazwy w Wielkim Iranie i późniejszych wymian kulturowych między Persją i subkontynentem indyjskim, Azją Środkową i Anatolii, litera...</p>", "Karri": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kari</b>.</p><p>Macromonycha (lat.) - rodzaj żółwiek schildonoznosnych (Cassidini) z rodziny liściżerców. Trzy rodzaje.</p>", "Kjetil": "<p>Kjetil to norweska imię męskie. Kjetil Aleksander Lie (ur. 1980), norweski szachowca, ósmego międzynarodowego mistrza Kjetil André Aamodt (ur. 1971), norweska były rowerka Kjetil Bang-Hansen (ur. 1940), norweskiej aktorki, tancerki, producenta scenicznego i reżysera teatralnego Kjetil Bjørklund (ur. 1967), norweskiego polityka z Partii W lewicy socjalistycznej Kjetil'a Bjørlo (ur. 1968), norweskich...</p>", "Kevin Santiago": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kajmir": "<b>Kanimir</b>, <b>Kanimier</b>, <b>Kajmir</b>, <b>Kalmir</b> — <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów: <i>Kani-</i> w różnych wersjach brzmieniowych (\"gościć, zapraszać\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"ten, u kogo gości pokój\".", "Kody": "<b>Kod</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>codex</i>), spis – ciąg składników sygnału (kombinacji sygnałów elementarnych, np. kropek i kresek, impulsów prądu, symboli) oraz reguła ich przyporządkowania składnikom wiadomości (np. znakom pisma). W niektórych zastosowaniach, głównie przy przesyłaniu informacji podlegających utajnieniu, zwany jest <a href=\"https://pl.wikipedia.org/wiki/Szyfr\" target=\"_blank\" rel=\"noopener noreferrer\">szyfrem</a>. Kody są stosowane m.in. w telegrafii, telefonii, w technice cyfrowej.", "Kochan": "<b>Kochan</b> – imię <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> (a współcześnie polskie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> odimienne), model jednoczłonowy, <a href=\"https://pl.wikipedia.org/wiki/Imies%C5%82%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">imiesłowowy</a> <i>Koch-an</i>, od <i>kochać</i>; zobacz podobne: <a href=\"https://pl.wikipedia.org/wiki/Poznan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Poznan</a>, <a href=\"https://pl.wikipedia.org/wiki/Stojan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Stojan</a>, <a href=\"https://pl.wikipedia.org/wiki/Ciechos%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Ciechan</a>, <a href=\"https://pl.wikipedia.org/wiki/Chocies%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Chocian</a>, mające swoje historyczne i nazewnicze potwierdzenie w licznych nazwach miejscowych: <a href=\"https://pl.wikipedia.org/wiki/Kochan%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Kochanów</a>, <a href=\"https://pl.wikipedia.org/wiki/Kochan%C3%B3wka\" target=\"_blank\" rel=\"noopener noreferrer\">Kochanówka</a>, <a href=\"https://pl.wikipedia.org/wiki/Kochanowo\" target=\"_blank\" rel=\"noopener noreferrer\">Kochanowo</a>. Staropolskie Koch mogło być skróceniem od Kochana, ale również od <a href=\"https://pl.wikipedia.org/wiki/Konstanty\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantyna</a> lub <a href=\"https://pl.wikipedia.org/wiki/Konrad_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Konrada</a>. Imię to notowane w Polsce od 1136 r.", "Kostya": "<p>Konstantyn (lub; Łacińska: Cōnstantīnus, Grecki: Κωνσταντῖνος, Kōnstantînos) to męskie i żeńskie (na francusku na przykład) nazwisko i nazwisko pochodzące od łacińskiej nazwy Constantinus, hipokorystyczny z pierwszych nazw Constans i Constantius, oba oznaczają \"stały, stały\" w łacińskim. Popularność pochodzi od trzynastu cesarzy rzymskich i bizantyjskich, począwszy od Konstantyna Wielkiego.</p>", "Krishna Rao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krishna</b>.</p><p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Krištof": "<p>Kristof, Krištof lub Kristóf mogą być zarówno nazwiskiem, jak i nazwiskiem. Do wybitnych osób z tym nazwiskiem należą:</p>", "Krescenty": "<b>Krescenty</b>, <b>Krescencjusz</b>, <b>Krescens</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwy rodu, która z kolei pochodzi od słowa <i>crescere</i> – \"wzrastać, narastać\". Wśród patronów – św. Krescencjusz (Krescenty), jeden z synów św. <a href=\"https://pl.wikipedia.org/wiki/Symforoza\" target=\"_blank\" rel=\"noopener noreferrer\">Symforozy</a> (<a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wiek</a>).", "Khrystyian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khristiian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khristian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Christian</b>.</p><p>Christian (niem. Christian, umysł.</p>", "Kosei": "<p>Kōsei, Kosei lub Kousei mogą odnosić się do:</p>", "Klimenti": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kliment</b>.</p><p>Kliment (cyrylicki: Климент) to męskie imię, słowiańska forma późnolatynskiej nazwy Klement. Klim jest formą mniejszą.</p>", "Kirile": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kiril</b>.</p><p>Mężczyzna Cyril (lub Kiril lub Кирилл) jest powszechną nazwą w świecie prawosławskich słowiańskich, zwłaszcza w Bułgarii, Macedonii Północnej i Rosji. Jest również dobrze znany w Grecji, ale w różnych formach, takich jak Kyriakos.</p>", "Kevin Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kai-Uwe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kai</b>.</p><b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Ksaweryn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ksaweryna</b>.</p><b>Ksawera</b>, <b>Ksaweryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">Ksawery</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Franciszka_Ksawera\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszka Ksawera</a> Cabrini.", "Kuriakose": "<p>Kuriakose (syrycki: ⁇) jest powszechną męską nazwą i nazwą wśród chrześcijan Świętego Tomasa, głównie z centralnej części stanu Kerala w Indiach i okolicznych obszarów. Do pochodnych nazwy Kuriakose należą Kurian i Kurien.</p>", "Krsto": "<p>Krsto (kręgowy: Krсто), również Krste lub Krǎstyo jest sławskim imieniem męskim. Krsto Papić, chorwacki reżyser Krsto Ungnad, Ban of Croatia Krsto Zrnov Popović, czarnogorski żołnierz Fran Krsto Frankopan, chorwański poeta barockie, szlachta i polityk Vuk Krsto Fran Kopan, choracki szlachtańiec i żołnierz Krsto Hegedušić, chorański malarz, ilustrator i projektant teatralny Krste Asanović, inżynier komputerowy Krste Crvenkovski,...</p>", "Kevin Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kamuran": "<p>Kamran (perskie: کامران Kāmrān) to perskie imię męskie oznaczające \"dobry, szczęśliwy\". Nazwa ta jest powszechnie używana w Iranie i Azerbejdżanie, a także w Bangladeszu, Tadżykistanie, Afganistanie, Uzbekistanie i Pakistanie.</p>", "Koppány": "<b>Koppány</b> (zm. <a href=\"https://pl.wikipedia.org/wiki/997\" target=\"_blank\" rel=\"noopener noreferrer\">997</a>) – <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierski</a> książę. Pochodził z dynastii <a href=\"https://pl.wikipedia.org/wiki/Arpadowie\" target=\"_blank\" rel=\"noopener noreferrer\">Arpadów</a>, jednak nie wiadomo z której linii. Przypuszcza się, że był potomkiem <a href=\"https://pl.wikipedia.org/wiki/Tarhos\" target=\"_blank\" rel=\"noopener noreferrer\">Tarhosa</a>. Był synem Zerinda.", "Koryun": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Koriun</b>.</p><b>Koriun</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiański</a> Կորյուն lub Կորիւն) – pierwszy dziejopisarz używający języka ormiańskiego. Jego dzieło <i>Żywot Mesropa</i> zawiera wiele informacji dotyczących ewangelizacji <a href=\"https://pl.wikipedia.org/wiki/Armenia\" target=\"_blank\" rel=\"noopener noreferrer\">Armenii</a> i stworzenia <a href=\"https://pl.wikipedia.org/wiki/Alfabet\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiego</a>. Niektórzy współcześni historycy uważają, że Koriun był z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gruzini\" target=\"_blank\" rel=\"noopener noreferrer\">Gruzinem</a> (<a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Iberii\" target=\"_blank\" rel=\"noopener noreferrer\">Iberia Kaukaska</a> lub miał mieszane pochodzenie, gruzińsko- <a href=\"https://pl.wikipedia.org/wiki/Ormianie\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskie</a>. Koriun był wychowankiem <a href=\"https://pl.wikipedia.org/wiki/Mesrop_Masztoc\" target=\"_blank\" rel=\"noopener noreferrer\">Mesropa Masztoca</a>. Wiadomo że nauki pobierał również w <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Bizancjum</a> a do Armenii powrócił w 432 roku. Był bliskim przyjacielem Eznika z Kolb. Został mianowany biskupem Iberii i oprócz pracy duszpasterskiej i misjonarskiej zajmował się także przekładami na język ormiański. Przypisuje mu się przetłumaczenie trzech, <a href=\"https://pl.wikipedia.org/wiki/Apokryf\" target=\"_blank\" rel=\"noopener noreferrer\">apokryficznych</a> ksiąg <a href=\"https://pl.wikipedia.org/wiki/Machabeusze\" target=\"_blank\" rel=\"noopener noreferrer\">Machabeuszy</a>. Koriun jako pierwszy podał informację jakoby Mesrop Mesztoc był twórcą <a href=\"https://pl.wikipedia.org/wiki/Alfabet_gruzi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu gruzińskiego</a>. Po śmierci Masztoca Koriun współpracował z Howsepem, jednym z najważniejszych, ormiańskich liderów duchownych. Na jego polecenie zaczął spisywać biografię Mesropa. Zakończył prace jeszcze przed <a href=\"https://pl.wikipedia.org/wiki/Bitwa_pod_Awarajr\" target=\"_blank\" rel=\"noopener noreferrer\">bitwą pod Awarajr</a>, którą datuje się na 451 rok i która doprowadziła do znacznych zmian w regionie. Prace Koriuna zostały przetłumaczone między innymi na <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">rosyjski</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielski</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuski</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecki</a>.", "Kagan": "Pierwsze świadectwo odnośnie do używania tytułu kagan pochodzi z ok. 265 roku. Wtedy to w źródłach <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chińskich</a> tytuł pojawia się w związku z Qifu, jednym z plemion <a href=\"https://pl.wikipedia.org/wiki/Xianbei\" target=\"_blank\" rel=\"noopener noreferrer\">Xianbei</a>. Tytuł rozpowszechnił się w związku z używaniem go przez władców <a href=\"https://pl.wikipedia.org/wiki/Rouran\" target=\"_blank\" rel=\"noopener noreferrer\">Rouran</a> oraz ich następców, <a href=\"https://pl.wikipedia.org/wiki/Turkuci\" target=\"_blank\" rel=\"noopener noreferrer\">Turkutów</a>. Następnie używany był przez wielu władców <a href=\"https://pl.wikipedia.org/wiki/Ludy_tureckie\" target=\"_blank\" rel=\"noopener noreferrer\">tureckich</a>, <a href=\"https://pl.wikipedia.org/wiki/Mongo%C5%82owie\" target=\"_blank\" rel=\"noopener noreferrer\">mongolskich</a>, <a href=\"https://pl.wikipedia.org/wiki/Awarowie\" target=\"_blank\" rel=\"noopener noreferrer\">Awarów</a>, a także <a href=\"https://pl.wikipedia.org/wiki/Rusowie\" target=\"_blank\" rel=\"noopener noreferrer\">Rusów</a>, którzy przyjęli go za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/Chazarowie\" target=\"_blank\" rel=\"noopener noreferrer\">Chazarów</a>.", "Kolade": "<p>Kọ́ládé jest męskim imieniem joruba, powszechnie używanym jako nazwisko w Nigerii. To znaczy \"Przyprowadź wiele zaszczytów\".</p>", "Kawa": "<b>Kawa</b> – napój sporządzany z palonych, a następnie zmielonych lub poddanych <a href=\"https://pl.wikipedia.org/wiki/Instantyzacja\" target=\"_blank\" rel=\"noopener noreferrer\">instantyzacji</a> ziaren <a href=\"https://pl.wikipedia.org/wiki/Kawowiec\" target=\"_blank\" rel=\"noopener noreferrer\">kawowca</a>, zwykle podawany na gorąco. Pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">Etiopii</a>, w <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europie</a> pojawiła się około XVI wieku. Jedna z najpopularniejszych <a href=\"https://pl.wikipedia.org/wiki/U%C5%BCywka\" target=\"_blank\" rel=\"noopener noreferrer\">używek</a> na świecie i główne źródło <a href=\"https://pl.wikipedia.org/wiki/Kofeina\" target=\"_blank\" rel=\"noopener noreferrer\">kofeiny</a>.", "Kürşad": "<p>Kürşad to tureckie imię dla mężczyzn. Do wybitnych osób z tym nazwiskiem należą: Kürşad Türkşen, biochemik Kürşat Tüzmen (ur. 1958), turecki urzędnik</p>", "Krishnendu": "<p>Krishnendu to indyjskie imię męskie. Znani ludzie z nazwiskiem to: Krishnendu Adhikari (ur. 1982), indyjski aktor i reżyser Krishnendu Chakrabarty, indyjsko-amerykański inżynier Krishnendu Chatterjee (ur. 1978), indyjscy naukowiec komputerowy Krishnendu Narayan Choudhury (ur. 1957), indyjskie adwokat i polityk Krishnendu Paul (ur. 1973), indyjska polityk KrishNendu Roy, indyjski piłkarz Krishnendu Sengupta (ur. 1970), indy...</p>", "Kriss": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kris</b>.</p><p>Chris (pol. Kris; prawdziwe imię - Kshshштоf Piotrovski, płeć.</p>", "Krys": "<p>Krys to przede wszystkim męskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Kenichiro": "<p>Ken'ichirō, Kenichirō, Kenichiro lub Kenichirou (zwany: 健一郎, 兼一郎,賢一郎 lub 研一郎) to męskie japońskie imię. Znanymi osobami z nazwiska są: Ken'ichiro Arai (新井 健一郎; ur. 1972), japoński zawodowy wrestler Kenichiro Fukui (福井 健 一郎; ur . 1970), japoński kompozytor gier wideo i muzyka elektroniczna Kenichiro Fumita (文田 健 一 郎; ur., 1995), japowski sportowca Ken-Ichiro Kobayashi (小林 研 一郎; Ur. 1940), japończyk dyrygent i kompozytor...</p>", "Kiriil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kiril</b>.</p><p>Mężczyzna Cyril (lub Kiril lub Кирилл) jest powszechną nazwą w świecie prawosławskich słowiańskich, zwłaszcza w Bułgarii, Macedonii Północnej i Rosji. Jest również dobrze znany w Grecji, ale w różnych formach, takich jak Kyriakos.</p>", "Katsumi": "<b>Katsumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かつみ, カツミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Kodjo": "<p>Kodjo to zarówno nazwisko, jak i imię. To może być imię dnia Akan.</p>", "Kanishk": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kanishka</b>.</p><p>Cesarz Kanishka (Francuz: कनिष्क, Hiszpański: Κανη ⁇ κι, Święty Han: 迦 ⁇ 色 ⁇) był królem Kyu Sōng w Azji Środkowej, był Kyu Sóng z rodu Nguyệt Chi. Armią Han-Viet Kanishka są Święty Król, Święty Książę, Święta Król, Dżan Książą, Piesny Król, Piesne Król lub Święty Sztel.</p>", "Kajo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kaj</b>.</p>Na starożytność tego imienia wskazuje <a href=\"https://pl.wikipedia.org/wiki/Ortografia\" target=\"_blank\" rel=\"noopener noreferrer\">pisownia</a> jego skrótu, którym tradycyjnie było <i>C.</i> <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">Litera</a> ta pierwotnie oznaczała głoskę <i>g</i>, gdyż pochodziła ona od greckiej <i><a href=\"https://pl.wikipedia.org/wiki/Gamma\" target=\"_blank\" rel=\"noopener noreferrer\">Γ</a></i> (zaś litera <i>K</i> oznaczała głoskę <i>k</i>). Te dwie litery stosowano w ten właśnie sposób do roku <a href=\"https://pl.wikipedia.org/wiki/312_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">312 p.n.e.</a>, kiedy cenzor <a href=\"https://pl.wikipedia.org/wiki/Appiusz_Klaudiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Appiusz Klaudiusz</a> zmienił pisownię, wprowadzając literę <i>G</i> powstałą z przekształcenia <i>C</i>, a literze <i>C</i> nadał wartość głoski <i>k</i>. Oznacza to, że pisownia skrótu imienia <i>Gaius</i> utrwaliła się jeszcze przed reformą, a więc i samo imię musi pochodzić sprzed <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>", "Kuber": "Informacje o Kuberze pochodzą wyłącznie z <i>Żywota i cudów świętego Demetriusza</i>. Nie są znane okoliczności w jakich w II połowie VII wieku pojawił się na czele koczowników bułgarskich w granicach państwa <a href=\"https://pl.wikipedia.org/wiki/Kaganat_Awar%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">awarskiego</a>. Ponieważ nastąpiło to w okresie po śmierci chana Kubrata i po najeździe <a href=\"https://pl.wikipedia.org/wiki/Chazarowie\" target=\"_blank\" rel=\"noopener noreferrer\">Chazarów</a> na <a href=\"https://pl.wikipedia.org/wiki/Wielka_Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Wielką Bułgarię</a>, jest możliwe, że opuścił Wielką Bułgarię pod naporem Chazarów i przeniósł się ze swym ludem na zachód. Historyk bizantyjski <a href=\"https://pl.wikipedia.org/wiki/Teofan_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Teofanes</a> piszący w IX wieku podaje informację, że synowie Kubrata po śmierci ojca, pokonani przez Chazarów, w większości opuścili ziemie Wielkiej Bułgarii. O czwartym z synów pisze tak: „poddawszy się kaganowi awarskiemu został ze swoim ludem w Panonii awarskiej”. Zdaniem części historyków jest całkiem możliwe, że nieznany z imienia syn Kubrata jest Kuberem, o którym mówi <i>Żywot i cuda św. Demetriusza</i>.", "Kevin Stiven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kostia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kostya</b>.</p><p>Konstantyn (lub; Łacińska: Cōnstantīnus, Grecki: Κωνσταντῖνος, Kōnstantînos) to męskie i żeńskie (na francusku na przykład) nazwisko i nazwisko pochodzące od łacińskiej nazwy Constantinus, hipokorystyczny z pierwszych nazw Constans i Constantius, oba oznaczają \"stały, stały\" w łacińskim. Popularność pochodzi od trzynastu cesarzy rzymskich i bizantyjskich, począwszy od Konstantyna Wielkiego.</p>", "Kavindu": "<p>Kavindu to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Keerthi": "<p>Keerthi, również pisane Keerti, Keerthy lub Kirti, to indyjskie imienne. Może odnosić się do: Keerti Gaekwad Kelkar (ur. 1974), indyjska aktorka i modelka Keerti Nagpure (ur.</p>", "Kee": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ke</b>.</p><b>Ќ</b>, <b>ќ</b> – litera <a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylicy</a> używana w alfabecie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka macedońskiego</a> oznaczająca /kj/. Często odpowiada <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackiemu</a> <a href=\"https://pl.wikipedia.org/wiki/%C4%86\" target=\"_blank\" rel=\"noopener noreferrer\">Ć</a>/<a href=\"https://pl.wikipedia.org/wiki/%D0%8B\" target=\"_blank\" rel=\"noopener noreferrer\">Ћ</a>, a niekiedy także np. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiemu</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskiemu</a> <a href=\"https://pl.wikipedia.org/wiki/C\" target=\"_blank\" rel=\"noopener noreferrer\">C</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">rosyjskiemu</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%A7\" target=\"_blank\" rel=\"noopener noreferrer\">Ч</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskiemu</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%A9\" target=\"_blank\" rel=\"noopener noreferrer\">Щ</a>.", "Karani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karan</b>.</p><p>Koran: Koran jest znakem dyakrytycznym tajskiego pisma. Koran - stanowisko w Siłach Achemeniódów.</p>", "Karion": "<b>Jądro komórkowe</b>, <b>nukleus</b> – otoczone podwójną błoną <a href=\"https://pl.wikipedia.org/wiki/Organellum\" target=\"_blank\" rel=\"noopener noreferrer\">organellum</a> obecne we wszystkich <a href=\"https://pl.wikipedia.org/wiki/Kom%C3%B3rka\" target=\"_blank\" rel=\"noopener noreferrer\">komórkach</a> <a href=\"https://pl.wikipedia.org/wiki/Eukarionty\" target=\"_blank\" rel=\"noopener noreferrer\">eukariotycznych</a>, z wyjątkiem tych, które wtórnie je utraciły w trakcie różnicowania, np. dojrzałe <a href=\"https://pl.wikipedia.org/wiki/Erytrocyt\" target=\"_blank\" rel=\"noopener noreferrer\">erytrocyty</a> niektórych <a href=\"https://pl.wikipedia.org/wiki/Ssaki\" target=\"_blank\" rel=\"noopener noreferrer\">ssaków</a> (min. człowiek i <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82py_cz%C5%82ekokszta%C5%82tne\" target=\"_blank\" rel=\"noopener noreferrer\">człekokształtne</a>). Zawiera większość <a href=\"https://pl.wikipedia.org/wiki/Materia%C5%82_genetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">materiału genetycznego</a> komórki, zorganizowanego w postaci wielu długich, <a href=\"https://pl.wikipedia.org/wiki/Podw%C3%B3jna_helisa\" target=\"_blank\" rel=\"noopener noreferrer\">dwuniciowych łańcuchów</a> <a href=\"https://pl.wikipedia.org/wiki/Kwas_deoksyrybonukleinowy\" target=\"_blank\" rel=\"noopener noreferrer\">DNA</a> związanych z dużą ilością <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82ka\" target=\"_blank\" rel=\"noopener noreferrer\">białek</a>, głównie <a href=\"https://pl.wikipedia.org/wiki/Histony\" target=\"_blank\" rel=\"noopener noreferrer\">histonowych</a>, które razem tworzą <a href=\"https://pl.wikipedia.org/wiki/Chromosom\" target=\"_blank\" rel=\"noopener noreferrer\">chromosomy</a>. <a href=\"https://pl.wikipedia.org/wiki/Gen\" target=\"_blank\" rel=\"noopener noreferrer\">Geny</a> zlokalizowane w chromosomach stanowią <a href=\"https://pl.wikipedia.org/wiki/Genom\" target=\"_blank\" rel=\"noopener noreferrer\">genom</a> komórki. Funkcją jądra komórkowego jest przechowywanie i <a href=\"https://pl.wikipedia.org/wiki/Replikacja_DNA\" target=\"_blank\" rel=\"noopener noreferrer\">powielanie</a> informacji genetycznej oraz kontrolowanie czynności komórki, poprzez regulowanie <a href=\"https://pl.wikipedia.org/wiki/Ekspresja_genu\" target=\"_blank\" rel=\"noopener noreferrer\">ekspresji genów</a>. Główne struktury, które obecne są w budowie jądra komórkowego to <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ona_j%C4%85drowa\" target=\"_blank\" rel=\"noopener noreferrer\">błona jądrowa</a>, podwójna membrana otaczająca całe organellum i oddzielająca je od <a href=\"https://pl.wikipedia.org/wiki/Cytoplazma\" target=\"_blank\" rel=\"noopener noreferrer\">cytoplazmy</a> oraz blaszka jądrowa, sieć delikatnych włókienek białkowych utworzonych przez <a href=\"https://pl.wikipedia.org/wiki/Laminy\" target=\"_blank\" rel=\"noopener noreferrer\">laminy</a>, stanowiących rusztowanie dla jądra i nadających mu wytrzymałość mechaniczną. Błona jądrowa jest nieprzepuszczalna dla większości cząsteczek, dlatego obecne są w niej <a href=\"https://pl.wikipedia.org/wiki/Por_j%C4%85drowy\" target=\"_blank\" rel=\"noopener noreferrer\">pory jądrowe</a>. Są to kanały przechodzące przez obie błony, umożliwiające transport <a href=\"https://pl.wikipedia.org/wiki/Jon\" target=\"_blank\" rel=\"noopener noreferrer\">jonów</a> i innych cząstek. Transport większych cząstek, takich jak białka, jest ściśle kontrolowany i zachodzi na zasadzie <a href=\"https://pl.wikipedia.org/wiki/Transport_aktywny\" target=\"_blank\" rel=\"noopener noreferrer\">transportu aktywnego</a>, kontrolowanego przez białka transportowe. Transport jądrowy jest kluczowy dla funkcjonowania komórki, ponieważ przemieszczanie cząstek poprzez błonę jądrową wymagane jest zarówno przy zarządzaniu ekspresją genów oraz utrzymywaniu chromosomów.", "Kevan": "<p>Kevan to imię, wariant nazwiska Kevin (Caoimheán lub Caomhán, irlandzka diminutiwna forma Caoimhín; również anglicizowana Cavan). Zmiana kobieca to Caoimhe (angliczowana jako Keeva lub Kweeva).</p>", "Ksaver": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ksawer</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ksawera</b>.</p><b>Ksawera</b>, <b>Ksaweryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">Ksawery</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Franciszka_Ksawera\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszka Ksawera</a> Cabrini.", "Kym": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Khen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Chen</b>.</p><p>Białe gęsi (lat. Chen) - gatunek ptaków pływających wodą z gatunku gęsi, wcześniej był w rankingu rodu.</p>", "Keon": "<p>Keon to męskie imię. W zależności od jego pisowni może być pochodzenia perskiego (کیان) lub gaelickiego irlandzkiego (Cian).</p>", "Kyogo": "<p>Kyōgo, Kyogo lub Kyougo (pisanie: 亨 ⁇ lub 恭吾) to męskie japońskie imię. Znanymi ludźmi z nazwiska są: Kyogo Furuhashi (古橋 亨 ⁇; urodzony 1995), japoński piłkarz.</p>", "Karan Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karan</b>.</p><p>Koran: Koran jest znakem dyakrytycznym tajskiego pisma. Koran - stanowisko w Siłach Achemeniódów.</p>", "Kylan": "<p>Kylan to unisex. Znani ludzie z nazwiskiem to: Kylan Boswell (ur. 2005), amerykański piłkarz koszykówki Kylan Darnell, amerykańska osobowość internetowa i Miss Ohio Teen USA 2022 Kylan Hamdaoui (ur. 1994), francuski gracz rugby.</p>", "Kair": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kaira</b>.</p><p>Kaira jest pająkiem z rodziny Araneidae.</p>", "Kevin Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kiprian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ciprian</b>.</p><p>Ciprian to imię lub nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Koral": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Coral</b>.</p><p>Gala Coral Group Ltd - brytyjski operator bukmacherskich biur, bingo i kasyna, należący do prywatnych domów akcji ⁇ Candover Investments ⁇ , ⁇ Cinven ⁇ i ⁇ Permira ⁇ . W październiku 2005 roku połączyła się z Coral Eurobet za 2,18 mld funtów.</p>", "Khoi Nguyen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khoi</b>.</p><p>Khoikhoi (\"ludzi\" lub \"prawdziwi ludzie\") lub Khoi, pisane jako Khoekhoe w standardowym Khoekhoe/Nama literacku, to grupa ludności rodzinną w południowo-zachodniej Afryce. W przeciwieństwie do sąsiednich Sanów, którzy polowali i zbierali ryby, Khoikhoi mieli tradycję hodowli bydła.</p>", "Korai": "<b>Kora</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;κόρη <i>kore</i> – dziewczyna; <a href=\"https://pl.wikipedia.org/wiki/Liczba_mnoga\" target=\"_blank\" rel=\"noopener noreferrer\">lm.</a> <i>korai</i>) – w sztuce Grecji <a href=\"https://pl.wikipedia.org/wiki/Okres_archaiczny_(staro%C5%BCytna_Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">okresu archaicznego</a> najstarszy typ greckiego posągu kobiecego, wyobrażający stojącą dziewczynę w długich szatach, często z owocem, kwiatem lub ptakiem w ręku; żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Kuros\" target=\"_blank\" rel=\"noopener noreferrer\">kurosa</a>.", "Khristian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Christian</b>.</p><p>Christian (niem. Christian, umysł.</p>", "Kavinda": "<p>Kavinda to syngalski nazwa, która może odnosić się do następujących wybitnych osób: Nazwa Kavinda Jayawardena, sri Lankański polityk Kavinda de Thissera, Sri Lankański kryker Surname Ashen Kavinda, Sri Lankan kryker Nuwan Kavinda, kryker Shehan Kavinda, sri Lankan entrepreneur</p>", "Kleo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cleo</b>.</p><p>Kleo, prawdziwe imię Joanna Kristina Klepko (pol. Joanna Krystyna Klepko; rodzaj.</p>", "Kornelia": "<b>Kornelia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Kornel</a>, <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusz</a> i <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Korneli</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliuszy</a>. Imię to było znane już w starożytności. W Polsce nadawane co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1770\" target=\"_blank\" rel=\"noopener noreferrer\">1770</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Kornelia w 2017 r. zajmowała 25. miejsce w grupie imion żeńskich.", "Kalasanty": "<b>Kalasanty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie powstałe od nazwy miejscowości (Calasanza) w Hiszpanii. Pierwotnie był to jedynie drugi człon nazywający świętego z przełomu XVI i XVII wieku, <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Kalasancjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Józefa Kalasantego</a> (<i>José de Calasanza</i>), założyciela zakonu pijarów.", "Kyran": "<p>Ciarán (irlandzkie pisowni) lub Ciaran (szkocka gagelicka pisowni) jest tradycyjnie męskie nazwisko pochodzenia irlandzkiego i szkockiego. Oznacza to \"małe ciemne\" lub \"małe mrocznie włosne\", wytwarzane poprzez dodanie drobnego sufiksu do ciar (\"czarny\", \"ciemny\").</p>", "Kausar": "<p>Kausar lub Kawthar (arabsko: كَوْثَر) to arabska muzułmańska nazwa zarówno dla mężczyzn, jak i kobiet, co oznacza \"rzeka w raju ozdobioną perlami o zapach słodkiego muszka\", \"biały niż mleko, słodszy niż miód\", \"brąże i złoty banki\", \"obfity\", \"bogaty\", \"obzbrojny\" lub \"obfitoczny\". Nazwa ta jest albo odniesieniem do surah Al-Kawthar lub Hauzu'l-Kausar, świętego jeziora zwanego \"zbiorzem obfitości\" w Raju, wspomnianym w Koranie.</p>", "Kira": "<b>Cyra</b>, <i>Kira</i> – żeński odpowiednik męskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Cyrus\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrus</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Marana_i_Cyra\" target=\"_blank\" rel=\"noopener noreferrer\">św. Cyra</a> z V wieku.", "Kersten": "<p>Kersten to niemieckie imię i nazwisko holenderskie/niższe niemieckiego nazwiska.</p>", "Kanishka": "<p>Cesarz Kanishka (Francuz: कनिष्क, Hiszpański: Κανη ⁇ κι, Święty Han: 迦 ⁇ 色 ⁇) był królem Kyu Sōng w Azji Środkowej, był Kyu Sóng z rodu Nguyệt Chi. Armią Han-Viet Kanishka są Święty Król, Święty Książę, Święta Król, Dżan Książą, Piesny Król, Piesne Król lub Święty Sztel.</p>", "Kevin De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kishor Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kishor</b>.</p><p>Kishor (hindi: किशोर}) to nazwa używana głównie w Indiach i Nepalu. Pochodzi z sanskryckiego słowa kishora, co oznacza \"chłopa\" lub \"dziecko\".</p>", "Korey": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Corey</b>.</p><p>Corey to męskie imię i nazwisko. Jest to męska wersja imienia Cora, która ma pochodzenie greckie i jest nazwiskiem dziewczęcym bogini Persyfonie.</p>", "Kalmir": "<b>Kanimir</b>, <b>Kanimier</b>, <b>Kajmir</b>, <b>Kalmir</b> — <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów: <i>Kani-</i> w różnych wersjach brzmieniowych (\"gościć, zapraszać\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"ten, u kogo gości pokój\".", "Kazuyuki": "<b>Kazuyuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずゆき, カズユキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Kyllian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Killian</b>.</p><p>Killian lub Kilian, jako nazwisko, jest angielskościową wersją irlandzkiego imienia Cillian. Nazwa Cillian nosiła kilku wczesnych świętych irlandzkich, w tym misjonarzy do Artois (Francja) i Frankonia (Niemcy) oraz autorka życia św. Brigid.</p>", "Kristoph": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristof</b>.</p><p>Kristof, Krištof lub Kristóf mogą być zarówno nazwiskiem, jak i nazwiskiem. Do wybitnych osób z tym nazwiskiem należą:</p>", "Kiwa": "<b>Kiwaidae</b> – <a href=\"https://pl.wikipedia.org/wiki/Rodzina_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzina</a> <a href=\"https://pl.wikipedia.org/wiki/Skorupiaki\" target=\"_blank\" rel=\"noopener noreferrer\">skorupiaków</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Dziesi%C4%99cionogi\" target=\"_blank\" rel=\"noopener noreferrer\">dziesięcionogów</a> (Decapoda). Występują na dużych głębokościach, w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Komin_hydrotermalny\" target=\"_blank\" rel=\"noopener noreferrer\">kominów hydrotermalnych</a>. Rodzina obejmuje <a href=\"https://pl.wikipedia.org/wiki/Takson_monotypowy\" target=\"_blank\" rel=\"noopener noreferrer\">jeden</a> rodzaj – <i>Kiwa</i>. Należą do niego cztery gatunki, z których dwa zostały formalnie opisane: <a href=\"https://pl.wikipedia.org/wiki/Gatunek_typowy\" target=\"_blank\" rel=\"noopener noreferrer\">typowy</a> <i><a href=\"https://pl.wikipedia.org/wiki/Kiwa_hirsuta\" target=\"_blank\" rel=\"noopener noreferrer\">Kiwa hirsuta</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Kiwa_puravida\" target=\"_blank\" rel=\"noopener noreferrer\">Kiwa puravida</a></i>. Rodzina została nazwana w 2005 roku przez Enrique Macphersona i współpracowników jako monotypowa rodzina dla <i>K. hirsuta</i>. <i>K. puravida</i> opisano w 2011 roku. Trzeci gatunek żyje w pobliżu kominów hydrotermalnych na East Scotia Ridge na <a href=\"https://pl.wikipedia.org/wiki/Ocean_Po%C5%82udniowy\" target=\"_blank\" rel=\"noopener noreferrer\">Oceanie Południowym</a>, a czwarty – na Southwest Indian Ridge.", "Keitaro": "<p>Keitarō to japońskie imię. Wiele osób jest w stanie się zmienić.</p>", "Karan Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karan</b>.</p><p>Koran: Koran jest znakem dyakrytycznym tajskiego pisma. Koran - stanowisko w Siłach Achemeniódów.</p>", "Kamila": "<b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Keny": "<p>Kenneth to imię pochodzące z języka gaelickiego. Nazwa jest angliczowaną formą dwóch zupełnie różnych gaelijskich nazw: Cainnech i Cináed.</p>", "Karolina": "<b>Karolina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>. Innym żeńskim odpowiednikiem imienia Karol jest <a href=\"https://pl.wikipedia.org/wiki/Karola\" target=\"_blank\" rel=\"noopener noreferrer\">Karola</a>. Imię Karolina jest pochodzenia starogermańskiego, od słowa charal, carl.", "Krassimir": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krasimir</b>.</p><p>Krasimir (bułgarski: Красимир) jest powszechną nazwą męską w Bułgarii. Pochodzi od słów krasi \"piękno, ozdoba\" i mir \"pokój\" lub \"świat\".</p>", "Keigo": "<b>Keigo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;敬語) – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">japoński</a> język zwrotów grzecznościowych. W językach europejskich istnieje mniej poziomów formalności, zwykle jeden jak w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a> lub też dwa jak w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a> czy <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a>. Mają one też mniejszy wpływ na gramatykę – dotyczą głównie zdań dotyczących współrozmówcy, nie zaś siebie samego czy przedmiotów i osób trzecich.", "Kirillo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kirill</b>.</p><p>Kirill (rosyjski: Кирилл) rosyjskie imię męskie, pochodzące od greckiego imienia Κύριλλος (Kyrillos), które z kolei pochodzą z greckiego κύριος (kyrios) \"pan\". Istnieje wiele wariantów nazwy: Cyryl, Cyrill, Kyrill, Kiryl, Kirillos, Kyryl, Kiril, Kyrylo, Kiro.</p>", "Kyuri": "<p>Gyuri jest nazwiskiem używanym zarówno w kulturze węgierskiej, jak i koreańskiej.</p>", "Kamal Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kamal</b>.</p><p>Kamal (Martin Engels, Martin Engels, urodzony 18 kwietnia 1956 roku w Bilefeld, Niemcy) - niemiecki muzykiem i reżyserem dźwięku. Studiował muzykę w Düsseldorf, później pracował w Bielefeld.</p>", "Karani̇": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karan</b>.</p><p>Koran: Koran jest znakem dyakrytycznym tajskiego pisma. Koran - stanowisko w Siłach Achemeniódów.</p>", "Katalin": "<p>Ekaterina Węgierska (Katalina lub Katarzyna, w. Katalin, podłoga.</p>", "Kaarlo": "<p>Kaarlo to fińskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Khrystyna": "<p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Kodi": "Pozwala uruchamiać aplikacje oficjalne i tworzone przez konsumentów tzw. homebrew oraz oglądać filmy, słuchać muzyki i przeglądać cyfrowe zdjęcia bezpośrednio z wbudowanego w <a href=\"https://pl.wikipedia.org/wiki/Xbox\" target=\"_blank\" rel=\"noopener noreferrer\">Xboksa</a> <a href=\"https://pl.wikipedia.org/wiki/Dysk_twardy\" target=\"_blank\" rel=\"noopener noreferrer\">dysku twardego</a>, czytnika <a href=\"https://pl.wikipedia.org/wiki/DVD\" target=\"_blank\" rel=\"noopener noreferrer\">DVD</a>, lokalnej sieci komputerowej, <a href=\"https://pl.wikipedia.org/wiki/Internet\" target=\"_blank\" rel=\"noopener noreferrer\">Internetu</a> lub z nośnika danych podłączonego przez przejściówkę pod port USB (np. z pendrive’a, jeżeli jest kompatybilny). Po podłączeniu konsoli do Internetu dodatkowo można sprawdzić pogodę, posłuchać radia internetowego, pograć w gry online w systemie xLink lub pobrać informację na temat oglądanego filmu. Dzięki instalacji dodatkowych <a href=\"https://pl.wikipedia.org/wiki/Wtyczka\" target=\"_blank\" rel=\"noopener noreferrer\">wtyczek</a> (skryptów) do programu można dodać dodatkowe funkcje, na przykład skrzynkę <a href=\"https://pl.wikipedia.org/wiki/Poczta_elektroniczna\" target=\"_blank\" rel=\"noopener noreferrer\">e-mail</a>, program TV, <a href=\"https://pl.wikipedia.org/wiki/Telewizja_internetowa\" target=\"_blank\" rel=\"noopener noreferrer\">telewizje internetową</a>, <a href=\"https://pl.wikipedia.org/wiki/Przegl%C4%85darka_internetowa\" target=\"_blank\" rel=\"noopener noreferrer\">przeglądarkę WWW</a> i wiele innych.", "Keyi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Key</b>.</p><b>Key</b> – japońskie studio tworzące <a href=\"https://pl.wikipedia.org/wiki/Powie%C5%9B%C4%87_wizualna\" target=\"_blank\" rel=\"noopener noreferrer\">powieści wizualne</a>, będące formalnie marką wydawcy gier komputerowych <a href=\"https://pl.wikipedia.org/wiki/Visual_Arts\" target=\"_blank\" rel=\"noopener noreferrer\">Visual Arts</a>. Jest jednym z głównych przedstawicieli nurtu <i>nakige</i>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;泣きゲ&#59; „gry wywołujące łzy”). Pierwszym tytułem studia była wydana w 1999 roku <a href=\"https://pl.wikipedia.org/wiki/Eroge\" target=\"_blank\" rel=\"noopener noreferrer\">gra dla dorosłych</a> <i><a href=\"https://pl.wikipedia.org/wiki/Kanon_(gra_komputerowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Kanon</a></i>. W 2004 roku wydana została pierwsza produkcja studia przeznaczona dla wszystkich grup wiekowych – <i><a href=\"https://pl.wikipedia.org/wiki/Clannad_(gra_komputerowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Clannad</a></i>. Key współpracowało ze studiem animacyjnym <a href=\"https://pl.wikipedia.org/wiki/P.A._Works\" target=\"_blank\" rel=\"noopener noreferrer\">P.A. Works</a> oraz firmą <a href=\"https://pl.wikipedia.org/wiki/Aniplex\" target=\"_blank\" rel=\"noopener noreferrer\">Aniplex</a> przy produkcji seriali <a href=\"https://pl.wikipedia.org/wiki/Anime\" target=\"_blank\" rel=\"noopener noreferrer\">anime</a> <i><a href=\"https://pl.wikipedia.org/wiki/Angel_Beats!\" target=\"_blank\" rel=\"noopener noreferrer\">Angel Beats!</a></i> (2010), <i><a href=\"https://pl.wikipedia.org/wiki/Charlotte_(anime)\" target=\"_blank\" rel=\"noopener noreferrer\">Charlotte</a></i> (2015) i <i><a href=\"https://pl.wikipedia.org/wiki/Kami-sama_ni_natta_hi\" target=\"_blank\" rel=\"noopener noreferrer\">Kami-sama ni natta hi</a></i> (2020).", "Kevin Julian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kameel": "<p>Kamil to imię używane w wielu językach. Kamil to polskie, czeskie i słowackie imię, równoważne włoskiemu Camillo, hiszpańsko-portugalskiemu Camilo i francuskiemu Camille.</p>", "Kaja": "<b>Gaja</b>, <b>Kaja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/Gaja_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">postaci z mitologii greckiej</a>, Ziemi-Matki (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Γαῖα – „Ziemia”), lub stanowiące żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a> (<i>Gaius</i>), należącego do nielicznej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marek</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>). Według różnych źródeł Gajusz ma bądź to niewyjaśnione pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckie</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruskie</a>, bądź to uznawane jest za oznaczające „cieszący (rodziców)”, por. <i>gaudeo</i> – „cieszę się” (zob. <a href=\"https://pl.wikipedia.org/wiki/Gaudenty_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gaudenty</a>). Gaja oznaczałaby zatem „ciesząca rodziców”.", "Keiichiro": "<p>Keiichirō, Keiichiro lub Keiichirou (pisanie: 敬一郎, ⁇ 一郎, Guyi一郎, ⁇ 一郎 , 啓一郎,恵一郎 lub 慶一郎) to męskie japońskie imię. Znanymi osobami z nazwiska są: Keiichirō Akagi (赤木 圭一郎; 1939-1961), japoński aktor Keiichiro Asao (浅尾 慶一郎; ur. 1964), japoński polityk Keiichiro Fukabori (深 ⁇ 圭一 Taro; ur. 1968), japończyk golfowiec Keiichirô Gotō (後藤 敬一郎; 1918-2004), japoński fotograf Keiichiro Hirano (平野 啓一郎; Ur. 1975), japowski pisarz Keiichiro...</p>", "Kristiaan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristian</b>.</p><b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Kellan": "<p>Kellan, czyli Kellen, to męskie imię. Inne warianty Kellen lub Kellan obejmują Kaelan, Kallen, Keelan, Keilan, Keillan, Kelan, Kelden, Kelle, Kellyn i Kellin.</p>", "Klimentiy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Klimenti</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kliment</b>.</p><p>Kliment (cyrylicki: Климент) to męskie imię, słowiańska forma późnolatynskiej nazwy Klement. Klim jest formą mniejszą.</p>", "Karno": "<b>Karno</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>Carneau</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rasy_go%C5%82%C4%99bia\" target=\"_blank\" rel=\"noopener noreferrer\">rasa gołębia</a> należąca do grupy uformowanych (<a href=\"https://pl.wikipedia.org/wiki/Rasy_go%C5%82%C4%99bia#Grupa_I_–_uformowane\" target=\"_blank\" rel=\"noopener noreferrer\">grupa I</a>), pochodzących (jak wszystkie inne) od <a href=\"https://pl.wikipedia.org/wiki/Domestykacja_zwierz%C4%85t\" target=\"_blank\" rel=\"noopener noreferrer\">udomowionego</a> <a href=\"https://pl.wikipedia.org/wiki/Go%C5%82%C4%85b_skalny\" target=\"_blank\" rel=\"noopener noreferrer\">gołębia skalnego</a>. Rasa wywodzi się z północnej <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a> i południowej <a href=\"https://pl.wikipedia.org/wiki/Belgia\" target=\"_blank\" rel=\"noopener noreferrer\">Belgii</a>, gdzie została <a href=\"https://pl.wikipedia.org/wiki/Hodowla\" target=\"_blank\" rel=\"noopener noreferrer\">wyhodowana</a> około IX wieku, a opisana w 1891 roku. Istnieją dwa typy rasy: europejski oraz amerykański. Karno jest gołębiem użytkowym, nierzadko wystawowym, a amerykański typ rasy jest przeznaczony do konsumpcji (z uwagi na dużą wagę i odporność reprodukcja jest wydajna).", "Kahtan": "<p>Qahtan (lub Kahtan), Qahtani (lub Kahtani) i Al-Qahtani (albo Al-Kahtani) to arabskie nazwiska. Mogą odnosić się do: Qahtan (plemię), arabskiej konfederacji plemiennej w Arabii Saudyjskiej. Qahtanite lub Qahtani, Arabowie pochodzący z południowego regionu Półwyspu Arabii, zwłaszcza z Jemenu</p>", "Kevin Miguel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kodie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kodi</b>.</p>Pozwala uruchamiać aplikacje oficjalne i tworzone przez konsumentów tzw. homebrew oraz oglądać filmy, słuchać muzyki i przeglądać cyfrowe zdjęcia bezpośrednio z wbudowanego w <a href=\"https://pl.wikipedia.org/wiki/Xbox\" target=\"_blank\" rel=\"noopener noreferrer\">Xboksa</a> <a href=\"https://pl.wikipedia.org/wiki/Dysk_twardy\" target=\"_blank\" rel=\"noopener noreferrer\">dysku twardego</a>, czytnika <a href=\"https://pl.wikipedia.org/wiki/DVD\" target=\"_blank\" rel=\"noopener noreferrer\">DVD</a>, lokalnej sieci komputerowej, <a href=\"https://pl.wikipedia.org/wiki/Internet\" target=\"_blank\" rel=\"noopener noreferrer\">Internetu</a> lub z nośnika danych podłączonego przez przejściówkę pod port USB (np. z pendrive’a, jeżeli jest kompatybilny). Po podłączeniu konsoli do Internetu dodatkowo można sprawdzić pogodę, posłuchać radia internetowego, pograć w gry online w systemie xLink lub pobrać informację na temat oglądanego filmu. Dzięki instalacji dodatkowych <a href=\"https://pl.wikipedia.org/wiki/Wtyczka\" target=\"_blank\" rel=\"noopener noreferrer\">wtyczek</a> (skryptów) do programu można dodać dodatkowe funkcje, na przykład skrzynkę <a href=\"https://pl.wikipedia.org/wiki/Poczta_elektroniczna\" target=\"_blank\" rel=\"noopener noreferrer\">e-mail</a>, program TV, <a href=\"https://pl.wikipedia.org/wiki/Telewizja_internetowa\" target=\"_blank\" rel=\"noopener noreferrer\">telewizje internetową</a>, <a href=\"https://pl.wikipedia.org/wiki/Przegl%C4%85darka_internetowa\" target=\"_blank\" rel=\"noopener noreferrer\">przeglądarkę WWW</a> i wiele innych.", "Kiho": "<p>Kiho może odnosić się do: Kiho-tumu, najwyższego boga w mitologii archipelagu Tuamotu Kihō, Mie, miasto w Japonii W Legendy Pięciu Pierścieni grę zbieralnych kart, karty kiho są grane jako akcje, ale generują efekty zaklęcia. Kiho prawie zawsze wymaga od shugenja lub mnich (czasami konkretnie jeden lub drugi) skłaniać się jako część kosztów gry w karty W Legend of the Five Rings Role-Playing Game, kiho są złożone walki...</p>", "Keni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Keny</b>.</p><p>Kenneth to imię pochodzące z języka gaelickiego. Nazwa jest angliczowaną formą dwóch zupełnie różnych gaelijskich nazw: Cainnech i Cináed.</p>", "Karter": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Carter</b>.</p><p>Carter może odnosić się do: Jimmy Carter Rosalynn Carter Nick Carter</p>", "Kalid": "<p>Khalid (varianty obejmują Khaled i Kalid; arabski: خالد) to popularne arabskie imię męskie oznaczające \"wieczne, wieczne, nieśmiertelne\". - Tak. - Jest też nazwiskiem.</p>", "Kevin Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kayl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kayle</b>.</p><p>Kayle to nazwisko, jiddish feminine, a męskie. Jako jydska nazwa, Kayle (קילא KAY-leh) jest znana od XIII wieku jako wariant Keyle, co oznacza \"wesoły\"; jest spokrewniona z nowoczesnym niemieckim słowem geil.</p>", "Karthik Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karthik</b>.</p><p>Karthik lub Kartik może odnosić się do:</p>", "Keylan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ceylan</b>.</p><p>Ceylan (tur. Ceylan) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Kyrie": "Forma wołania błagalnego występująca w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> (Ps. 40, 5; 40, 11, Iz. 33,2, a w zmienionej postaci <i>eleison me kyrie</i> - Ps. 7, 3; 10, 14; 31, 10; 56, 2; 86, 3 – numeracja według <a href=\"https://pl.wikipedia.org/wiki/Septuaginta\" target=\"_blank\" rel=\"noopener noreferrer\">Septuaginty</a>), która w tej postaci została przejęta do wszystkich liturgii Kościoła katolickiego.", "K": "<b>K</b> (<a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>k</b>) (<i>ka</i>) – jedenasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i czternasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. W języku polskim oznacza <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę zwartą miękkopodniebienną bezdźwięczną</a>. Pochodzi od litery <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu fenickiego</a> <a href=\"https://pl.wikipedia.org/wiki/Kaf\" target=\"_blank\" rel=\"noopener noreferrer\">kaph</a>, za pośrednictwem litery alfabetu greckiego <a href=\"https://pl.wikipedia.org/wiki/Kappa_(litera)\" target=\"_blank\" rel=\"noopener noreferrer\">kappa</a> i alfabetu etruskiego.", "Kazimierz Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kazimierz</b>.</p><b>Kazimierz</b> – współcześnie przyjęta forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> męskiego <b>Kazimir</b> (z odmiankami <b>Kazimirz</b>, <b>Kazimiar</b>, <b>Kazimier</b>, <b>Kaźmir</b>, <b>Kaźmisz</b>), składającego się z członów: <i>Kazi-</i> („niszcz, psuj, niwecz” od <i>kazić</i> „niszczyć, psuć”, porównaj współczesne <i>od-kazić</i> „od-psuć”) i <i>-mir</i> („pokój, spokój”). Oznacza „ten, który (niech) niszczy pokój” – niszcz pokój! = kaź mir! (staropolskie kazi mir!).", "Khorshed": "<p>Khorshīd lub Khorshēd (perskie: خورشید [xoɾˈʃid], co oznacza Słońce lub \"Słońce promieniowane\"), również pisowniane jako Khurshed i Khurshid, jest perskim nazwiskiem. W dzisiejszych czasach, jak również w historycznym Iranie, Turcji i Azerbejdżanie, ale także w irackim Kurdystanie, Egipcie, Azji Środkowej i Azji Południowej, jest to głównie imię dla chłopców.</p>", "Kyohei": "<p>Kyōhei, Kyohei lub Kyouhei (pisanie: 恭平, 京平, 喬平, 亨平 lub 恭兵) to męskie japońskie imię. Znanymi osobami z tej nazwy są: Kyohei Inukai (ur. 1886) (1886-1954), amerykański artysta Kyōhei Katō (加藤 恭平; 1909-1983), japoński fotograf Kyohei Inusai (ur. 1913) (1913-1985), amerykańska artysta Kyohei Fujita (藤田 喬平; 1921-2004), japoński artysta Kyohei Tsutsumi (筒美 京平; 1940-2020), japoński kompozytor i producent płyt, Kyōhei Shibata (柴田 恭兵;...</p>", "Kumarasiri": "<p>Kumarasiri to imię i nazwisko. Wśród znanych osób z nazwiskiem są: Kumarasiri Rathnayake (ur. 1967), Sri Lankanki nauczyciel i polityk Ananda Kumarasiri (ur. 1954), Sri Lanka polityk K.</p>", "Kristiian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristian</b>.</p><b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Kipkoech": "<p>Kipkoech to imię pochodzenia kenijskiego, które oznacza \" (męski) urodzony rano\". Synów / córki Kipkoech byłoby następnie nazwać \"Koech\" jako ich nazwisko i dane ich indywidualne nazwiska; osiągnięte po prostu usunięcie prefiksu \"kip\" jak dzieje się z większością innych podobnych nazw, które zaczynają się od \"Kip\" z tej konkretnej społeczności lub ktokolwiek rozumie znaczenie i sposoby odziedziczenia nazwy.</p>", "Keelan": "<p>Caolán to męskie imię pochodzące z Irlandii, pochodzące od irskiego słowa \"caol-\" (\"slanki, wąski  piękny\").[and] Nazwa ma wiele angliczacji, w tym \"Kelan\", \"Keelan\" i \"Kealan\".</p>", "Karolos": "<p>Karolos lub Károlos to greckie imię męskie, które jest alternatywną formą Karola. Do wybitnych osób, o których mowa w tej nazwie, należą:</p>", "Kunihiko": "<b>Kunihiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;くにひこ, クニヒコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Kibria": "<p>Kibria (arabski: كبرياء, transliteracje różnią się) jest męskim imieniem pochodzenia arabskiego oznaczającym \"pady\". Wśród znanych osób z nazwiskiem są: Mohammad Kibria (1929-2011), artysta Shah Abu Muhammad Shamsul Kibria (1931-2005), były minister finansów Bangladeszu Amatul Kibria Keya Chowdhury, kobieta polityka</p>", "Krystyian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristiian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristian</b>.</p><b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Kyosuke": "<p>Kyōsuke, Kyosuke lub Kyousuke to męskie japońskie imię. Znanymi osobami z nazwiska są: Eto Kyōsuke (江渡 恭助; 1881-1917), japoński oficer marynarki wojennej Kyosuke Goto (後藤 京介; ur. 1992), japoński piłkarz Kyousuke Hamao (浜尾 京介, ur. 1991), japończyk aktor, piosenkarz i model Kyosuke Himuro (氷室 京介 , ur. 1960), japońskiego piosenkarza Kyosuke Horie (⁇ 江 恭佑; ur. 1990), japowski gracz rugby Ryōsu Ikeeda (池田 恭祐, ur. 1992).</p>", "Karunarathna": "<p>Karunaratne lub Karunarathna (Sinhala: කරුණාරත්න, romanized: Karuṇāratna) to sinhalaskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Khristiian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khristian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Christian</b>.</p><p>Christian (niem. Christian, umysł.</p>", "Ki Ho": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ki</b>.</p><p>KI (drwa litera - główna ⁇ i ⁇) lub Ki może oznaczać: Kibi- (skr. Ki lub Ki) - podwójna przymowa, oznaczająca 210 (podobna do dziesięcioletniej przymowy ⁇ kil- ⁇).</p>", "Kevin Mauricio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kato": "<p>Thomas Kato Vitrup (d. Thomas Kato Vittrup; rod.</p>", "Khôi Nguyên": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khoi</b>.</p><p>Khoikhoi (\"ludzi\" lub \"prawdziwi ludzie\") lub Khoi, pisane jako Khoekhoe w standardowym Khoekhoe/Nama literacku, to grupa ludności rodzinną w południowo-zachodniej Afryce. W przeciwieństwie do sąsiednich Sanów, którzy polowali i zbierali ryby, Khoikhoi mieli tradycję hodowli bydła.</p>", "Karl-Friedrich": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karl</b>.</p><p>Karl Kurzwazje (niem. Karl Fr.</p>", "Krystian Junior": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystian</b>.</p><b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Krystopher": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristopher</b>.</p><p>Christopher to angielska wersja europejskiej nazwy pochodząca z greckiego imienia Χριστόφορος (Christophoros lub Christoforos). Jego części są Χριστός (Christós), \"Chrys\" lub \"Poświęty\" oraz φέρειν (phérein), \"nieść\"; stąd \"nieść Chrystusa\".</p>", "Kayvan": "<p>Kayvan (zwane również Keyvan, Kayvon, Kaivon, Keivan, Kaywan, Kavon, Kevan lub Kaevon; perskie: کیوان) jest perskim męskim imieniem planety Saturn. Jest związany z słowem Saturn w kilku starożytnych językach, w tym Kaimanu w sumeryjskim, Kajamānu w akadyjskim, Kewwān w syryjskim, Kiwan w klasycznym mandaiku i \"Kewan\" (kywʾn') w środkowym perskim.</p>", "Kanji": "<b>Kanji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;漢字&#32;<i>kanji</i>&#59; „znaki <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Han\" target=\"_blank\" rel=\"noopener noreferrer\">Hanów</a>”) – <a href=\"https://pl.wikipedia.org/wiki/Pismo_logograficzne\" target=\"_blank\" rel=\"noopener noreferrer\">znaki logograficzne</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chińskiego</a>, które wraz z <a href=\"https://pl.wikipedia.org/wiki/Sylabariusz\" target=\"_blank\" rel=\"noopener noreferrer\">sylabariuszami</a> <a href=\"https://pl.wikipedia.org/wiki/Hiragana\" target=\"_blank\" rel=\"noopener noreferrer\">hiragana</a> (ひらがな, 平仮名), <a href=\"https://pl.wikipedia.org/wiki/Katakana\" target=\"_blank\" rel=\"noopener noreferrer\">katakana</a> (カタカナ, 片仮名), <a href=\"https://pl.wikipedia.org/wiki/Cyfry_arabskie\" target=\"_blank\" rel=\"noopener noreferrer\">cyframi arabskimi</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetem łacińskim</a> stanowią element <a href=\"https://pl.wikipedia.org/wiki/Pismo_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">pisma japońskiego</a>.", "Khalid Mahmood": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khalid</b>.</p><p>Khalid Donnel Robinson - amerykański piosenkarz, laureat i nominac wielu nagród muzycznych.</p>", "Keshaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Keshav</b>.</p><p>Keshav to małe imię z Azji Południowej, które jest nowoczesną formą imienia Keshava, jedno z wielu imion Pana Kryszny i Pana Wisnu. Wśród znanych osób z nazwiskiem są: Keshav Kashmiri (1410-1490), indyjski filozof Keshav Bansal (ur. 1991), indyjski przedsiębiorca Keshav Vaman Bhole (1896-1967), indyjskie kompozytor muzyczny Keshav Kumar Budhathoki, nepalski polityk Keshav Dutt (1925-2021), indyjska hokejistka Keshav Ginde (ur. 1942),...</p>", "Kenneth John": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kenneth</b>.</p><p>Kenneth może odnosić się do: Kenneth Arrow Kenneth Pitzer Kenneth Pitzer</p>", "Kelvin Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kelvin</b>.</p><p>Kelwin (ruckoznawstwo: K; międzynarodowe: K) - jednostka temperatury termodynazyjnej w Międzynarodowym Systemie Jednostek (SI), jedna z siedmiu podstawowych jednostek SI. Zaproponowana w 1848 roku.</p>", "Karl Hans": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karl</b>.</p><p>Karl Kurzwazje (niem. Karl Fr.</p>", "Krzyś": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krzysztof</b>.</p><b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Krzysztof Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krzysztof</b>.</p><b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Kim Chung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Kayle": "<p>Kayle to nazwisko, jiddish feminine, a męskie. Jako jydska nazwa, Kayle (קילא KAY-leh) jest znana od XIII wieku jako wariant Keyle, co oznacza \"wesoły\"; jest spokrewniona z nowoczesnym niemieckim słowem geil.</p>", "Karmel": "Jest głównym składnikiem niektórych rodzajów <a href=\"https://pl.wikipedia.org/wiki/Cukierek\" target=\"_blank\" rel=\"noopener noreferrer\">cukierków</a>, <a href=\"https://pl.wikipedia.org/wiki/Barwniki_spo%C5%BCywcze\" target=\"_blank\" rel=\"noopener noreferrer\">barwnikiem</a> napojów typu <a href=\"https://pl.wikipedia.org/wiki/Cola\" target=\"_blank\" rel=\"noopener noreferrer\">cola</a>, ciemnego <a href=\"https://pl.wikipedia.org/wiki/Pieczywo\" target=\"_blank\" rel=\"noopener noreferrer\">pieczywa</a>, <a href=\"https://pl.wikipedia.org/wiki/Czekolada\" target=\"_blank\" rel=\"noopener noreferrer\">czekolad</a>, <a href=\"https://pl.wikipedia.org/wiki/Lody\" target=\"_blank\" rel=\"noopener noreferrer\">lodów</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCem\" target=\"_blank\" rel=\"noopener noreferrer\">dżemów</a> i <a href=\"https://pl.wikipedia.org/wiki/Jogurt\" target=\"_blank\" rel=\"noopener noreferrer\">jogurtów</a>. Dodatek karmelu do żywności jest oznaczany przez kod E150 i literę wyróżniającą typ karmelu.", "Karol Emanuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karol</b>.</p><b>Karol</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankijskiego</a> oznaczające człowieka mężnego lub wojownika. Staroskandynawskie znaczenie – „człowiek, mąż”. Imię jest również rozpowszechnione w krajach latynoskich.", "Kamillus": "<b>Marek Furiusz Kamillus</b>, <i>Marcus Furius Camillus</i> (ur. około <a href=\"https://pl.wikipedia.org/wiki/446_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">446 p.n.e.</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/364_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">364 p.n.e.</a>) – wódz i reformator armii <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiej</a>, wielokrotny <a href=\"https://pl.wikipedia.org/wiki/Konsul_rzymski#Republika\" target=\"_blank\" rel=\"noopener noreferrer\">trybun konsularny</a> i <a href=\"https://pl.wikipedia.org/wiki/Dyktator_(staro%C5%BCytny_Rzym)\" target=\"_blank\" rel=\"noopener noreferrer\">dyktator</a>.", "Kirpa": "<p>Kirpa to nazwa, która jest używana jako nazwisko i imię. Jest to również termin używany w sikhismie.</p>", "Kai-Olaf": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kai</b>.</p><b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Ki Yong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ki</b>.</p><p>KI (drwa litera - główna ⁇ i ⁇) lub Ki może oznaczać: Kibi- (skr. Ki lub Ki) - podwójna przymowa, oznaczająca 210 (podobna do dziesięcioletniej przymowy ⁇ kil- ⁇).</p>", "Khalid S": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khalid</b>.</p><p>Khalid Donnel Robinson - amerykański piosenkarz, laureat i nominac wielu nagród muzycznych.</p>", "Karl Heinz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karl</b>.</p><p>Karl Kurzwazje (niem. Karl Fr.</p>", "Kyrollos": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kirollos</b>.</p><p>Cyryl (zwany również Cyryllem lub Cyryllem) jest męskim imieniem. Pochodzi z greckiego imienia Κύριλλος (Kýrillos), co oznacza \"władca, mistrzowczy\", co z kolei pochodzi z greckiej κυριος (kýrios) \"pan\".</p>", "Ki Sub": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ki</b>.</p><p>KI (drwa litera - główna ⁇ i ⁇) lub Ki może oznaczać: Kibi- (skr. Ki lub Ki) - podwójna przymowa, oznaczająca 210 (podobna do dziesięcioletniej przymowy ⁇ kil- ⁇).</p>", "Kyösti": "<p>Kyösti to fińskie imię męskie i wariant Kustaa. Do wybitnych osób z tym nazwiskiem należą: Kyösti Haataja, dwudziesty wiek fiński polityk Kyösti Kakkonen (ur. 1956), fiński biznesmen i kolekcjoner sztuki Kyösti Kallio (1873-1940), czwarty prezydent Finlandii (1937-1940) Kyösti Karhila (1921-2009), fiński wojenny as II wojny światowej z 321⁄4 zwycięstwami Kyösti karjalainen (ur. 1967), hokejista na lodzie Kyösti Carjula (ur. 1952),...</p>", "Kanth": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kant</b>.</p>Kant otwiera poczet klasycznych <a href=\"https://pl.wikipedia.org/wiki/Idealizm_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">idealistów niemieckich</a>; do kantyzmu odwoływały się też <a href=\"https://pl.wikipedia.org/wiki/Neokantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">neokantyzm</a> (kontynuacja), <a href=\"https://pl.wikipedia.org/wiki/Fenomenologia\" target=\"_blank\" rel=\"noopener noreferrer\">fenomenologia</a> (rewizja) oraz <a href=\"https://pl.wikipedia.org/wiki/Pozytywizm_logiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pozytywizm logiczny</a> (opozycja). Z tego ostatniego wywodzi się bliższy Kantowi <a href=\"https://pl.wikipedia.org/wiki/Popperyzm\" target=\"_blank\" rel=\"noopener noreferrer\">popperyzm</a> znany też jako <a href=\"https://pl.wikipedia.org/wiki/Krytyczny_racjonalizm\" target=\"_blank\" rel=\"noopener noreferrer\">krytyczny racjonalizm</a>. Kantyzm wywarł też wpływ na szkoły i kierunki, z którymi kontrastował; tomizm to <a href=\"https://pl.wikipedia.org/wiki/System_filozoficzny\" target=\"_blank\" rel=\"noopener noreferrer\">system filozoficzny</a> oparty na epistemologii realistycznej i dążący do wiedzy drogą metafizyki, jednak jedną z postaci <a href=\"https://pl.wikipedia.org/wiki/Neotomizm\" target=\"_blank\" rel=\"noopener noreferrer\">neotomizmu</a> jest <a href=\"https://pl.wikipedia.org/wiki/Tomizm_transcendentalizuj%C4%85cy\" target=\"_blank\" rel=\"noopener noreferrer\">tomizm transcendentalizujący</a>.", "Kumaraswamy": "<p>Kumaraswamy lub Coomaraswamy (tamilsky குமாரசுவாமி; kanadyjski: ಕುಮಾರಸ್ವಾಮಿ) to imiona męskie w południowoindyjskiej części. Ze względu na tradycję używania nazwisk patronymowych w południowoindyjskich krajach może to być także nazwisko dla mężczyzn i kobiet.</p>", "Kazimierz Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kazimierz</b>.</p><b>Kazimierz</b> – współcześnie przyjęta forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> męskiego <b>Kazimir</b> (z odmiankami <b>Kazimirz</b>, <b>Kazimiar</b>, <b>Kazimier</b>, <b>Kaźmir</b>, <b>Kaźmisz</b>), składającego się z członów: <i>Kazi-</i> („niszcz, psuj, niwecz” od <i>kazić</i> „niszczyć, psuć”, porównaj współczesne <i>od-kazić</i> „od-psuć”) i <i>-mir</i> („pokój, spokój”). Oznacza „ten, który (niech) niszczy pokój” – niszcz pokój! = kaź mir! (staropolskie kazi mir!).", "Konstantynos": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Konstantinos</b>.</p><p>Konstantinos lub Constantinos (Κωνσταντίνος, Konstantínos) to greckie imię męskie. Konstantinos \"Kosta\" Barbarouses (ur. 1990), nowozelandski piłkarz Konstantinos Chalkias (ur. 1974), grecki piłkarze Konstadinos Gatsioudis (ur. 1973), grecki sportowca Konstantinos Gavras (ur. 1933, znany profesjonalnie jako \"Costa-Gavras\"), grecko-francuski filmowiec Konstantinos Kanaris (1790-1877), grecki admirał i człowiek stanu, były premier...</p>", "Kaname": "<b>Kaname</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かなめ, カナメ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Kostandin": "<p>Kostandin to albanskie imię męskie. Jest to również armenijska męska nazwisko (armeńskie: Կոստանդին), wymawia się Kostandin w wschodnim armenijskim i Gosdantin w zachodnim armeniskim.</p>", "Kássio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cássio</b>.</p><p>Cássio to brazylijskie imię męskie, a Cassio to włoskie nazwisko. Cássio lub Cassio mogą odnosić się do:</p>", "Kevin Dario": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kyoji": "<p>Kyōji (pisanie: 恭司, 恭二, 恭士 lub 喬二, a alternatywnie rzymski jako Kyoji, Kyouji lub Kyozi) jest męskie japońskie imię. Znani ludzie z nazwiska to: Kyoji Horiguchi (⁇ 口 恭司; ur. 1990), japoński artysta walki mieszanej Kyozi Kawasaki (川崎 恭治; 1930-2021), japoński fizyk Kyoji Komachi (小町 恭士; ur. 1946), japończyk dyplomat Kyoji Kutsuna (忽那 喬司; ur., 1997), japowski piłkarz Kyoji Saito (齋藤 恭司, ur. 1944), japońskiego matematyka...</p>", "Kazimierz Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kazimierz</b>.</p><b>Kazimierz</b> – współcześnie przyjęta forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> męskiego <b>Kazimir</b> (z odmiankami <b>Kazimirz</b>, <b>Kazimiar</b>, <b>Kazimier</b>, <b>Kaźmir</b>, <b>Kaźmisz</b>), składającego się z członów: <i>Kazi-</i> („niszcz, psuj, niwecz” od <i>kazić</i> „niszczyć, psuć”, porównaj współczesne <i>od-kazić</i> „od-psuć”) i <i>-mir</i> („pokój, spokój”). Oznacza „ten, który (niech) niszczy pokój” – niszcz pokój! = kaź mir! (staropolskie kazi mir!).", "Krishna Chaitanya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krishna</b>.</p><p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Karl Heinrich": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karl</b>.</p><p>Karl Kurzwazje (niem. Karl Fr.</p>", "Kiryłł": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kiryl</b>.</p><p>Mężczyzna Cyril (lub Kiril lub Кирилл) jest powszechną nazwą w świecie prawosławskich słowiańskich, zwłaszcza w Bułgarii, Macedonii Północnej i Rosji. Jest również dobrze znany w Grecji, ale w różnych formach, takich jak Kyriakos.</p>", "Kristyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristian</b>.</p><b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Konstadinos": "<p>Konstantinos lub Constantinos (Κωνσταντίνος, Konstantínos) to greckie imię męskie. Konstantinos \"Kosta\" Barbarouses (ur. 1990), nowozelandski piłkarz Konstantinos Chalkias (ur. 1974), grecki piłkarze Konstadinos Gatsioudis (ur. 1973), grecki sportowca Konstantinos Gavras (ur. 1933, znany profesjonalnie jako \"Costa-Gavras\"), grecko-francuski filmowiec Konstantinos Kanaris (1790-1877), grecki admirał i człowiek stanu, były premier...</p>", "Kornell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kornel</b>.</p><b>Kornel</b>, <b>Korneliusz</b>, <b>Korneli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Cornelii</i> (<i>Korneliuszy</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusze Cynna</a>). Istnieją różne hipotezy pochodzenia wspomnianej nazwy rodowej; wywodzi się ją bądź to ze słowa <i>cornu</i> („róg”), bądź to <i>cornus</i> („<a href=\"https://pl.wikipedia.org/wiki/Dere%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dereń</a>”), bądź to od nazwy pola <i>Corne</i> w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. W dawnej Polsce zapisywane od <a href=\"https://pl.wikipedia.org/wiki/1402\" target=\"_blank\" rel=\"noopener noreferrer\">1402</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> formie <i>Cornelius</i> oraz od <a href=\"https://pl.wikipedia.org/wiki/1412\" target=\"_blank\" rel=\"noopener noreferrer\">1412</a> roku w formach pochodnych Kornosz, Kornasz, Korna (masc.), Kornosza (masc.), Kornoszek i ze zdrobnieniami Nela (masc.), Nelka (masc.), Nelko.", "Kristaq": "<p>Kristaq to albanskie imię męskie. Do osób z imieniem Kristaq należą: Kristaq Antoniu (1907-1979) (znany również jako Cristache Antoniu), rumuński tenor operety, barytonowy i aktor Kristaq Dhamo (1933-2022), albanianki aktor i reżyser filmowy Kristaq Eksarko (1959-2025), albanianski piłkarz Kristaq Mile (urodzony w 1958 roku), albanianka piłkarza i trener Kristaq Mitro (1945-2023), albanian film reżysera Kristaq Paspali (1926-2001), albanianki tenor opera ...</p>", "K M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>K</b>.</p><b>K</b> (<a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>k</b>) (<i>ka</i>) – jedenasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i czternasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. W języku polskim oznacza <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę zwartą miękkopodniebienną bezdźwięczną</a>. Pochodzi od litery <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu fenickiego</a> <a href=\"https://pl.wikipedia.org/wiki/Kaf\" target=\"_blank\" rel=\"noopener noreferrer\">kaph</a>, za pośrednictwem litery alfabetu greckiego <a href=\"https://pl.wikipedia.org/wiki/Kappa_(litera)\" target=\"_blank\" rel=\"noopener noreferrer\">kappa</a> i alfabetu etruskiego.", "Krzysztof Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krzysztof</b>.</p><b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Koldo": "<p>Koldo to imię męskie. Wśród znanych osób z tej nazwy są: Koldo Aguirre (1939-2019), hiszpański piłkarz Koldo Álvarez, Andorran Koldo Fernández (ur. 1981), hiszpański rowerzysta Koldo Gil (ur. 1978), hiszpanski rowerzyst Koldo Gorostiaga Atxalandabaso (ur. 1940), hiszpanski polityk Koldo Izagirre (ur. 1953), hiszpaniański pisarz Koldo Mitxelena (1915-1987) Koldo Serra, hiszpajski reżyser Koldo Zuazo (ur. 1956), językoznawiec baski</p>", "Kusal": "<p>Kusal może odnosić się do Kusal Goonewardena, australijskiego fizykoterapeuty i wykładowcy zdrowia Kusal Mendis, Sri Lankan kryketa Kusal Perera, Sri Lanka kryketa Francišak Kušal, białoruski oficer armii i polityk Kusaal język, Gur (Niger-Kongo) język używany w Ghanie Kusal (film), Sri Lankan film</p>", "Kirtan": "Praktykowanie <i>sankirtanu</i> rozpoczął święty i reformator <a href=\"https://pl.wikipedia.org/wiki/Gaudija_wisznuizm\" target=\"_blank\" rel=\"noopener noreferrer\">gaudija wisznuizmu</a> – <a href=\"https://pl.wikipedia.org/wiki/%C4%86ajtanja_Mahaprabhu\" target=\"_blank\" rel=\"noopener noreferrer\">Ćajtanja Mahaprabhu</a> w <a href=\"https://pl.wikipedia.org/wiki/XVI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVI wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Bengal\" target=\"_blank\" rel=\"noopener noreferrer\">Bengalu</a> (<a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indie</a> wschodnie). Współcześnie <i>sankirtan</i> jest propagowany na całym świecie przez <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowe_Towarzystwo_%C5%9Awiadomo%C5%9Bci_Kryszny\" target=\"_blank\" rel=\"noopener noreferrer\">Międzynarodowe Towarzystwo Świadomości Kryszny</a> (ISKCON) i inne ruchy religijne wywodzące się z gaudija wisznuizmu. W ISKCON słowo <i>sankirtan</i> oznacza także rozpowszechnianie pism i książek lub wszelkiego rodzaju propagowanie religii.", "Korneliu": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Corneliu</b>.</p><p>Corneliu to rumuńskie imię, pochodzące od łacińskiego Cornelius. Corneliu może odnosić się do: Corneliu Baba Corneliu Bogdan Corneliu Calotescu Corneliu Carp Corneliu Chisu Corneliu Ciontu Corneliu Zelea Codreanu Corneliu Codreanu (piłkarz) Corneliu Coposu Corneliu Dragalina Corneliu E.</p>", "Kohta": "<p>Kōta, Kota, Kouta lub Kohta (pisanie: 耕太, 恒太, 康太, ⁇ 太, ??大 lub 幸太) to męskie japońskie imię. Znanymi osobami z nazwiska są: Kota Fujioka (藤岡康太; 1988-2024), japoński żokier Kota Fukatsu (深津 康太; ur. 1984), japońska piłkarka Kouta Hirano (平野 耕太; ur . 1973), japońskiego artysty manga Kota Ibushi (飯伏 幸太; ur., 1982), japończyka zawodowa walka Kota Kanai (金井 恒太; ur.; 1986), japoanska szogier Kota Mizuno (ur. 1982),...</p>", "Karl Peter": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karl</b>.</p><p>Karl Kurzwazje (niem. Karl Fr.</p>", "Ki Won": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ki</b>.</p><p>KI (drwa litera - główna ⁇ i ⁇) lub Ki może oznaczać: Kibi- (skr. Ki lub Ki) - podwójna przymowa, oznaczająca 210 (podobna do dziesięcioletniej przymowy ⁇ kil- ⁇).</p>", "Kazum": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kazumi</b>.</p><b>Kazumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずみ, カズミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Kaly": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kali</b>.</p><p>Kali (lat. Kali) - rodzaj promieniowanych ryb z rodziny żółtych (Chiasmodontidae).</p>", "Kevin Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kumara Swamy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kumara</b>.</p><p>Kumara (lat. Kumara) - rodzaj sukkulatów należących do rodziny Asphodeloideae i rosnących na terytorium Południowej Afryki, w szczególności w prowincji Kapskiej. Obecnie rodzaj obejmuje dwa gatunki, które wcześniej były klasyfikowane jako gatunki rodu Aloe (Aloe).</p>", "Kasi̇m": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Casim</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kasim</b>.</p><p>Kasim jako imię, wariant Qasim. Może odnosić się do:</p>", "Kevin-Elisei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kevin Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kalifa": "<p>Kalifa to męskie imię i nazwisko pochodzące z arabskiego pochodzenia, pochodzące od kalifa i kalifatu. Khalifa lub Khalifah to imię lub tytuł, który oznacza \"naśladowca\", \"leader\" lub \"władca\".</p>", "Krishna Mohan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krishna</b>.</p><p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Kašpar": "<p>Kašpar to czeskie nazwisko. Może odnosić się do: Adolf Kašpar (1877-1934), czeskiego malarza i ilustratora Jana Kašparów (1883-1927), czeskego lotnika, projektanta i inżyniera Jonáš Kašpar, czeskiego slalomisty kanotnika, który rywalizował od końca lat 2000 Lukáš Kašpara (ur. 1985), czeskiej hokejisty lodu Karel Kašpar (ur. 1870-1941), czeskie kardynał katolicki Petr Kašpar z 1960 r., czeskiego emeryturki piłkarskiej i obecnego dyrektora generalnego słowackiego klubu piłkarskiego Slovan...</p>", "Krzysztof Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krzysztof</b>.</p><b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Ki Beom": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ki</b>.</p><p>KI (drwa litera - główna ⁇ i ⁇) lub Ki może oznaczać: Kibi- (skr. Ki lub Ki) - podwójna przymowa, oznaczająca 210 (podobna do dziesięcioletniej przymowy ⁇ kil- ⁇).</p>", "Kobie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kobi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Koby</b>.</p><p>Coby lub Koby to imię męskie i żeńskie, nazwisko lub ksywkę pochodzące od nazwiska \"Jakob\" lub \"Jakob\".</p>", "Kryspinian": "<b>Kryspinian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od imienia <a href=\"https://pl.wikipedia.org/wiki/Kryspin\" target=\"_blank\" rel=\"noopener noreferrer\">Kryspin</a> (od łac. <i>crispus</i>, 'kędzierzawy'). Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Kryspin_i_Kryspinian\" target=\"_blank\" rel=\"noopener noreferrer\">św. Kryspinian</a>, wspominany razem ze <a href=\"https://pl.wikipedia.org/wiki/Kryspin_i_Kryspinian\" target=\"_blank\" rel=\"noopener noreferrer\">św. Kryspinem</a>.", "Kadi": "Od nazwy tej pochodzi <a href=\"https://pl.wikipedia.org/wiki/Alkad\" target=\"_blank\" rel=\"noopener noreferrer\">alkad</a>.", "Karthic": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karthik</b>.</p><p>Karthik lub Kartik może odnosić się do:</p>", "Kevin Andrey": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kevin-Amir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kalev": "<b>Kalev</b> – według mitologii fińskiej praojciec wszystkich <a href=\"https://pl.wikipedia.org/wiki/Finowie\" target=\"_blank\" rel=\"noopener noreferrer\">Finów</a>, bardzo ważna postać dla <a href=\"https://pl.wikipedia.org/wiki/Finowie\" target=\"_blank\" rel=\"noopener noreferrer\">Finów</a>, <a href=\"https://pl.wikipedia.org/wiki/Esto%C5%84czycy\" target=\"_blank\" rel=\"noopener noreferrer\">Estończyków</a> i <a href=\"https://pl.wikipedia.org/wiki/Karelowie\" target=\"_blank\" rel=\"noopener noreferrer\">Karelów</a> i innych narodów bałtycko-fińskich. Występował w <a href=\"https://pl.wikipedia.org/wiki/Finlandia\" target=\"_blank\" rel=\"noopener noreferrer\">fińskiej</a> \"<a href=\"https://pl.wikipedia.org/wiki/Kalevala\" target=\"_blank\" rel=\"noopener noreferrer\">Kalevali</a>\" i w <a href=\"https://pl.wikipedia.org/wiki/Estonia\" target=\"_blank\" rel=\"noopener noreferrer\">estońskim</a> \"Kalevipoeg\" (Synowie Kaleva). W sagach <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskich</a> występuje jako <b>Fornjotr</b> i według legendy pochodził z terenów <a href=\"https://pl.wikipedia.org/wiki/Estonia\" target=\"_blank\" rel=\"noopener noreferrer\">Estonii</a>, a następnie przeniósł się do <a href=\"https://pl.wikipedia.org/wiki/Finlandia\" target=\"_blank\" rel=\"noopener noreferrer\">Finlandii</a>. Zjednoczył wszystkie fińskie plemiona, miał żyć w latach ok. 160-210. Do dziś w języku estońskim pojęcie Kalev jest kojarzone z nadludzką siłą i potęgą, które były atrybutami tego herosa.", "Kalyana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kalyan</b>.</p><p>Kalyan (Marathi: कल्याण) to miasto w dzielnicy Thane w Maharashtra, jest przecinkiem linii kolejowej blisko Mumbai, India. To jest stolica Kalyan Taluka, jednostki administracyjnej okręgu.</p>", "Kazi̇m": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ćazim</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kazim</b>.</p><p>Kazem (zwany również Kadim, Kadhem, Kadhim, Kazim, Qazim lub Cathum; napisany w języku arabskim: كاظم, w perskim: کاظِم) oznacza \"tolerancja\", \"przebawienie\" i \"mieć cierpliwość\" jest arabskim męskim nazwiskiem. Chociaż wymowa litery arabskiej Ẓāʾ jest często bliżej silnego dźwięku \"d\", biorąc pod uwagę rozpowszechnienie nazwy w Wielkim Iranie i późniejszych wymian kulturowych między Persją i subkontynentem indyjskim, Azją Środkową i Anatolii, litera...</p>", "Krishn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krishna</b>.</p><p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Kip": "W 1979 roku nastąpiła w Laosie reforma walutowa. 100 starych kipów zastąpiono 1 nowym. Notowania (na dzień <a href=\"https://pl.wikipedia.org/wiki/Stycze%C5%84_2014#5_stycznia_2014\" target=\"_blank\" rel=\"noopener noreferrer\">5 stycznia 2014</a>): 1 USD = 8035 LAK, 1 PLN = 2619 LAK.", "Ki Hoon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ki</b>.</p><p>KI (drwa litera - główna ⁇ i ⁇) lub Ki może oznaczać: Kibi- (skr. Ki lub Ki) - podwójna przymowa, oznaczająca 210 (podobna do dziesięcioletniej przymowy ⁇ kil- ⁇).</p>", "Kevin Fabian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kennan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kenan</b>.</p>Księga Jubileuszów (rozdział 4) podaje również imię jego matki – Noam, imię jego żony i zarazem siostry – Melelet, oraz syna – Rasujal.", "Kondwani": "<p>Kondwani to męskie imię. Znani ludzie z nazwiska to: Kondwani Chiwina, Malawian średniej odległości biegacz Kondwani Mtonga (urodzony 1986), Zimbabwean piłkarz Kondwani Nankhumwa (urodzona 1978), Malawian polityk</p>", "Kevin Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kalistrat": "<b>Kalistrat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się ze złożenia słów <i>kalios</i> i <i>stratos</i> oznaczających kolejno \"piękno\" i \"armia\". Imię to nosiło kilku świętych katolickich.", "Kellen": "<p>Kellan, czyli Kellen, to męskie imię. Inne warianty Kellen lub Kellan obejmują Kaelan, Kallen, Keelan, Keilan, Keillan, Kelan, Kelden, Kelle, Kellyn i Kellin.</p>", "Kim Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Katsuji": "<p>Katsuji to zarówno japońskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Kima": "<p>Kima jest pająkiem z rodziny Salticidae.</p>", "Kamaleddin": "<p>Kamal ad-Din (arabski: كمال الدين, Kamāl ad-Dīn) to muzułmańskie imię lub nazwisko (laqab w języku arabskim), co oznacza \"doskonałość religii\" w językach arabskich. Nazwa jest utworzona z elementów kamāl (كمال), al- (الـp) i dīn (دين).</p>", "Kantaro": "<p>Kantarō, Kantaro, Kantarou lub Kantaroh (pisanie: 貫太郎, 勘太郎 lub 幹太郎) to męskie japońskie imię. Znanymi osobami z nazwiska są: Kantaro Hoshino (星野 勘太郎; 1943-2010), japoński zawodowy walker, menedżer i promotor Kantarō Suga (⁇ 貫太郎; 1934-1994), japoński aktor Kantarō Suzuki (鈴木 貫太 Taro; 1868-1948), admirał japońskiej marynarki wojennej i premier Japonii Kantaro Tomiyama (富山 幹太郎; ur. 1954), japoński biznesmen</p>", "Khodr": "<p>Khadr lub Khader, Kheder, Khidr/Khizr, Khodr, Khudr, Xidir itp. są rumowniami z خضر, arabskiej nazwy i nazwiska.</p>", "Klet": "<b>Klet</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o niejasnej etymologii. Może być ono użytym jako nazwa własna <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckim</a> przymiotnikiem <i>kl-tós</i> oznaczającym: \"wybrany\", \"wezwany\", jak również może być aluzją do greckiego ewangelicznego cytatu: \"<i>polloi eisi kl-toi, olígoi d- eklektoi\" -</i> \"wielu wezwanych, mało wybranych\".", "Kenan Mert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kenan</b>.</p>Księga Jubileuszów (rozdział 4) podaje również imię jego matki – Noam, imię jego żony i zarazem siostry – Melelet, oraz syna – Rasujal.", "Kays": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kais</b>.</p><p>Kais jest miastem w prowincji Khenchela w Algierii. W 2002 roku liczba ludności wynosiła 28 724 osób.</p>", "Kheder": "<p>Khadr lub Khader, Kheder, Khidr/Khizr, Khodr, Khudr, Xidir itp. są rumowniami z خضر, arabskiej nazwy i nazwiska.</p>", "Krystoff": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krystof</b>.</p><p>Kryštof to czeskie imię, równoważne angielskiej Christopher. Do wybitnych osób z tym nazwiskiem należą: Jan Kryštof Liška (kr.</p>", "Kevin Johan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Khaled F": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khaled</b>.</p><p>Khaled Haj Ibrahim (arabski خالد حاج إبراهيم; 29 lutego 1960, Oran, Algier) - algierski piosenkarz i muzykiem w stylu raji - mieszanki muzyki berberskiej i południowoeuropejskiej.</p>", "Kim Thành": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Kociemir": "<b>Chociemir</b>, <b>Chocimier</b>, <b>Chocimir</b>, <b>Chocimirz</b>, <b>Kociemir</b>, <b>Kociemiar</b>, <b>Kociemier</b>, <b>Kocimiar</b>, <b>Kocimier</b>, <b>Kocimir</b>, <b>Koćmir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Chocie-</i> („chcieć”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło oznaczać „pragnący pokoju”.", "Krzysztof Adam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krzysztof</b>.</p><b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Koshiro": "<p>Kōshirō, Koshiro lub Koushirou (zwany 幸四郎, 孝四郎, 高志郎, ⁇ 子郎, 好志郎 lub 公志郎) to męskie japońskie imię. Wśród znanych osób z tej nazwy są: Koshiro Itohara (糸原 ⁇ 史郎; ur. 1998), japoński piłkarz Kōshirō Ishida (石田 幸四郎; 1930-2006), japoński polityk Matsumoto Kōshirō (松本 幸四 Taro), różni aktorzy kabuki Matsumoto Koshiro X (十代目 松本幸四郎), japończyk Matsumoto Koshirō VII (七代目 松本 福四郎), japonski aktor Kōshirō Onchi (恩地...</p>", "Kazym": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kazim</b>.</p><p>Kazem (zwany również Kadim, Kadhem, Kadhim, Kazim, Qazim lub Cathum; napisany w języku arabskim: كاظم, w perskim: کاظِم) oznacza \"tolerancja\", \"przebawienie\" i \"mieć cierpliwość\" jest arabskim męskim nazwiskiem. Chociaż wymowa litery arabskiej Ẓāʾ jest często bliżej silnego dźwięku \"d\", biorąc pod uwagę rozpowszechnienie nazwy w Wielkim Iranie i późniejszych wymian kulturowych między Persją i subkontynentem indyjskim, Azją Środkową i Anatolii, litera...</p>", "Krzysztof Sławomir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krzysztof</b>.</p><b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Kevin Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Khalid R": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khalid</b>.</p><p>Khalid Donnel Robinson - amerykański piosenkarz, laureat i nominac wielu nagród muzycznych.</p>", "Kilyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kilian</b>.</p><b>Kilian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, etymologicznie wiążące się ze słowem <i>gillean</i> „mnich”. Angielska, polska i niemiecka forma imienia <i>Cillian</i> pochodzi od słowa <i>ceallach</i> oznaczającego „wojna” lub <i>ceall</i> oznaczającego „kościół”. Istnieją zapisy tego imienia w Polsce pochodzące jeszcze ze średniowiecza.", "Kay-Uwe": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kai-Uwe</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kai</b>.</p><b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Kai-Wei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kai</b>.</p><b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Kallen": "<p>Kallen to zarówno nazwisko, jak i imię. Znani ludzie z nazwiska obejmują: Horace Kallen (1882-1974), amerykański filozof Jackie Kallen (ur. 1946), amerykańskiego menedżera boksu Kitty Kallen (1921-2016), amerykańskiej piosenkarki Arvid Emanuel Kallen (1895-1969), szwedzkiego amerykańskego biznesmena Kallen Esperian (ur. 1961), amerykańskiego piosenkarza</p>", "Kieren": "<p>Ciarán (irlandzkie pisowni) lub Ciaran (szkocka gagelicka pisowni) jest tradycyjnie męskie nazwisko pochodzenia irlandzkiego i szkockiego. Oznacza to \"małe ciemne\" lub \"małe mrocznie włosne\", wytwarzane poprzez dodanie drobnego sufiksu do ciar (\"czarny\", \"ciemny\").</p>", "Kyryllo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kirillo</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kirill</b>.</p><p>Kirill (rosyjski: Кирилл) rosyjskie imię męskie, pochodzące od greckiego imienia Κύριλλος (Kyrillos), które z kolei pochodzą z greckiego κύριος (kyrios) \"pan\". Istnieje wiele wariantów nazwy: Cyryl, Cyrill, Kyrill, Kiryl, Kirillos, Kyryl, Kiril, Kyrylo, Kiro.</p>", "Kalwin": "<b>Jan Kalwin</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a>&#160;<em>Jean Cauvin</em> albo również <i>Jean Calvin</i>; ur. <a href=\"https://pl.wikipedia.org/wiki/10_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">10 lipca</a> <a href=\"https://pl.wikipedia.org/wiki/1509\" target=\"_blank\" rel=\"noopener noreferrer\">1509</a> w <a href=\"https://pl.wikipedia.org/wiki/Noyon\" target=\"_blank\" rel=\"noopener noreferrer\">Noyon</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/27_maja\" target=\"_blank\" rel=\"noopener noreferrer\">27 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1564\" target=\"_blank\" rel=\"noopener noreferrer\">1564</a> w <a href=\"https://pl.wikipedia.org/wiki/Genewa\" target=\"_blank\" rel=\"noopener noreferrer\">Genewie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Francuzi\" target=\"_blank\" rel=\"noopener noreferrer\">francuski</a> <a href=\"https://pl.wikipedia.org/wiki/Teolog\" target=\"_blank\" rel=\"noopener noreferrer\">teolog</a> protestancki, reformator, <a href=\"https://pl.wikipedia.org/wiki/Kaznodzieja\" target=\"_blank\" rel=\"noopener noreferrer\">kaznodzieja</a>, <a href=\"https://pl.wikipedia.org/wiki/Humanista\" target=\"_blank\" rel=\"noopener noreferrer\">humanista</a>, <a href=\"https://pl.wikipedia.org/wiki/Pisarz\" target=\"_blank\" rel=\"noopener noreferrer\">pisarz</a> i organizator życia duchowego w <a href=\"https://pl.wikipedia.org/wiki/Szwajcaria\" target=\"_blank\" rel=\"noopener noreferrer\">Szwajcarii</a> w okresie <a href=\"https://pl.wikipedia.org/wiki/Reformacja\" target=\"_blank\" rel=\"noopener noreferrer\">reformacji</a>. Twórca jednej z doktryn religijnych – <a href=\"https://pl.wikipedia.org/wiki/Kalwinizm\" target=\"_blank\" rel=\"noopener noreferrer\">ewangelicyzmu reformowanego</a> (od jego nazwiska nazywanej kalwinizmem), przyjętej przez <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bcio%C5%82y_ewangelicko-reformowane\" target=\"_blank\" rel=\"noopener noreferrer\">Kościoły ewangelicko-reformowane</a>, <a href=\"https://pl.wikipedia.org/wiki/Prezbiterianizm\" target=\"_blank\" rel=\"noopener noreferrer\">prezbiteriańskie</a>, a następnie przez część <a href=\"https://pl.wikipedia.org/wiki/Kongregacjonalizm\" target=\"_blank\" rel=\"noopener noreferrer\">kongregacjonalnych</a>, opierającej się głównie na nauce o <a href=\"https://pl.wikipedia.org/wiki/Predestynacja\" target=\"_blank\" rel=\"noopener noreferrer\">predestynacji</a> oraz nauce o realnej i duchowej obecności <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a> w <a href=\"https://pl.wikipedia.org/wiki/Eucharystia_(sakrament)\" target=\"_blank\" rel=\"noopener noreferrer\">Wieczerzy Pańskiej</a>, w odróżnieniu od poglądu powszechnie panującego w <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościele katolickim</a> (obecności realnej i cielesnej). Nazywany przez swych zwolenników „teologiem <a href=\"https://pl.wikipedia.org/wiki/Par_excellence\" target=\"_blank\" rel=\"noopener noreferrer\">par excellence</a>”; „Arystotelesem Reformacji”; „Akwinatą Kościoła reformowanego”; „najbardziej chrześcijańskim mężem swej epoki” czy też „drugim patriarchą reformacji”.", "Kasjano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kasjan</b>.</p><b>Kasjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">rodu</a> <a href=\"https://pl.wikipedia.org/wiki/Republika_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> <i>Cassianus</i>. Imię to nosiło około dwunastu <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty\" target=\"_blank\" rel=\"noopener noreferrer\">świętych</a> lub <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ogos%C5%82awiony\" target=\"_blank\" rel=\"noopener noreferrer\">błogosławionych</a>. W Polsce imię wystąpiło w 1445 roku jako Cassianus (Kasyjan). Później było rzadkie i ma niewielką popularność. W 2015 r. imię to nadano 27 chłopcom, w 2016 r. – 43, w 2017 r. – 61. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 1476 mężczyzn o imieniu Kasjan nadanym jako imię pierwsze.", "Kasperi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kasper</b>.</p><b>Kacper</b>, <b>Kasper</b>, <b>Kaspar</b>, <b>Gaspar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, oboczności powstałe jako przekształcenie imienia Kasper, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> <i>ganzabara</i> („strażnik skarbca”) od <i>*ganzah</i> (“skarb”) + <i>*barah</i> (“brzemię”), od praindoeuropejskiego <i>*bʰer-</i> („brać”).", "Kemal-Sebastian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kemal</b>.</p><p>Mustafa Kemal Atatürk (Turkish pronunciation: [musˈtafa ceˈmal ataˈtyɾk]; (19 maja 1881 - 10 listopada 1938) był oficerem wojskowym, rewolucjonistą i patriotą, a także pierwszym prezydentem Republiki Turcji. Atatürk był znany z uznania za sztuczną w czasie I wojny światowej.</p>", "Kevin Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kazimierz Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kazimierz</b>.</p><b>Kazimierz</b> – współcześnie przyjęta forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> męskiego <b>Kazimir</b> (z odmiankami <b>Kazimirz</b>, <b>Kazimiar</b>, <b>Kazimier</b>, <b>Kaźmir</b>, <b>Kaźmisz</b>), składającego się z członów: <i>Kazi-</i> („niszcz, psuj, niwecz” od <i>kazić</i> „niszczyć, psuć”, porównaj współczesne <i>od-kazić</i> „od-psuć”) i <i>-mir</i> („pokój, spokój”). Oznacza „ten, który (niech) niszczy pokój” – niszcz pokój! = kaź mir! (staropolskie kazi mir!).", "Krzysztof Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krzysztof</b>.</p><b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Kevin Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kalyan Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kalyan</b>.</p><p>Kalyan (Marathi: कल्याण) to miasto w dzielnicy Thane w Maharashtra, jest przecinkiem linii kolejowej blisko Mumbai, India. To jest stolica Kalyan Taluka, jednostki administracyjnej okręgu.</p>", "Kim Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Key": "<b>Key</b> – japońskie studio tworzące <a href=\"https://pl.wikipedia.org/wiki/Powie%C5%9B%C4%87_wizualna\" target=\"_blank\" rel=\"noopener noreferrer\">powieści wizualne</a>, będące formalnie marką wydawcy gier komputerowych <a href=\"https://pl.wikipedia.org/wiki/Visual_Arts\" target=\"_blank\" rel=\"noopener noreferrer\">Visual Arts</a>. Jest jednym z głównych przedstawicieli nurtu <i>nakige</i>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;泣きゲ&#59; „gry wywołujące łzy”). Pierwszym tytułem studia była wydana w 1999 roku <a href=\"https://pl.wikipedia.org/wiki/Eroge\" target=\"_blank\" rel=\"noopener noreferrer\">gra dla dorosłych</a> <i><a href=\"https://pl.wikipedia.org/wiki/Kanon_(gra_komputerowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Kanon</a></i>. W 2004 roku wydana została pierwsza produkcja studia przeznaczona dla wszystkich grup wiekowych – <i><a href=\"https://pl.wikipedia.org/wiki/Clannad_(gra_komputerowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Clannad</a></i>. Key współpracowało ze studiem animacyjnym <a href=\"https://pl.wikipedia.org/wiki/P.A._Works\" target=\"_blank\" rel=\"noopener noreferrer\">P.A. Works</a> oraz firmą <a href=\"https://pl.wikipedia.org/wiki/Aniplex\" target=\"_blank\" rel=\"noopener noreferrer\">Aniplex</a> przy produkcji seriali <a href=\"https://pl.wikipedia.org/wiki/Anime\" target=\"_blank\" rel=\"noopener noreferrer\">anime</a> <i><a href=\"https://pl.wikipedia.org/wiki/Angel_Beats!\" target=\"_blank\" rel=\"noopener noreferrer\">Angel Beats!</a></i> (2010), <i><a href=\"https://pl.wikipedia.org/wiki/Charlotte_(anime)\" target=\"_blank\" rel=\"noopener noreferrer\">Charlotte</a></i> (2015) i <i><a href=\"https://pl.wikipedia.org/wiki/Kami-sama_ni_natta_hi\" target=\"_blank\" rel=\"noopener noreferrer\">Kami-sama ni natta hi</a></i> (2020).", "Kido": "Dnia 13 lutego 2009 roku firma <a href=\"https://pl.wikipedia.org/wiki/Microsoft\" target=\"_blank\" rel=\"noopener noreferrer\">Microsoft</a> wyznaczyła po 250 tys. <a href=\"https://pl.wikipedia.org/wiki/Dolar_ameryka%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">dolarów</a> nagrody dla każdego, kto jest w stanie udzielić informacji mogących pomóc w ujęciu twórcy <a href=\"https://pl.wikipedia.org/wiki/Wirus_komputerowy\" target=\"_blank\" rel=\"noopener noreferrer\">wirusa</a>.", "Ki Young": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ki</b>.</p><p>KI (drwa litera - główna ⁇ i ⁇) lub Ki może oznaczać: Kibi- (skr. Ki lub Ki) - podwójna przymowa, oznaczająca 210 (podobna do dziesięcioletniej przymowy ⁇ kil- ⁇).</p>", "Kier": "Odpowiednikiem kierów w talii niemieckiej są serca, w talii szwajcarskiej – kwiaty, zaś w talii włosko-hiszpańskiej puchary.", "Kajetano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kajetan</b>.</p><b>Kajetan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pierwotnie oznaczało „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Gaeta\" target=\"_blank\" rel=\"noopener noreferrer\">Caiety</a>”, miasta w <a href=\"https://pl.wikipedia.org/wiki/Italia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Italii</a>. Na Kresach imię to cieszyło się szczególną popularnością wśród mniejszości <a href=\"https://pl.wikipedia.org/wiki/Ormianie_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiej</a>.", "Kerr": "<b>Kerr</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gaelicki_szkocki\" target=\"_blank\" rel=\"noopener noreferrer\">gael.</a> <i>Cearr</i>, <i>MacGhillechearr</i>) – szkockie nazwisko i nazwa klanu ze szkockich <a href=\"https://pl.wikipedia.org/wiki/Lowlands\" target=\"_blank\" rel=\"noopener noreferrer\">Nizin</a> i <a href=\"https://pl.wikipedia.org/wiki/Borders\" target=\"_blank\" rel=\"noopener noreferrer\">Pogranicza</a>. Klan pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Normanowie\" target=\"_blank\" rel=\"noopener noreferrer\">normańskiego</a>. pochodzenie nazwiska, pisanego dawniej jako <b>Carr</b>, <b>Ker</b> lub <b>Carre</b>, nie jest do końca wyjaśnione. Istniejące hipotezy wywodzą je od:", "Karunesh": "Po poważnym wypadku drogowym wyjechał w 1979 do <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indii</a>, gdzie poznał <a href=\"https://pl.wikipedia.org/wiki/Osho_(guru)\" target=\"_blank\" rel=\"noopener noreferrer\">Osho</a>, przeszedł inicjację w <a href=\"https://pl.wikipedia.org/wiki/Ashram\" target=\"_blank\" rel=\"noopener noreferrer\">aszramie</a> w <a href=\"https://pl.wikipedia.org/wiki/Pune\" target=\"_blank\" rel=\"noopener noreferrer\">Punie</a> i przyjął imię „<i>Karunesh</i>”, co w <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrycie</a> znaczy „współczucie”. Po powrocie do Niemiec przez pięć lat mieszkał w <a href=\"https://pl.wikipedia.org/wiki/Hamburg\" target=\"_blank\" rel=\"noopener noreferrer\">Hamburgu</a> we wspólnocie <i>Rajneesh</i>, gdzie stykał się z muzykami z całego świata. W <a href=\"https://pl.wikipedia.org/wiki/1987\" target=\"_blank\" rel=\"noopener noreferrer\">1987</a> wydał pierwszy album <i>Sounds of The Heart</i> („Dźwięki serca”), zaliczony do klasyki gatunku. Każdy następny album odnosił spory międzynarodowy sukces.", "Keiji": "<b>Keiji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けいじ, ケイジ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Krzysztof Stefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krzysztof</b>.</p><b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Kevin Alfonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kevin</b>.</p><p>Kevin () jest anglojęzyczną formą imienia Caoimhín ([kiːvjiːnj], średnioirelski: Caoimhghín [kəi ⁇ j ⁇ iːnj], pierwotny irlandzki: Cóemgein [koi ⁇ jɣjinj], łacińskiej Coemgenus) dla mężczyzn w języku irlandzkim, powstawając z irlandzkiego caomh (przednioirelska cóem) \"niebieskie; szlachetne\" (dear, noble) i -gin (przednieirelska gein) \"rodzenie\" (birth). Wariant Kevana jest angielski, a w formie angielskiej jest angielsko.</p>", "Kostin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Costin</b>.</p><p>Costin to rumuńskie i angielskie nazwisko i imię. Znani ludzie z nazwiskiem to: Nazwisko: Brandon Costin, australijski gracz rugby Darren Costin (ur. 1966), angielski muzyk Doug Costin (ura. 1997), amerykański piłkarz Frank Costin (1920-1995), brytyjski inżynier motoryzacyjny Gheorghe Costin (urat. 1955), rumuński dyrygent i kompozytor Henry Gilbert Costin (1898-1918), żołnierz armii Stanów Zjednoczonych i Medal Honoru...</p>", "Kazimierz Wiktor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kazimierz</b>.</p><b>Kazimierz</b> – współcześnie przyjęta forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> męskiego <b>Kazimir</b> (z odmiankami <b>Kazimirz</b>, <b>Kazimiar</b>, <b>Kazimier</b>, <b>Kaźmir</b>, <b>Kaźmisz</b>), składającego się z członów: <i>Kazi-</i> („niszcz, psuj, niwecz” od <i>kazić</i> „niszczyć, psuć”, porównaj współczesne <i>od-kazić</i> „od-psuć”) i <i>-mir</i> („pokój, spokój”). Oznacza „ten, który (niech) niszczy pokój” – niszcz pokój! = kaź mir! (staropolskie kazi mir!).", "Kanimir": "<b>Kanimir</b>, <b>Kanimier</b>, <b>Kajmir</b>, <b>Kalmir</b> — <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów: <i>Kani-</i> w różnych wersjach brzmieniowych (\"gościć, zapraszać\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"ten, u kogo gości pokój\".", "Kalian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kalyan</b>.</p><p>Kalyan (Marathi: कल्याण) to miasto w dzielnicy Thane w Maharashtra, jest przecinkiem linii kolejowej blisko Mumbai, India. To jest stolica Kalyan Taluka, jednostki administracyjnej okręgu.</p>", "Kseniia": "<p>Xenia (varianty obejmują Ksenia, Kseniia, Ksenja, Kseniya; pochodzące z greckiego Ξένια xenia, \"gastotliwość\") jest nazwą dla kobiet. Poniższe sekcje zawierają listę znanych osób z jedną z wariantów tej nazwy.</p>", "Kim Sơn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Klavs": "<p>Klavs to głównie duńskie imię męskie, które jest wariantem Klaus. Kłóci, którzy nosili nazwę Klavs, to: Klāvs Čavars (ur. 1996), lotyjski piłkarz koszykówki Klavs Jørn Christensen (ur. 1961), duński strzelca sportowy Klavs F.</p>", "Kham": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cham</b>.</p><b>Cham</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> חָם <i>Ḥam</i>) – według biblijnej <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a> jeden z 3 synów <a href=\"https://pl.wikipedia.org/wiki/Noe\" target=\"_blank\" rel=\"noopener noreferrer\">Noego</a>, przodek ludów <a href=\"https://pl.wikipedia.org/wiki/Kanaan\" target=\"_blank\" rel=\"noopener noreferrer\">Kanaanu</a> i <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>. Od jego imienia wzięła się nazwa grupy ludów <a href=\"https://pl.wikipedia.org/wiki/Chamici\" target=\"_blank\" rel=\"noopener noreferrer\">chamickich</a>. Za swoje zachowanie w stosunku do ojca został, w popularnym rozumieniu, wraz z potomstwem, <a href=\"https://pl.wikipedia.org/wiki/Przekle%C5%84stwo_Chama\" target=\"_blank\" rel=\"noopener noreferrer\">przeklęty przez Noego</a> (stąd chamem określa się człowieka źle wychowanego, gbura, prostaka), choć ściśle został przeklęty tylko jeden jego syn <a href=\"https://pl.wikipedia.org/wiki/Kanaan_(syn_Chama)\" target=\"_blank\" rel=\"noopener noreferrer\">Kanaan</a>.", "Khurshedi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khurshed</b>.</p><p>Khorshīd lub Khorshēd (perskie: خورشید [xoɾˈʃid], co oznacza Słońce lub \"Słońce promieniowane\"), również pisowniane jako Khurshed i Khurshid, jest perskim nazwiskiem. W dzisiejszych czasach, jak również w historycznym Iranie, Turcji i Azerbejdżanie, ale także w irackim Kurdystanie, Egipcie, Azji Środkowej i Azji Południowej, jest to głównie imię dla chłopców.</p>", "Krzysztof Edward": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krzysztof</b>.</p><b>Krzysztof</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Christophoros</i>, powstałego ze złączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Χριστός (<i>Christos</i>) i φορος „nosiciel” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φέρω – <i>phero</i> „niosę”) – co w tłumaczeniu znaczy „niosący <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>” w znaczeniu <i>przynoszący Chrystusa</i> lub też <i>noszący w sobie Chrystusa</i>, co wiąże się z legendą o <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Krzysztofie</a>.", "Katarzyna": "<b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Krystyna": "<b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kinga": "<b>Kinga</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia węgierskiego, wywodzące się od zdrobnienia <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kunegunda\" target=\"_blank\" rel=\"noopener noreferrer\">Kunegunda</a>. W piśmiennictwie węgierskim występują formy: <i>Kunegund, Kinga, Kynga, Kynka,</i> natomiast w polskim – <i>Kinga</i> (1278) i <i>Kinka</i> (1320–1329).", "Klaudia": "<b>Klaudia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Claudia</em>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego. Wywodzi się od nazwy rzymskiego rodu Klaudiuszów. Imię <a href=\"https://pl.wikipedia.org/wiki/Klaudia_(z_Klaudiusz%C3%B3w)\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudia</a> nosiły wszystkie kobiety z tego rodu. Odnotowano trzy święte katolickie o tym imieniu. Istnieje też pochodna forma tego imienia: <a href=\"https://pl.wikipedia.org/wiki/Klaudyna\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudyna</a>.", "Kazimiera": "<b>Kazimiera</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kazimierz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kazimierz</a>. W średniowieczu nie występowało. Prawdopodobnie rozpowszechniło się pod koniec XVII wieku, po przyjeździe do Polski <a href=\"https://pl.wikipedia.org/wiki/Maria_Kazimiera_d%E2%80%99Arquien\" target=\"_blank\" rel=\"noopener noreferrer\">Marysieńki</a>, żony króla <a href=\"https://pl.wikipedia.org/wiki/Jan_III_Sobieski\" target=\"_blank\" rel=\"noopener noreferrer\">Jana III Sobieskiego</a>.", "Klara": "<b>Klara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przymiotnika <i>clarus</i> oznaczającego „jasny”, „jaśniejący”, „sławny”.", "Karina": "<b>Karina</b>, <b>Karyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z jęz. niemieckiego; forma zdrobniała od imienia <i>Katarina</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Katarzyna\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna</a>). Inna hipoteza mówi, że wywodzi się od słowa <i>cara</i>, które po <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacinie</a> oznacza \"kochana, droga\" lub w galickim \"przyjaciel\". Jeszcze inna hipoteza mówi, że pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">konstelacji</a> <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Kila\" target=\"_blank\" rel=\"noopener noreferrer\">Kil</a>, nazwanej w związku kilem statku <a href=\"https://pl.wikipedia.org/wiki/Jazon_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jazona</a>.", "Kalina": "<b>Kalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnym pochodzeniu, stanowiące być może przekształcone na gruncie białoruskim imię <a href=\"https://pl.wikipedia.org/wiki/Akwilina\" target=\"_blank\" rel=\"noopener noreferrer\">Akwilina</a>, lub powstałe na gruncie wschodniosłowiańskim pod wpływem wyrazu <a href=\"https://pl.wikipedia.org/wiki/Kalina_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">kalina</a>. Zgodnie z rosyjskimi źródłami, <i><b>Kalinka</b></i> to zdrobnienie zarówno męskie od <a href=\"https://pl.wikipedia.org/wiki/Kalinik\" target=\"_blank\" rel=\"noopener noreferrer\">Kalinika</a>, jak i żeńskie – od żeńskiego rosyjskiego odpowiednika tego imienia, tj. <i>Kallinikii</i> (<i>Каллиникня</i>). Należy też podkreślić, iż forma Kalina spotykana była jako męska forma skrócona imienia <a href=\"https://pl.wikipedia.org/wiki/Kalinik\" target=\"_blank\" rel=\"noopener noreferrer\">Kalinik</a> już w źródłach pochodzących z lat <a href=\"https://pl.wikipedia.org/wiki/1479\" target=\"_blank\" rel=\"noopener noreferrer\">1479</a>–<a href=\"https://pl.wikipedia.org/wiki/1584\" target=\"_blank\" rel=\"noopener noreferrer\">1584</a> z <a href=\"https://pl.wikipedia.org/wiki/Monastyr_So%C5%82owiecki\" target=\"_blank\" rel=\"noopener noreferrer\">monastyru sołowieckiego</a>.", "Karyna": "<b>Karina</b>, <b>Karyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z jęz. niemieckiego; forma zdrobniała od imienia <i>Katarina</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Katarzyna\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna</a>). Inna hipoteza mówi, że wywodzi się od słowa <i>cara</i>, które po <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacinie</a> oznacza \"kochana, droga\" lub w galickim \"przyjaciel\". Jeszcze inna hipoteza mówi, że pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">konstelacji</a> <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Kila\" target=\"_blank\" rel=\"noopener noreferrer\">Kil</a>, nazwanej w związku kilem statku <a href=\"https://pl.wikipedia.org/wiki/Jazon_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jazona</a>.", "Konstancja": "<b>Konstancja</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Konstancjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Konstancjusz</a>, wywodząca się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>constantia</em> – „stałość, stateczność, wytrwałość”.", "Kamilla": "<b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Katsiaryna": "<p>Katerina (greckie: Κατερίνα, romanized: Katerína; rosyjski, bułgarski i makedonii: Катерина, romanize: Katerina) to imiona żeńskie. Jest to greckie wariant Ekaterini i rosyjska i bułgarska krótka forma Ekaterina lub Yekaterina.</p>", "Ksenia": "<b>Ksenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „gościnna” (Ξενία, dosł. „życzliwa dla obcych”), popularne zwłaszcza w krajach prawosławnych: rosyjskie <b>Ксения</b> (<i><b>Ksienija</b></i>), <b>Аксиния</b> (<i><b>Aksinija</b></i>), ukraińskie <b>Ксенія</b> (<i><b>Ksenija</b></i>), <b>Ксеня</b> (<i><b>Ksenia</b></i>) oraz pochodne <b>Оксана</b> (<i><b>Oksana</b></i>), białoruskie <b>Ксенія</b> (<i><b>Ksenìâ</b></i>), czeskie <b>Xenie</b>, słowackie <b>Xeni</b>.", "Krzysztofa": "<b>Krzysztofa</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Krzysztof\" target=\"_blank\" rel=\"noopener noreferrer\">Krzysztof</a> o pochodzeniu greckim.", "Klementyna": "<b>Klementyna</b> – żeński odpowiednik łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Klementyn\" target=\"_blank\" rel=\"noopener noreferrer\">Klementyn</a>.", "Klaudyna": "<b>Klaudyna</b> – pochodna forma imienia <a href=\"https://pl.wikipedia.org/wiki/Klaudia\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudia</a>, powstała od zdrobniałego imienia <i>Claudine</i>, co oznacza 'należąca do rodu Claudia, córka Claudiusa' lub 'mała, kochana Claudia'. Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Klaudyna_Th%C3%A9venet\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudyna Thévenet</a>.", "Kseniya": "<p>Xenia (varianty obejmują Ksenia, Kseniia, Ksenja, Kseniya; pochodzące z greckiego Ξένια xenia, \"gastotliwość\") jest nazwą dla kobiet. Poniższe sekcje zawierają listę znanych osób z jedną z wariantów tej nazwy.</p>", "Kunegunda": "<b>Kunegunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>kuni</i> „(ktoś) ze szlachetnego rodu” oraz <i>gund</i> „walka”, można określić jego pierwotne znaczenie jako „walcząca dla swojego rodu”. Jego zdrobnieniem powstałym na gruncie węgierskim jest <a href=\"https://pl.wikipedia.org/wiki/Kinga\" target=\"_blank\" rel=\"noopener noreferrer\">Kinga</a>, stąd polskie Kinga.", "Kornela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kornel</b>.</p><b>Kornel</b>, <b>Korneliusz</b>, <b>Korneli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Cornelii</i> (<i>Korneliuszy</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusze Cynna</a>). Istnieją różne hipotezy pochodzenia wspomnianej nazwy rodowej; wywodzi się ją bądź to ze słowa <i>cornu</i> („róg”), bądź to <i>cornus</i> („<a href=\"https://pl.wikipedia.org/wiki/Dere%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dereń</a>”), bądź to od nazwy pola <i>Corne</i> w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. W dawnej Polsce zapisywane od <a href=\"https://pl.wikipedia.org/wiki/1402\" target=\"_blank\" rel=\"noopener noreferrer\">1402</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> formie <i>Cornelius</i> oraz od <a href=\"https://pl.wikipedia.org/wiki/1412\" target=\"_blank\" rel=\"noopener noreferrer\">1412</a> roku w formach pochodnych Kornosz, Kornasz, Korna (masc.), Kornosza (masc.), Kornoszek i ze zdrobnieniami Nela (masc.), Nelka (masc.), Nelko.", "Katerina": "<p>Katerina - żeńskie imię, fonetyczny wariant nazwiska Ekaterina.</p>", "Kasandra": "<b>Kasandra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, powstałe z wyrazów <i>kekasmai</i> – „wyróżniająca się” i <i>anēr</i>, d. <i>andrós</i> – „człowiek”.", "Ksymena": "<b>Ksymena</b>, <b>Xymena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szymon\" target=\"_blank\" rel=\"noopener noreferrer\">Szymon</a>, ukształtowany za pośrednictwem dawnego języka hiszpańskiego.", "Karola": "<b>Karola</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>.", "Kate": "<p>Kate (KDE Advanced Text Editor) - redaktor tekstu w skład środowiska pracy KDE. Rozprzestrzegana jest na podstawie GNU General Public License.</p>", "Klavdiia": "<p>Claudia to kobiece imię równoważne z Claudius lub Claudio. W portugalsku jest akcentem Cláudia.</p>", "Kesja": "<b>Kasja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od łacińskiej nazwy rodu Kasjuszy (<i>Cassius</i>). Wśród patronów – czterech świętych.", "Kiara": "<p>Kiara (ang. Kiara, Ciara) lub Hier (ang.</p>", "Ksawera": "<b>Ksawera</b>, <b>Ksaweryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">Ksawery</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Franciszka_Ksawera\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszka Ksawera</a> Cabrini.", "Krystiana": "<b>Krystiana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Krystian\" target=\"_blank\" rel=\"noopener noreferrer\">Krystian</a>, które powstało poprzez dodanie przyrostka <i>-ianus</i>, oznaczającego przynależność lub pochodzenie, do łacińskiego imienia <i><a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Christinus/Cristinus</a></i>. Oznacza „chrześcijanka, należąca do Chrystusa, Chrystusowa”. Imię to jest poświadczone w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, w formie <i><b>Krzys(z)tyjana</b></i>, <i><b>Krystyjana</b></i>. Staropolskie formy pochodne: Krczona, Krzczona, Chryścijanica, Chrzczonka.", "Karine": "<p>Karine to francuskie imię kobiety. Wśród znanych osób z tej nazwy są: Karine Bakhoum, egipsko-amerykański szef kuchni Karine Baste (ur. 1982), francuska dziennikarz i prezenterka wiadomości Karine Beauchard (ur. 1978), francuska matematyka Karine Berger (ur. 1973), francuska polityka Karine Ferri (ur. 1982), francuska prezenterka telewizyjna i modelka Karine Giboulo (ur. 1980), kanadyjska artystka Karine Costa (ur. 1977), francuska piosenkarka Karine Haaland (ur....</p>", "Kasia": "<b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Kamelia": "<b>Kamelia</b> – imię żeńskie pochodzące od nazwy <a href=\"https://pl.wikipedia.org/wiki/Kamelia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">kwitnącego krzewu</a> nazwanego na cześć botanika i misjonarza <a href=\"https://pl.wikipedia.org/wiki/Georg_Joseph_Kamel\" target=\"_blank\" rel=\"noopener noreferrer\">Georga Josepha Kamela</a>.", "Kayla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kayl</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kayle</b>.</p><p>Kayle to nazwisko, jiddish feminine, a męskie. Jako jydska nazwa, Kayle (קילא KAY-leh) jest znana od XIII wieku jako wariant Keyle, co oznacza \"wesoły\"; jest spokrewniona z nowoczesnym niemieckim słowem geil.</p>", "Katrina": "<p>Huragan Katrina jest 11 r. nazwanym huraganem i piątym tropikalnym huraganem z 2005 roku. Katrina była największą katastrofą materialną i piątą największą stratą w historii USA.</p>", "Kryspina": "<b>Kryspina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>crispa</i> – (osoba) o kręconych włosach, kędzierzawa.", "Kaia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kai</b>.</p><b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Kora": "<b>Kora</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>cortex</em>) – w <a href=\"https://pl.wikipedia.org/wiki/Botanika\" target=\"_blank\" rel=\"noopener noreferrer\">botanice</a> nieprecyzyjna nazwa tkanek w zewnętrznych partiach <a href=\"https://pl.wikipedia.org/wiki/Korze%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">korzenia</a> lub <a href=\"https://pl.wikipedia.org/wiki/%C5%81odyga\" target=\"_blank\" rel=\"noopener noreferrer\">łodygi</a>, może być używana w różnym znaczeniu:", "Kasjana": "<b>Kasjana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kasjan\" target=\"_blank\" rel=\"noopener noreferrer\">Kasjan</a> o pochodzeniu łacińskim.", "Kama": "<b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Koryna": "<b>Koryna</b>, Korynna – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, będące zdrobnieniem imienia <a href=\"https://pl.wikipedia.org/wiki/Kora_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kora</a>, wywodzącego się od słowa <i>kóre</i> „dziewczę”. Patronką tego imienia jest św. Koryna z <a href=\"https://pl.wikipedia.org/wiki/Syria\" target=\"_blank\" rel=\"noopener noreferrer\">Syrii</a> (II wiek).", "Konstantyna": "<b>Konstantyna</b> – imię żeńskie. forma żeńska <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Konstanty\" target=\"_blank\" rel=\"noopener noreferrer\">Konstanty</a>, <a href=\"https://pl.wikipedia.org/wiki/Konstanty\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantyn</a>.", "Kordula": "<b>Kordula</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Cordulus/ula</i>, stanowiącego złożenie wyrazów <i>cor</i>, <i>cordis</i> („serce”) i <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> zdrabniającego <i>-ula</i>. Według innych hipotez pochodzi bezpośrednio od łacińskiego wyrazu <i>cordulum</i> („serduszko”), może stanowić żeńską formę imienia rzymskiego <i>Cordus</i> i oznaczać „późno urodzona” lub pochodzić od nazwy greckiego miasta Kordule. W Polsce notowane od <a href=\"https://pl.wikipedia.org/wiki/1414\" target=\"_blank\" rel=\"noopener noreferrer\">1414</a> roku.", "Kathryn": "<p>Kathryn to kobiece imię i pochodzi od greckiego znaczenia \"czysty\". To wariant Katherine.</p>", "Katja": "<p>Zitha (lat. Zitha) - rodzaj motyle podrodzinnego Pyralinae z rodziny palących prawdziwych (Pyralidae). Znane jest około 150 gatunków.</p>", "Krystina": "<p>Krystina to kobiece imię. Znanymi osobami z tego nazwiska są: Krystina Alabado (ur. 1989), amerykańska aktorka i piosenkarka Krystina Alogbo (ur. 1986), kanadyjska graczka w polo wodne Krystina Arielle (ur. 1986), amerykańska aktorka, gospodarz i cosplayer Krystina Emmanouilides (ur. 1991), grecko-australijska inżynierka dynamiki płynów obliczeniowych</p>", "Koleta": "<b>Koleta</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Coleta</em>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a>&#160;<em>Colette</em>) – pierwotnie zdrobniała forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Nikoleta\" target=\"_blank\" rel=\"noopener noreferrer\">Nikoleta</a>, powstałego od <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikoli</a>, żeńskiego odpowiednika <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaja</a>. Koleta jest imieniem znanym w Polsce, dzięki funkcjonującemu zakonowi żeńskiemu.", "Klarysa": "<b>Klarysa</b> – imię żeńskie, pokrewne imieniu <a href=\"https://pl.wikipedia.org/wiki/Klara\" target=\"_blank\" rel=\"noopener noreferrer\">Klara</a>.", "Khava": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Chava</b>.</p><p>Eve jest angielskie imienne, pochodzące z łacińskiej nazwy Eva, a z kolei pochodzące od hebrajskiego חַוָּה (Chavah/Havah - chavah, oddychać, a chayah, żyć lub dać życie). W Grecji nazwa Ewa jest Evi (Εύη), skróceniem nazwy chrztu Paraskevi.</p>", "Konrada": "<b>Konrada</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Konrad_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Konrad</a> pochodzenia germańskiego.", "Klotylda": "<b>Klotylda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „słynąca w walce”.", "Kwiryna": "<b>Kwiryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kwiryn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kwiryn</a> o łacińskim pochodzeniu.", "Kheda": "<p>Kheda to miasto i dzielnica w hrabstwie Kheda w stanie Gujarat, India.</p>", "Kathy": "<p>Kathy to kobiece imię. Często jest skróceniem dla innych nazw.</p>", "Khadija": "<p>Khadija, Khadeeja lub Khadijah (arabsko: خديجة, romanized: Khadīja) to arabskie nazwisko kobiece, nazwisko Khadija bint Khuwaylid, pierwszej żony islamskiego proroka Muhammada. W 1995 roku było to jedno z trzech najpopularniejszych arabskich nazw kobiet w świecie muzułmańskim, wraz z Fatimą i Aishą.</p>", "Katya": "<p>Katya to kobiece imię. Jest to bardzo popularne imię w Rosji, Ukrainie, Bułgarii, Serbii i Macedonii Północnej.</p>", "Kayah": "<p>Kayah może być: Kayah The Kayah The State Kayah The Keynote Kayah Li Znasz się z polskiej piosenkarki Katarzyna Szczot.</p>", "Karmela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karmel</b>.</p>Jest głównym składnikiem niektórych rodzajów <a href=\"https://pl.wikipedia.org/wiki/Cukierek\" target=\"_blank\" rel=\"noopener noreferrer\">cukierków</a>, <a href=\"https://pl.wikipedia.org/wiki/Barwniki_spo%C5%BCywcze\" target=\"_blank\" rel=\"noopener noreferrer\">barwnikiem</a> napojów typu <a href=\"https://pl.wikipedia.org/wiki/Cola\" target=\"_blank\" rel=\"noopener noreferrer\">cola</a>, ciemnego <a href=\"https://pl.wikipedia.org/wiki/Pieczywo\" target=\"_blank\" rel=\"noopener noreferrer\">pieczywa</a>, <a href=\"https://pl.wikipedia.org/wiki/Czekolada\" target=\"_blank\" rel=\"noopener noreferrer\">czekolad</a>, <a href=\"https://pl.wikipedia.org/wiki/Lody\" target=\"_blank\" rel=\"noopener noreferrer\">lodów</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCem\" target=\"_blank\" rel=\"noopener noreferrer\">dżemów</a> i <a href=\"https://pl.wikipedia.org/wiki/Jogurt\" target=\"_blank\" rel=\"noopener noreferrer\">jogurtów</a>. Dodatek karmelu do żywności jest oznaczany przez kod E150 i literę wyróżniającą typ karmelu.", "Kassandra": "<p>Kassandra (Grzec. ?) jest samodzielnym terytorium w regionie Macedonii Środkowej, Grecja. Autonomiczna dzielnica Kassandra ma powierzchnię 334 km2, populacja według badania z 18 marca 2001 roku wynosi 14971 mieszkańców.</p>", "Karena": "<b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Katharine": "<p>Katherine (), również pisowana jako Catherine i inne warianty, jest imieniem żeńskim. Nazwa i jej warianty są popularne w krajach, w których istnieje duża populacja chrześcijańska, ze względu na związki z jedną z najwcześniejszych świętych chrześcijan, Kataryną z Aleksandrii.</p>", "Katalina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Katalin</b>.</p><p>Ekaterina Węgierska (Katalina lub Katarzyna, w. Katalin, podłoga.</p>", "Kylie": "<p>Kylie to debiutancki album australijskiej piosenkarki Kylie Minogue, wydany 4 lipca 1988 roku. Dziewięć z dziesięciu piosenek zestawu zostało napisanych przez znane producencko-trio Stoka, Aitken i Waterman.</p>", "Katherina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Katerina</b>.</p><p>Katerina - żeńskie imię, fonetyczny wariant nazwiska Ekaterina.</p>", "Krisztina": "<p>Krisztina może odnosić się do: Krisztina Barta (ur. 1991), węgierskiej tancerki na lodzie Krisztina Bodri (ur. 1986), królowej piękności, która reprezentowała Węgry w Miss World 2007 w Chinach Krisztina Csáky (1654-1723) węgierska hrabina Krisztina Chzakó (ur. 1978), były węgierka pateruska figurna Krisztina Egerszegi (ur. 1974), węgarska była pływaczka rekordów świata i węgielska mistrzowa olimpijska Krisztina Fazekas (ur. 1980), węgiaczka sprint...</p>", "Krzesisława": "<b>Krzesisława</b>, <b>Krzesława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sława</i>. Znaczenie imienia: „odnawiająca sławę”. W zapisach staropolskich zachowała się krótsza forma <b>Krzesława</b> i zdrobniała <b>Krzechna</b> (1388 rok).", "Khalida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khalid</b>.</p><p>Khalid Donnel Robinson - amerykański piosenkarz, laureat i nominac wielu nagród muzycznych.</p>", "Kala": "<p>Kala - drugi album studiowej brytyjskiej piosenkarki Maya, wydany 8 sierpnia 2007 roku. Album został nagrany w drodze w 2006 roku, kiedy M. I. A.</p>", "Kajetana": "<b>Kajetana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Kajetan\" target=\"_blank\" rel=\"noopener noreferrer\">Kajetan</a>. Wywodzi się od słowa oznaczającego „pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Gaeta\" target=\"_blank\" rel=\"noopener noreferrer\">Kajety</a>”, miasta w <a href=\"https://pl.wikipedia.org/wiki/Italia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Italii</a>. Patronką tego imienia jest bł. Kajetana Sterni. Na Kresach imię to było szczególnie związene z mniejszością <a href=\"https://pl.wikipedia.org/wiki/Ormianie_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańską</a>.", "Katerine": "Jej pierwszy album <i>Katerine</i> ukazał się w listopadzie 2005 roku. Znajduje się na nim hit <i>Here Come All The Boys</i>. W roku 2006 otrzymała 2 duńskie nagrody <i>Best Female Artist</i> oraz <i>Best Music Video National</i>. Rok później ukazały się jej kolejne utwory <i>Take Me Home</i> oraz <i>Catfight</i>. Następny rok przyniósł artystce występ w belgijskim odpowiedniku programu Gwiazdy tańczą na lodzie - Sterren op het Ijs. Między artystką a wytwórnią jej płyt doszło do nieporozumień, w wyniku których zmieniła wytwórnię na Mostiko.", "Kasja": "<b>Kasja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od łacińskiej nazwy rodu Kasjuszy (<i>Cassius</i>). Wśród patronów – czterech świętych.", "Korneliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kornelia</b>.</p><b>Kornelia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Kornel</a>, <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusz</a> i <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Korneli</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliuszy</a>. Imię to było znane już w starożytności. W Polsce nadawane co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1770\" target=\"_blank\" rel=\"noopener noreferrer\">1770</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Kornelia w 2017 r. zajmowała 25. miejsce w grupie imion żeńskich.", "Karmina": "Ekstrakt koszenili to ciemnoczerwony płyn, a po wysuszeniu – proszek. Produkt handlowy barwnika występuje w połączeniu z <a href=\"https://pl.wikipedia.org/wiki/Kation\" target=\"_blank\" rel=\"noopener noreferrer\">kationami</a> <a href=\"https://pl.wikipedia.org/wiki/Jon_amonowy\" target=\"_blank\" rel=\"noopener noreferrer\">amonu</a>, wapnia, sodu i potasu, pojedynczo lub w kombinacjach. Może także zawierać materiał <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82ka\" target=\"_blank\" rel=\"noopener noreferrer\">białkowy</a> pochodzący z innych <a href=\"https://pl.wikipedia.org/wiki/Owady\" target=\"_blank\" rel=\"noopener noreferrer\">owadów</a>.", "Keiko": "<b>Keiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;けいこ, ケイコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kathrine": "<p>Katherine (), również pisowana jako Catherine i inne warianty, jest imieniem żeńskim. Nazwa i jej warianty są popularne w krajach, w których istnieje duża populacja chrześcijańska, ze względu na związki z jedną z najwcześniejszych świętych chrześcijan, Kataryną z Aleksandrii.</p>", "Khloe": "<p>Chloe (grek. Χλόη), również pisowana Chloë, Chlöe lub Chloé, jest imieniem kobiece, które w greckim znaczy \"kwiecie\" lub \"płodność\". Nazwa ostatecznie pochodzi, przez grecki, z protoindoeuropejskiego korzenia * ⁇ helh3-, który odnosi się do kolorów żółtego i zielonego.</p>", "Kaliksta": "<b>Kaliksta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kalikst\" target=\"_blank\" rel=\"noopener noreferrer\">Kalikst</a>. Istnieje kilka świętych katolickich o tym imieniu.", "Ksaweryna": "<b>Ksawera</b>, <b>Ksaweryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ksawery\" target=\"_blank\" rel=\"noopener noreferrer\">Ksawery</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Franciszka_Ksawera\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszka Ksawera</a> Cabrini.", "Katelyn": "<p>Caitlin to żeńskie imię pochodzenia irlandzkiego. Historycznie irlandzka nazwa Caitlín była anglicizowana jako Cathleen lub Kathleen.</p>", "Kaori": "<b>Kaori</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かおり, カオリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Keti": "<p>Qeti jest miastem w prowincji Shirak w Armenii. W 2011 roku liczba ludności wynosiła 1095 osób.</p>", "Kasylda": "<b>Kasylda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od imienia <a href=\"https://pl.wikipedia.org/wiki/Kasja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasja</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Kasylda_z_Toledo\" target=\"_blank\" rel=\"noopener noreferrer\">Kasylda z Toledo</a>.", "Kamela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kamel</b>.</p><p>Kamel (arabski: كامل) to imię, które oznacza doskonałe lub doskonałe. Może odnosić się do:</p>", "Kaitlyn": "<p>Caitlin to żeńskie imię pochodzenia irlandzkiego. Historycznie irlandzka nazwa Caitlín była anglicizowana jako Cathleen lub Kathleen.</p>", "Krysia": "<p>Krysia to kobiece imię, diminutiw Krystyna. Znani ludzie z nazwiska to: Krysia Kocjan (1953-2007), członek Natural Acoustic Band Krysia Nowak (urodzony 1948), brytyjski malarz i projektant pochodzenia polskiego Krysia Osostowicz (urodzona 1960), brytyjska skrzypka</p>", "Kaira": "<p>Kaira jest pająkiem z rodziny Araneidae.</p>", "Konkordia": "<b>Konkordia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Oznacza harmonię, pokój. Imię to nosiła jedna z <a href=\"https://pl.wikipedia.org/wiki/Concordia_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">bogiń</a> w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a>.", "Kalista": "<b>Kalista</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego \"najpiękniejsze\". Jest odpowiednikiem męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Kalikst\" target=\"_blank\" rel=\"noopener noreferrer\">Kalikst</a>. Istnieją dwie święte o tym imieniu.", "Kata": "<b>Kata (układ formalny)</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;型, 形&#32;<i>kata</i>&#59; standardowa forma ruchu, postawy itp. w sztukach walki i sporcie) – japońskie słowo oznaczające wysoce sformalizowany rodzaj ćwiczeń stosowanych w wielu tradycyjnych <a href=\"https://pl.wikipedia.org/wiki/Sztuki_walki\" target=\"_blank\" rel=\"noopener noreferrer\">sztukach i sportach walki</a>, szczególnie z grupy <a href=\"https://pl.wikipedia.org/wiki/Bud%C5%8D\" target=\"_blank\" rel=\"noopener noreferrer\">budō</a>, jak również <a href=\"https://pl.wikipedia.org/wiki/Taekwondo\" target=\"_blank\" rel=\"noopener noreferrer\">taekwondo</a> (gdzie noszą one nazwę <i>tul</i> w wersji <a href=\"https://pl.wikipedia.org/wiki/International_Taekwon-Do_Federation\" target=\"_blank\" rel=\"noopener noreferrer\">ITF</a>, <i>poomse</i> w <a href=\"https://pl.wikipedia.org/wiki/World_Taekwondo_Federation\" target=\"_blank\" rel=\"noopener noreferrer\">WTF</a> a <i>hyeong</i> w niektórych innych organizacjach), <a href=\"https://pl.wikipedia.org/wiki/Taijiquan\" target=\"_blank\" rel=\"noopener noreferrer\">taijiquan</a> i innych. Są to sekwencje technik ataku i obrony, połączone z określonym poruszaniem, przyjęciem ściśle określonej pozycji i sposobu oddychania. <i>Kata</i> są bardzo ważną częścią programów nauczania dla wielu <a href=\"https://pl.wikipedia.org/wiki/Sztuki_walki\" target=\"_blank\" rel=\"noopener noreferrer\">sztuk</a> i <a href=\"https://pl.wikipedia.org/wiki/Sport_walki\" target=\"_blank\" rel=\"noopener noreferrer\">sportów walki</a>, a dla niektórych, zwłaszcza tych, gdzie kontakt broni z ciałem przeciwnika stanowiłby realne zagrożenie, stanowią ćwiczenia podstawowe.", "Krasimira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krasimir</b>.</p><p>Krasimir (bułgarski: Красимир) jest powszechną nazwą męską w Bułgarii. Pochodzi od słów krasi \"piękno, ozdoba\" i mir \"pokój\" lub \"świat\".</p>", "Klaudiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Klaudia</b>.</p><b>Klaudia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Claudia</em>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego. Wywodzi się od nazwy rzymskiego rodu Klaudiuszów. Imię <a href=\"https://pl.wikipedia.org/wiki/Klaudia_(z_Klaudiusz%C3%B3w)\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudia</a> nosiły wszystkie kobiety z tego rodu. Odnotowano trzy święte katolickie o tym imieniu. Istnieje też pochodna forma tego imienia: <a href=\"https://pl.wikipedia.org/wiki/Klaudyna\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudyna</a>.", "Ksena": "<p>Avksenty (rosyjski: Авксе́нтий) to rosyjskie imię chrześcijańskie męskie. Nazwa pochodzi od greckiego imienia Auxentios, które z kolei pochodzi od słowa auxano, co oznacza wzrost, wzrost.</p>", "Kirsty": "<p>Kirsty lub Kirstie to kobiece imię i nazwa. Jest szkockim diminutiwem Christine w krajach anglojęzycznych i jest również powiązany z Kirsten - skandynawską wersją Christine.</p>", "Käthe": "<p>Käthe lub Kathe to imiono kobiece, często krótka forma Katharina. Wśród znanych osób z tej nazwy są: Käthe Dorsch (1890-1957), niemiecka aktorka Käthe Gold (1907-1997), austriacka aktorka Kätthe Grasegger, później Deuschl (1917-2001), niemiecka narciarka alpa Kathe Green (urodzona w 1944 roku), amerykańska aktorka, modelka i śpiewaczka Käthe Haack (1897-1986), niemiecki aktorka Ketthe Hoffmann, niemiecki botanik, który odkrył i katalogizował wiele gatunków roślin w Nowym...</p>", "Klemensa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Klemens</b>.</p><b>Klemens</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „człowiek o łagodnym usposobieniu”, „delikatny”, „pobłażliwy”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Klemencja\" target=\"_blank\" rel=\"noopener noreferrer\">Klemencja</a>.", "Kapitolina": "<b>Kapitolina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od słowa oznaczającego lud łaciński, który mieszkał na <a href=\"https://pl.wikipedia.org/wiki/Kapitol\" target=\"_blank\" rel=\"noopener noreferrer\">Kapitolu</a>. Patronką tego imienia jest św. Kapitolina (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>), wspominana razem ze św. Eroteidą.", "Kaarina": "<p>Kaarina (fin. Kaarina jest szwedzka.</p>", "Kameliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kamelia</b>.</p><b>Kamelia</b> – imię żeńskie pochodzące od nazwy <a href=\"https://pl.wikipedia.org/wiki/Kamelia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">kwitnącego krzewu</a> nazwanego na cześć botanika i misjonarza <a href=\"https://pl.wikipedia.org/wiki/Georg_Joseph_Kamel\" target=\"_blank\" rel=\"noopener noreferrer\">Georga Josepha Kamela</a>.", "Kana": "<b>Kana</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かな, カナ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Krystianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krystiana</b>.</p><b>Krystiana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Krystian\" target=\"_blank\" rel=\"noopener noreferrer\">Krystian</a>, które powstało poprzez dodanie przyrostka <i>-ianus</i>, oznaczającego przynależność lub pochodzenie, do łacińskiego imienia <i><a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Christinus/Cristinus</a></i>. Oznacza „chrześcijanka, należąca do Chrystusa, Chrystusowa”. Imię to jest poświadczone w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, w formie <i><b>Krzys(z)tyjana</b></i>, <i><b>Krystyjana</b></i>. Staropolskie formy pochodne: Krczona, Krzczona, Chryścijanica, Chrzczonka.", "Karoliina": "<p>Karoliina to fińskie i estyckie imię pochodzące od Karola. Do osób z nazwiskiem należą: Karoliina Blackburn (ur. 1972), fińska aktorka i bokserka Muay Thai Karoliina Kallio (ur. 1979), fińska piosenkarka i aktorka Karoliina Lundahl (ur. 1968), fińskie ciężarosta Karoliina Rantamäki (ur. 1978), fińską hokejistka lodowa</p>", "Krystyna Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kalinka": "<p>⁇ Kalíнка ⁇ (od nazwy rośliny kaliny; znana również jako ⁇ Kали́нка-Mали́нka ⁇) - rosyjska piosenka napisana przez Iwan Petrovic Larionowa w stylu ludowym. Czasami błędnie uważa się za folk.</p>", "Kaliopi": "<p>Kaliopii (ur. Kaliopi Bukle; arum.</p>", "Karuna": "W <a href=\"https://pl.wikipedia.org/wiki/Emocja\" target=\"_blank\" rel=\"noopener noreferrer\">emocjonalnym</a> rozumieniu ma znaczenie <a href=\"https://pl.wikipedia.org/wiki/Empatia\" target=\"_blank\" rel=\"noopener noreferrer\">empatycznej</a> <a href=\"https://pl.wikipedia.org/wiki/Dobro\" target=\"_blank\" rel=\"noopener noreferrer\">dobroci</a> okazywanej <a href=\"https://pl.wikipedia.org/wiki/Cierpienie\" target=\"_blank\" rel=\"noopener noreferrer\">cierpiącym</a>. W rozumieniu funkcjonalnym jest szlachetną aktywnością, jedną z <a href=\"https://pl.wikipedia.org/wiki/Paramita\" target=\"_blank\" rel=\"noopener noreferrer\">dziesięciu paramit</a> pochodzących z buddyjskiej szkoły <a href=\"https://pl.wikipedia.org/wiki/Theravada\" target=\"_blank\" rel=\"noopener noreferrer\">therawady</a>. Na duchowym poziomie jest konsekwencją i uzupełnieniem szlachetnego stanu umysłu określanego jako <a href=\"https://pl.wikipedia.org/wiki/Metta\" target=\"_blank\" rel=\"noopener noreferrer\">kochająca życzliwość</a>.", "Klavdiya": "<p>Klavdiya to imię. Znanymi osobami z nazwiska są: Klavdiya Afanasyeva (ur. 1996), rosyjska biegaczka Klavdiya Blinova (ur. 1920-1988), rosyjski pilot bojowy Klavdiya Boyarskikh (1939-2009), rosyjska narciarza na targach Klavdiya Gadyuchkina (1910-2025), rosyjskie supersetnik Klavdiya Kildsheva (1917-1994), rosyjski i rosyjski inżynier testowy Klavdija Koženkova (ur., 1949), litewski rudzki rudzki rower olimpijski Klavdiya Kuzmina...</p>", "Kristiana": "<p>Kristiana to kobiece imię, odpowiednik Kristian. Znanymi osobami z nazwiska są: Kristiana Gregory Kristiana Levy Kristiana Manu'a Kristiana Petlichka Kristiana Rae Colón</p>", "Kameliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kamelia</b>.</p><b>Kamelia</b> – imię żeńskie pochodzące od nazwy <a href=\"https://pl.wikipedia.org/wiki/Kamelia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">kwitnącego krzewu</a> nazwanego na cześć botanika i misjonarza <a href=\"https://pl.wikipedia.org/wiki/Georg_Joseph_Kamel\" target=\"_blank\" rel=\"noopener noreferrer\">Georga Josepha Kamela</a>.", "Khrystyna-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Kalyani": "<p>Kalyani to miasto i dzielnica w hrabstwie Nadia w stanie Bengala Zachodniego, India.</p>", "Kristy": "<p>Kristy to kobiece imię pochodzące z łacińskiego, co oznacza \"pośladowcy Chrystusa\". Znanymi osobami z imieniem są: Kristy Cates (ur. 1977), amerykańska aktorka Kristy Lee Cook (ur. 1984), amerykański piosenkarz Kristy Curry (ur. 1966), amerykańskiego trenerki koszykówki Kristy Hanson (ur. 1981), amerykacka piosenkarka-powieściosenka Kristy Hawkins (ur. 1980), amerykajska kulturystka Kirsty Jones (ur. 2000), brytyjska ofiara morderstwa kobiety Kristy Kowal (ur. 1978),...</p>", "Katerin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Katerina</b>.</p><p>Katerina - żeńskie imię, fonetyczny wariant nazwiska Ekaterina.</p>", "Kyoko": "<p>Kyoko, Kyoko, Kyouko lub Kyohko (きょうこ, キョウコ, 京子) jest bardzo powszechną kobiecą japońską nazwą, nie należy mylić z Kiyoko.</p>", "Kiliana": "<b>Kiliana</b>, <b>Kilia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Kilian\" target=\"_blank\" rel=\"noopener noreferrer\">Kilian</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, od <i>ceallach</i> oznaczającego \"wojna\" lub <i>ceall</i> oznaczającego \"kościół\". Patronem tego imienia jest św. Kilian.", "Katryna": "<p>Katryna to kobieca warianta nazwy Katrina. Znanymi osobami z nazwiska są: Katryna Esposito (ur. 2000), maltańska judoka Katryna Gaither (ur. 1975), amerykańska piłkarka koszykówki Katryna Nields, amerykańska artystka muzyczna</p>", "Kornella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kornela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kornel</b>.</p><b>Kornel</b>, <b>Korneliusz</b>, <b>Korneli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Cornelii</i> (<i>Korneliuszy</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusze Cynna</a>). Istnieją różne hipotezy pochodzenia wspomnianej nazwy rodowej; wywodzi się ją bądź to ze słowa <i>cornu</i> („róg”), bądź to <i>cornus</i> („<a href=\"https://pl.wikipedia.org/wiki/Dere%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dereń</a>”), bądź to od nazwy pola <i>Corne</i> w <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a>. W dawnej Polsce zapisywane od <a href=\"https://pl.wikipedia.org/wiki/1402\" target=\"_blank\" rel=\"noopener noreferrer\">1402</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> formie <i>Cornelius</i> oraz od <a href=\"https://pl.wikipedia.org/wiki/1412\" target=\"_blank\" rel=\"noopener noreferrer\">1412</a> roku w formach pochodnych Kornosz, Kornasz, Korna (masc.), Kornosza (masc.), Kornoszek i ze zdrobnieniami Nela (masc.), Nelka (masc.), Nelko.", "Konstanze": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Constanze</b>.</p><p>Constanze to kobiece imię związane z Constance. Jest nosiona przez: Constanze Backes, niemiecką soprankę operową i koncertową Constanze Blum (ur. 1972), niemieckiego narciarza na targach Constanze Engelbrecht (1950-2000), niemieńską aktorkę Constanze Feine (ur. 1999), niemieczną kanowistkę Constanse Geiger (1835-1890), austriackiego pianisty, aktorki, aktorki teatralnej, kompozytorki i piosenkarki Constanze Gensel (ur. 1969 lub 1970), figurowego paterzystka, który rywalizował w zawodnictwie wschodniej...</p>", "Krescencja": "<b>Krescencja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od nazwy rodu, która z kolei pochodzi od słowa <i>crescere</i> – „wzrastać, narastać”. Wśród patronów – św. <a href=\"https://pl.wikipedia.org/wiki/Maria_Krescencja_H%C3%B6ss\" target=\"_blank\" rel=\"noopener noreferrer\">Maria Krescencja Höss</a> (<a href=\"https://pl.wikipedia.org/wiki/1682\" target=\"_blank\" rel=\"noopener noreferrer\">1682</a>–<a href=\"https://pl.wikipedia.org/wiki/1744\" target=\"_blank\" rel=\"noopener noreferrer\">1744</a>).", "Kanako": "<b>Kanako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かなこ, カナコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kornelija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kornelia</b>.</p><b>Kornelia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Kornel</a>, <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliusz</a> i <a href=\"https://pl.wikipedia.org/wiki/Kornel\" target=\"_blank\" rel=\"noopener noreferrer\">Korneli</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Korneliusze_Cynna\" target=\"_blank\" rel=\"noopener noreferrer\">Korneliuszy</a>. Imię to było znane już w starożytności. W Polsce nadawane co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1770\" target=\"_blank\" rel=\"noopener noreferrer\">1770</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Kornelia w 2017 r. zajmowała 25. miejsce w grupie imion żeńskich.", "Karthika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karthik</b>.</p><p>Karthik lub Kartik może odnosić się do:</p>", "Karen Dayana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Katriona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Catriona</b>.</p><p>Catriona to imiona żeńskie w języku angielskim. Jest anglicyzacją irlandzkiej Caitríona lub szkockiej gaelickiej Catrìona, które są formami angielskiej Katherine.</p>", "Kirana": "<p>Anggun (lub Anggun, całkowicie - Anggun Chipta Sasmi, Anggun Cipta Sasmi; urodzony 29 kwietnia 1974, w Jakarta, Indonezja, na Bali oznacza to ⁇ Gracja, urodzona w marzeniach ⁇ .) - indonezyjska pop-piewnica i autorka piosenek w stylu RnB, obecnie mieszkająca we Francji.</p>", "Khánh Linh": "<p>Faum Khánh Linh (ur. 29 sierpnia 1983), znana jako Khánh Lin, jest wietnamską piosenkarką, która zdobyła trzy nominacje do Nagrody Dedykowania. Jako siostra zmarłego muzyka Ngọc Châu i córka piosenkarza Vũ Dậu, była znana jako osoba o wysokim i jasnym głosu.</p>", "Khadijah": "<p>Khadija, Khadeeja lub Khadijah (arabsko: خديجة, romanized: Khadīja) to arabskie nazwisko kobiece, nazwisko Khadija bint Khuwaylid, pierwszej żony islamskiego proroka Muhammada. W 1995 roku było to jedno z trzech najpopularniejszych arabskich nazw kobiet w świecie muzułmańskim, wraz z Fatimą i Aishą.</p>", "Kumiko": "<b>Kumiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;くみこ, クミコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Khánh Vy": "<p>Trần Khánh Vy (ur. 21 sierpnia 1999), znana jako Khánh Vy, jest wietnamską blogerką, YouTuberką i telewizyjną programistką.</p>", "Kasha": "<p>Kasha (jap. 火車, Hán Việt oznacza \"odległe ogień\", inaczej spisywane 化車, Hân Việt oznacza \"dalne miejsce\") jest rodzajem demonów w japońskiej pojęciu ludowej, które są uważane za kradzież ciał ludzi, którzy tworzyli zło podczas życia.</p>", "Keisha": "<p>Keisha to żeńskie imię, które ma wiele znaczeń w różnych językach, takich jak \"Umiłowany\", \"Zwracanie do serca Boga\" lub \"Cassia Tree\". W języku hebrajskim Keisha prawdopodobnie pochodzi od hebrajskiej nazwy Keziah, która oznacza \"kość cynamonu\".</p>", "Krzesława": "<b>Krzesisława</b>, <b>Krzesława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sława</i>. Znaczenie imienia: „odnawiająca sławę”. W zapisach staropolskich zachowała się krótsza forma <b>Krzesława</b> i zdrobniała <b>Krzechna</b> (1388 rok).", "Karyn": "<p>Karyn to angielskie imię i może odnosić się do:</p>", "Kani": "<p>Kani maranjandu (lat. Kani maranjand) - rodzaj krabów lądowych z rodziny Gecarcinucidae. Do tej pory obserwowano go tylko w lasach Zachodnich Gatow w Kerali w Indiach.</p>", "Keerthana": "<p>Kirtana (sanskrit: कीर्तन; IAST: Kīrtana), również przetłumaczona jako Kiirtan, Kirtan lub Keertan, jest słowem sanskryckim, które oznacza \"powiedzenie, recyting, opowiadanie, opis\" pomysłu lub historii, szczególnie w religii indyjskich. Odnosi się również do gatunku religijnych sztuk spektaklowych, oznaczających muzyczną formę narracji, wspólnego recytowania lub śpiewu oddanego, szczególnie duchowych lub religijnych idei, pochodzących z subkontynentu indyjskiego.</p>", "Krzysława": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krzysław</b>.</p><b>Krzesisław</b>, <b>Krzecsław</b>, <b>Krzesław</b>, <b>Krzysław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Krzesi-</i> („wskrzeszać, przywracać do życia, podnosić”) i <i>-sław</i> („sława”). Znaczenie imienia: „odnawiający sławę”.", "Kula": "<p>Kula jest miastem w prowincji Vidin, Bungaria. W 2011 roku liczba ludności wynosi 3158 osób.</p>", "Kezia": "<p>Kezia - debiutancki album kanadyjskiego zespołu metalcore Protest the Hero, wydany w 2005 roku.</p>", "Kaitlin": "<p>Caitlin to żeńskie imię pochodzenia irlandzkiego. Historycznie irlandzka nazwa Caitlín była anglicizowana jako Cathleen lub Kathleen.</p>", "Kimia": "<p>Kimia to starożytne greckie słowo i żeńskie imię w języku perskim. Oznacza elixir życia, alchemię lub kamienie filozoficzne.</p>", "Kerly": "<p>Kerly to kobiece imię. Mieszkańcy imienia Kerly to: Kerly Théus (ur. 1999), haityjski piłkarz Kerly Santos (ur. 1970), brazylijczyk w siatkówce</p>", "Karoll": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karol</b>.</p><b>Karol</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankijskiego</a> oznaczające człowieka mężnego lub wojownika. Staroskandynawskie znaczenie – „człowiek, mąż”. Imię jest również rozpowszechnione w krajach latynoskich.", "Karina-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karina</b>.</p><b>Karina</b>, <b>Karyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z jęz. niemieckiego; forma zdrobniała od imienia <i>Katarina</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Katarzyna\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna</a>). Inna hipoteza mówi, że wywodzi się od słowa <i>cara</i>, które po <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacinie</a> oznacza \"kochana, droga\" lub w galickim \"przyjaciel\". Jeszcze inna hipoteza mówi, że pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">konstelacji</a> <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Kila\" target=\"_blank\" rel=\"noopener noreferrer\">Kil</a>, nazwanej w związku kilem statku <a href=\"https://pl.wikipedia.org/wiki/Jazon_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jazona</a>.", "Karen Lorena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Krystyna Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kloe": "<p>Chloe (grek. Χλόη), również pisowana Chloë, Chlöe lub Chloé, jest imieniem kobiece, które w greckim znaczy \"kwiecie\" lub \"płodność\". Nazwa ostatecznie pochodzi, przez grecki, z protoindoeuropejskiego korzenia * ⁇ helh3-, który odnosi się do kolorów żółtego i zielonego.</p>", "Kwiatosława": "<b>Florianna</b>, <b>Floriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Florian\" target=\"_blank\" rel=\"noopener noreferrer\">Florian</a>, które z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>florus</i> – „kwitnący” i oznacza „należący do <i>Florusa</i>”. <b>Florianna</b> jest nadawana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>, a po raz pierwszy zapisana była w formie <i><b>Floryjana</b></i>. Zanotowano także zdrobnienie Floszka, oraz drugie, Tworka, które mogło pochodzić od Florianny z substytucją polską (jak Florian → Tworzyjan), lub też od imion rodzimych zaczynających się na <i>Tworzy-</i>.", "Kolet": "Był długim <a href=\"https://pl.wikipedia.org/wiki/Kaftan\" target=\"_blank\" rel=\"noopener noreferrer\">kaftanem</a> lub płaszczem z długimi <a href=\"https://pl.wikipedia.org/wiki/R%C4%99kaw_(ubi%C3%B3r)\" target=\"_blank\" rel=\"noopener noreferrer\">rękawami</a> (lub bez), rozszerzanym w części dolnej. Zwykle wkładano go pod <a href=\"https://pl.wikipedia.org/wiki/Kirys\" target=\"_blank\" rel=\"noopener noreferrer\">kirys</a> (np. <a href=\"https://pl.wikipedia.org/wiki/Rajtaria\" target=\"_blank\" rel=\"noopener noreferrer\">rajtaria</a>, arkebuzeria, <a href=\"https://pl.wikipedia.org/wiki/Pikinierzy\" target=\"_blank\" rel=\"noopener noreferrer\">pikinierzy</a>) lub na wierzch jako rodzaj lżejszego ubioru ochronnego (np. u <a href=\"https://pl.wikipedia.org/wiki/Muszkieter\" target=\"_blank\" rel=\"noopener noreferrer\">muszkieterów</a>, <a href=\"https://pl.wikipedia.org/wiki/Dragoni\" target=\"_blank\" rel=\"noopener noreferrer\">dragonów</a>). Nazwa pochodzi od wywijanego skórzanego <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%82nierz\" target=\"_blank\" rel=\"noopener noreferrer\">kołnierza</a>.", "Kaho": "<b>Kaho</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かほ, カホ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Katarzyna Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Katarzyna</b>.</p><b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Kasumi": "<b>Kasumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かすみ, カスミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kandyda": "<b>Kandyda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Kandyd_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kandyd</a>, oznaczające \"jasna, błyszcząca, biała\", czyli \"dziecko o jasnych włosach\" lub \"dziecko o jasnej <a href=\"https://pl.wikipedia.org/wiki/Karnacja\" target=\"_blank\" rel=\"noopener noreferrer\">cerze</a>\"; jeden z najpopularniejszych <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomków</a> rzymskich. W Polsce notowane od <a href=\"https://pl.wikipedia.org/wiki/1396\" target=\"_blank\" rel=\"noopener noreferrer\">1396</a> roku.", "Karmelina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karmel</b>.</p>Jest głównym składnikiem niektórych rodzajów <a href=\"https://pl.wikipedia.org/wiki/Cukierek\" target=\"_blank\" rel=\"noopener noreferrer\">cukierków</a>, <a href=\"https://pl.wikipedia.org/wiki/Barwniki_spo%C5%BCywcze\" target=\"_blank\" rel=\"noopener noreferrer\">barwnikiem</a> napojów typu <a href=\"https://pl.wikipedia.org/wiki/Cola\" target=\"_blank\" rel=\"noopener noreferrer\">cola</a>, ciemnego <a href=\"https://pl.wikipedia.org/wiki/Pieczywo\" target=\"_blank\" rel=\"noopener noreferrer\">pieczywa</a>, <a href=\"https://pl.wikipedia.org/wiki/Czekolada\" target=\"_blank\" rel=\"noopener noreferrer\">czekolad</a>, <a href=\"https://pl.wikipedia.org/wiki/Lody\" target=\"_blank\" rel=\"noopener noreferrer\">lodów</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCem\" target=\"_blank\" rel=\"noopener noreferrer\">dżemów</a> i <a href=\"https://pl.wikipedia.org/wiki/Jogurt\" target=\"_blank\" rel=\"noopener noreferrer\">jogurtów</a>. Dodatek karmelu do żywności jest oznaczany przez kod E150 i literę wyróżniającą typ karmelu.", "Kimiko": "<b>Kimiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;きみこ, キミコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Klementina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Klement</b>.</p><b>Klemens</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „człowiek o łagodnym usposobieniu”, „delikatny”, „pobłażliwy”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Klemencja\" target=\"_blank\" rel=\"noopener noreferrer\">Klemencja</a>.", "Kassiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kasia</b>.</p><b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Kazumi": "<b>Kazumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かずみ, カズミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Klarisa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Klarysa</b>.</p><b>Klarysa</b> – imię żeńskie, pokrewne imieniu <a href=\"https://pl.wikipedia.org/wiki/Klara\" target=\"_blank\" rel=\"noopener noreferrer\">Klara</a>.", "Kim Ngân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Kadija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kadia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kadi</b>.</p>Od nazwy tej pochodzi <a href=\"https://pl.wikipedia.org/wiki/Alkad\" target=\"_blank\" rel=\"noopener noreferrer\">alkad</a>.", "Karen Julieth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Karime": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karim</b>.</p><b>Karim</b> (<b>كريم</b>) – imię pochodzenia arabskiego, jest czterdziestym trzecim z „Najpiękniejszych imion Allaha”. Oznacza dosłownie „hojny”.", "Kim Oanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Keya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Key</b>.</p><b>Key</b> – japońskie studio tworzące <a href=\"https://pl.wikipedia.org/wiki/Powie%C5%9B%C4%87_wizualna\" target=\"_blank\" rel=\"noopener noreferrer\">powieści wizualne</a>, będące formalnie marką wydawcy gier komputerowych <a href=\"https://pl.wikipedia.org/wiki/Visual_Arts\" target=\"_blank\" rel=\"noopener noreferrer\">Visual Arts</a>. Jest jednym z głównych przedstawicieli nurtu <i>nakige</i>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;泣きゲ&#59; „gry wywołujące łzy”). Pierwszym tytułem studia była wydana w 1999 roku <a href=\"https://pl.wikipedia.org/wiki/Eroge\" target=\"_blank\" rel=\"noopener noreferrer\">gra dla dorosłych</a> <i><a href=\"https://pl.wikipedia.org/wiki/Kanon_(gra_komputerowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Kanon</a></i>. W 2004 roku wydana została pierwsza produkcja studia przeznaczona dla wszystkich grup wiekowych – <i><a href=\"https://pl.wikipedia.org/wiki/Clannad_(gra_komputerowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Clannad</a></i>. Key współpracowało ze studiem animacyjnym <a href=\"https://pl.wikipedia.org/wiki/P.A._Works\" target=\"_blank\" rel=\"noopener noreferrer\">P.A. Works</a> oraz firmą <a href=\"https://pl.wikipedia.org/wiki/Aniplex\" target=\"_blank\" rel=\"noopener noreferrer\">Aniplex</a> przy produkcji seriali <a href=\"https://pl.wikipedia.org/wiki/Anime\" target=\"_blank\" rel=\"noopener noreferrer\">anime</a> <i><a href=\"https://pl.wikipedia.org/wiki/Angel_Beats!\" target=\"_blank\" rel=\"noopener noreferrer\">Angel Beats!</a></i> (2010), <i><a href=\"https://pl.wikipedia.org/wiki/Charlotte_(anime)\" target=\"_blank\" rel=\"noopener noreferrer\">Charlotte</a></i> (2015) i <i><a href=\"https://pl.wikipedia.org/wiki/Kami-sama_ni_natta_hi\" target=\"_blank\" rel=\"noopener noreferrer\">Kami-sama ni natta hi</a></i> (2020).", "Kim Chi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Khady": "<p>Khady to kobiece imię powszechne w Senegal. Wśród znanych osób z tej nazwy są: Khady Diallo (ur. 1955), Frankofil i inżynier kultury Khaddy Dieng lub Ndeye Dieng (ur. 1994), Senegalijski piłkarz koszykówki Khady Diop (ur. 1971), Senegalejski piłka koszykówka Khady Hane (ur. 1962), Senegalec Khaddy Koita (ur. 1959), Senegalski aktywista przeciwko przemocy wobec kobiet i FGM Khady Yacine ...</p>", "Kayoko": "<b>Kayoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かよこ, カヨコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kasiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kasia</b>.</p><b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Korneliya": "<p>Kornelia to kobiece imię, podobne do Kornelia.</p>", "Kaiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kaia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kai</b>.</p><b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Karolina-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karolina</b>.</p><b>Karolina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>. Innym żeńskim odpowiednikiem imienia Karol jest <a href=\"https://pl.wikipedia.org/wiki/Karola\" target=\"_blank\" rel=\"noopener noreferrer\">Karola</a>. Imię Karolina jest pochodzenia starogermańskiego, od słowa charal, carl.", "Kaede": "<b>Kaede</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;かえで, カエデ, 楓) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Kallina": "<b>Kalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnym pochodzeniu, stanowiące być może przekształcone na gruncie białoruskim imię <a href=\"https://pl.wikipedia.org/wiki/Akwilina\" target=\"_blank\" rel=\"noopener noreferrer\">Akwilina</a>, lub powstałe na gruncie wschodniosłowiańskim pod wpływem wyrazu <a href=\"https://pl.wikipedia.org/wiki/Kalina_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">kalina</a>. Zgodnie z rosyjskimi źródłami, <i><b>Kalinka</b></i> to zdrobnienie zarówno męskie od <a href=\"https://pl.wikipedia.org/wiki/Kalinik\" target=\"_blank\" rel=\"noopener noreferrer\">Kalinika</a>, jak i żeńskie – od żeńskiego rosyjskiego odpowiednika tego imienia, tj. <i>Kallinikii</i> (<i>Каллиникня</i>). Należy też podkreślić, iż forma Kalina spotykana była jako męska forma skrócona imienia <a href=\"https://pl.wikipedia.org/wiki/Kalinik\" target=\"_blank\" rel=\"noopener noreferrer\">Kalinik</a> już w źródłach pochodzących z lat <a href=\"https://pl.wikipedia.org/wiki/1479\" target=\"_blank\" rel=\"noopener noreferrer\">1479</a>–<a href=\"https://pl.wikipedia.org/wiki/1584\" target=\"_blank\" rel=\"noopener noreferrer\">1584</a> z <a href=\"https://pl.wikipedia.org/wiki/Monastyr_So%C5%82owiecki\" target=\"_blank\" rel=\"noopener noreferrer\">monastyru sołowieckiego</a>.", "Karen Tatiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kátia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Katya</b>.</p><p>Katya to kobiece imię. Jest to bardzo popularne imię w Rosji, Ukrainie, Bułgarii, Serbii i Macedonii Północnej.</p>", "Khrystyna-Ivanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Ksenya": "<p>Avksenty (rosyjski: Авксе́нтий) to rosyjskie imię chrześcijańskie męskie. Nazwa pochodzi od greckiego imienia Auxentios, które z kolei pochodzi od słowa auxano, co oznacza wzrost, wzrost.</p>", "Karlina": "<p>Karlina to duńskie, farerskie, norweskie i słoweńskie nazwisko żeńskie, które jest alternatywną formą Karli i krótką formą Karoliny. Karlīna jest łacińskim imieniem żeńskim, które jest kobiecą formą Kārlis.</p>", "Khadijat": "<p>Khadija, Khadeeja lub Khadijah (arabsko: خديجة, romanized: Khadīja) to arabskie nazwisko kobiece, nazwisko Khadija bint Khuwaylid, pierwszej żony islamskiego proroka Muhammada. W 1995 roku było to jedno z trzech najpopularniejszych arabskich nazw kobiet w świecie muzułmańskim, wraz z Fatimą i Aishą.</p>", "Karen Daniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kim Dung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Kalsoom": "<p>Kalsoom (urdu: كلثوم) to pakistańskie kobiece imię. Znanymi osobami z nazwiskiem są: Kalsoom Nawaz Sharif (1950-2018), Pierwsza Pani Pakistanu Kalsoom Perveen (1945-2020), pakistański polityk</p>", "Kulsum": "<p>Kulthum lub Kulsum (arabski: كلثوم) to arabskie nazwisko kobiety. Oznacza to \"kto ma piękną twarz\" lub \"kto rozumie ludzi\".</p>", "Katerinne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Katerine</b>.</p>Jej pierwszy album <i>Katerine</i> ukazał się w listopadzie 2005 roku. Znajduje się na nim hit <i>Here Come All The Boys</i>. W roku 2006 otrzymała 2 duńskie nagrody <i>Best Female Artist</i> oraz <i>Best Music Video National</i>. Rok później ukazały się jej kolejne utwory <i>Take Me Home</i> oraz <i>Catfight</i>. Następny rok przyniósł artystce występ w belgijskim odpowiedniku programu Gwiazdy tańczą na lodzie - Sterren op het Ijs. Między artystką a wytwórnią jej płyt doszło do nieporozumień, w wyniku których zmieniła wytwórnię na Mostiko.", "Kelly Johanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kelly</b>.</p><p>Kelly (ang. Kelly, Kelley, Kellie), początkowo O'Kelly (irl.</p>", "Kristal": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cristal</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Crystal</b>.</p><p>⁇ Crystal ⁇ (rosyjski: Кристал) - piosenka brytyjskiej grupy New Order, wydana na single w 2001 roku w ramach albumu ⁇ Get Ready ⁇ .</p>", "Kaylie": "<p>Kaylee (i jego różne pisowni) to imiona żeńskie. Nazwa jest współczesnym angielskim połączeniem elementów imienia Kay i Lee.</p>", "Kineret": "<p>Kinneret to angielski transliterat Kineret, hebrajska nazwa Morza Galilei, największego jeziora słodkowodnego w Izraelu. Do innych znaczeń Kinneret i Kineret należą:</p>", "Khristyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Kokila": "<b>Kokila</b> – metalowa <a href=\"https://pl.wikipedia.org/wiki/Forma_odlewnicza\" target=\"_blank\" rel=\"noopener noreferrer\">forma odlewnicza</a>, do której wlewa się roztopiony metal (często pod ciśnieniem). Kokila jest formą wielokrotnego użytku. Może być zalewana <a href=\"https://pl.wikipedia.org/wiki/Odlewanie_od%C5%9Brodkowe\" target=\"_blank\" rel=\"noopener noreferrer\">odśrodkowo</a> lub grawitacyjnie.", "Khawla": "<p>Khawlah lub Khawla (arabicko: خولة) to kobiece arabskie imię, co oznacza \"żółta. \"</p>", "Karolyn": "<p>Karolyn to angielskie i szwedzkie imię żeńskie, które jest diminutiwną formą Carolina i Caroline, a także alternatywną formą Karolin. Do wybitnych osób, o których mowa w tej nazwie, należą:</p>", "Karenina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Khadijeh": "<p>Khadija, Khadeeja lub Khadijah (arabsko: خديجة, romanized: Khadīja) to arabskie nazwisko kobiece, nazwisko Khadija bint Khuwaylid, pierwszej żony islamskiego proroka Muhammada. W 1995 roku było to jedno z trzech najpopularniejszych arabskich nazw kobiet w świecie muzułmańskim, wraz z Fatimą i Aishą.</p>", "Kenya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Keny</b>.</p><p>Kenneth to imię pochodzące z języka gaelickiego. Nazwa jest angliczowaną formą dwóch zupełnie różnych gaelijskich nazw: Cainnech i Cináed.</p>", "Kim Lan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Katryn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Katryna</b>.</p><p>Katryna to kobieca warianta nazwy Katrina. Znanymi osobami z nazwiska są: Katryna Esposito (ur. 2000), maltańska judoka Katryna Gaither (ur. 1975), amerykańska piłkarka koszykówki Katryna Nields, amerykańska artystka muzyczna</p>", "Klemencja": "<b>Klemencja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Klemens\" target=\"_blank\" rel=\"noopener noreferrer\">Klemens</a>. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/21_marca\" target=\"_blank\" rel=\"noopener noreferrer\">21&#160;marca</a>.", "Kalia": "<b>Cantedeskia</b>, kalijka, kalia (<i>Zantedeschia</i> Spreng.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Obrazkowate\" target=\"_blank\" rel=\"noopener noreferrer\">obrazkowatych</a>, obejmujący 8 <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a> pochodzących ze środkowo-południowej <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>, z jednym gatunkiem introdukowanym na wszystkich kontynentach z wyjątkiem Antarktydy. Z uwagi na bardzo atrakcyjne kwiatostany i ulistnienie cantedeskie, zarówno gatunki botaniczne, jak i ich <a href=\"https://pl.wikipedia.org/wiki/Kultywar\" target=\"_blank\" rel=\"noopener noreferrer\">kultywary</a>, są szeroko uprawiane na świecie jako <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny_ozdobne\" target=\"_blank\" rel=\"noopener noreferrer\">rośliny ozdobne</a>.", "Kathe": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kate</b>.</p><p>Kate (KDE Advanced Text Editor) - redaktor tekstu w skład środowiska pracy KDE. Rozprzestrzegana jest na podstawie GNU General Public License.</p>", "Kady": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kadi</b>.</p>Od nazwy tej pochodzi <a href=\"https://pl.wikipedia.org/wiki/Alkad\" target=\"_blank\" rel=\"noopener noreferrer\">alkad</a>.", "Kelly Johana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kelly</b>.</p><p>Kelly (ang. Kelly, Kelley, Kellie), początkowo O'Kelly (irl.</p>", "Ksenyia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kseniia</b>.</p><p>Xenia (varianty obejmują Ksenia, Kseniia, Ksenja, Kseniya; pochodzące z greckiego Ξένια xenia, \"gastotliwość\") jest nazwą dla kobiet. Poniższe sekcje zawierają listę znanych osób z jedną z wariantów tej nazwy.</p>", "Karolyne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karolyn</b>.</p><p>Karolyn to angielskie i szwedzkie imię żeńskie, które jest diminutiwną formą Carolina i Caroline, a także alternatywną formą Karolin. Do wybitnych osób, o których mowa w tej nazwie, należą:</p>", "Khadiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khadija</b>.</p><p>Khadija, Khadeeja lub Khadijah (arabsko: خديجة, romanized: Khadīja) to arabskie nazwisko kobiece, nazwisko Khadija bint Khuwaylid, pierwszej żony islamskiego proroka Muhammada. W 1995 roku było to jedno z trzech najpopularniejszych arabskich nazw kobiet w świecie muzułmańskim, wraz z Fatimą i Aishą.</p>", "Kareen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Krystyna Stanisława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kamila-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kamila</b>.</p><b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Kacey": "<p>Kacey to unisex imię i nazwisko, które mogą odnosić się do: Kacey Ainsworth (ur. 1968), angielskiej aktorki Kacey Bellamy (ur. 1987), amerykańskiej defensywniczki hokeja na lodzie Kacey Carrig (ur. 1992), amerykański model Kacey Clarke (ur. 1988), angielskiego aktorki Kacy Coppola, połowy Kate &amp; Kacey, amerykańskiego duotu muzyki country Kacey Jones (1950-2016), amerykańską piosenkarkę-powieścię, producentkę i humoristę Kacey Jost (ur. 2000), kanadyjską piłkarkę siatkówki...</p>", "Katelin": "<p>Caitlin to żeńskie imię pochodzenia irlandzkiego. Historycznie irlandzka nazwa Caitlín była anglicizowana jako Cathleen lub Kathleen.</p>", "Katlyn": "<p>Caitlin to żeńskie imię pochodzenia irlandzkiego. Historycznie irlandzka nazwa Caitlín była anglicizowana jako Cathleen lub Kathleen.</p>", "Katelynn": "<p>Caitlin to żeńskie imię pochodzenia irlandzkiego. Historycznie irlandzka nazwa Caitlín była anglicizowana jako Cathleen lub Kathleen.</p>", "Khurshida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khurshid</b>.</p><p>Khorshīd lub Khorshēd (perskie: خورشید [xoɾˈʃid], co oznacza Słońce lub \"Słońce promieniowane\"), również pisowniane jako Khurshed i Khurshid, jest perskim nazwiskiem. W dzisiejszych czasach, jak również w historycznym Iranie, Turcji i Azerbejdżanie, ale także w irackim Kurdystanie, Egipcie, Azji Środkowej i Azji Południowej, jest to głównie imię dla chłopców.</p>", "Kaiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kaia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kai</b>.</p><b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Karia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kari</b>.</p><p>Macromonycha (lat.) - rodzaj żółwiek schildonoznosnych (Cassidini) z rodziny liściżerców. Trzy rodzaje.</p>", "Katerini": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Katerin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Katerina</b>.</p><p>Katerina - żeńskie imię, fonetyczny wariant nazwiska Ekaterina.</p>", "Kim Thanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Khrystyna-Hanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Kaylin": "<p>Kaylin, Kaylyn itp. są imionami kobiecymi, a Kaylin znajduje się również jako nazwisko. Do wybitnych osób z tymi nazwami należą:</p>", "Kateri": "<p>Kateri to kobiece imię. Znanymi osobami z nazwiska są: Kateri Amman, hinduska bogini Kateri Akiwenzie-Damm (ur. 1965), kanadyjska pisarka Kateri Champagne Jourdain (ur. 1981), kanadyjskie polityk Kateri Tekakwitha (1656-1680), amerykańska święta</p>", "Karen Viviana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Karol Dayana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karol</b>.</p><b>Karol</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankijskiego</a> oznaczające człowieka mężnego lub wojownika. Staroskandynawskie znaczenie – „człowiek, mąż”. Imię jest również rozpowszechnione w krajach latynoskich.", "Kristianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristiana</b>.</p><p>Kristiana to kobiece imię, odpowiednik Kristian. Znanymi osobami z nazwiska są: Kristiana Gregory Kristiana Levy Kristiana Manu'a Kristiana Petlichka Kristiana Rae Colón</p>", "Krystyna Helena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kathlyn": "<p>Kathlyn to kobiece imię. Wśród znanych osób z nazwiskiem są: Kathlyn Curtis (ur. 1963), kanadyjska sędzia Kathlyn Gilliam (1930-2011), amerykańska aktywistka praw obywatelskich Kathlyn Kelly (1919-2006), amerykańscy sportowca Kathlyn Ragg (ur. 1962), fijianka Kathlyn Williams (1879-1960), amerykańską aktorka</p>", "Khalide": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Khalid</b>.</p><p>Khalid Donnel Robinson - amerykański piosenkarz, laureat i nominac wielu nagród muzycznych.</p>", "Kamelya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kamelia</b>.</p><b>Kamelia</b> – imię żeńskie pochodzące od nazwy <a href=\"https://pl.wikipedia.org/wiki/Kamelia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">kwitnącego krzewu</a> nazwanego na cześć botanika i misjonarza <a href=\"https://pl.wikipedia.org/wiki/Georg_Joseph_Kamel\" target=\"_blank\" rel=\"noopener noreferrer\">Georga Josepha Kamela</a>.", "Kadia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kadi</b>.</p>Od nazwy tej pochodzi <a href=\"https://pl.wikipedia.org/wiki/Alkad\" target=\"_blank\" rel=\"noopener noreferrer\">alkad</a>.", "Krina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Crina</b>.</p><p>Crina to rumuńska nazwisko kobiet. Do znanych osób z nazwiskiem należą: Crina Georgescu (ur. 1960), Rumunijska piłkarka siatkówki Crina Pintea (ur. 1990), Rumuniana piłkarzka handbolu Crina Violeta Serediuc (ur. 1971), rumunska remarka</p>", "Kimberlee": "<p>Kimberley (zwane również Kimberly lub Kimberlee) jest unisex nazwisko pochodzące z staroanglicy. John Wodehouse, 1. hrabia Kimberley, miejscowość w Norfolk w Anglii, upowszechnił nazwę podając go miastu w Południowej Afryce i regionowi w Australii.</p>", "Kamyla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kamila</b>.</p><b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Karen Johanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Klara-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Klara</b>.</p><b>Klara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przymiotnika <i>clarus</i> oznaczającego „jasny”, „jaśniejący”, „sławny”.", "Katarzyna Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Katarzyna</b>.</p><b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Krystyna Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kahori": "<p>Kahori może odnosić się do: Kahori, Azad Kashmir, miasto w Pakistanie Kahori Uchiyama (内山 佳保里; ur. 1975), japoński rąk Kahhori, fikcyjna postać w serialu telewizyjnym What If...?</p>", "Kim Ngan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Katterine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Katerine</b>.</p>Jej pierwszy album <i>Katerine</i> ukazał się w listopadzie 2005 roku. Znajduje się na nim hit <i>Here Come All The Boys</i>. W roku 2006 otrzymała 2 duńskie nagrody <i>Best Female Artist</i> oraz <i>Best Music Video National</i>. Rok później ukazały się jej kolejne utwory <i>Take Me Home</i> oraz <i>Catfight</i>. Następny rok przyniósł artystce występ w belgijskim odpowiedniku programu Gwiazdy tańczą na lodzie - Sterren op het Ijs. Między artystką a wytwórnią jej płyt doszło do nieporozumień, w wyniku których zmieniła wytwórnię na Mostiko.", "Karleen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karlen</b>.</p><p>Karlen lub Karlén to nazwisko. Do wybitnych osób z nazwiskiem należą:</p>", "Kaddy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kady</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kadi</b>.</p>Od nazwy tej pochodzi <a href=\"https://pl.wikipedia.org/wiki/Alkad\" target=\"_blank\" rel=\"noopener noreferrer\">alkad</a>.", "Karen Dayanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Khrystyna-Sofiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Konomi": "<p>Konomi (pisanie: 好美 lub このみ w hiragana) jest kobiece japońskie imię. Wśród znanych osób z tej nazwy są: Konomi Asazu (浅津 このみ; ur. 1986), japoński bobsledder Konomi Inagaki (稲垣 好), japońska aktorka głosowa Konomi Kai (甲斐 好美; ur. 1993), japońskiego skakacza długiego, Konomi Kohara (小原 好美; Ur. 1992), japoanska aktorka głosu, Konomi Suzuki (鈴木 このみ), japończyka piosenkarka Konomi Taniguchi (谷口乃 木実; ur. 1995), japowski piłkarz Konomi Takeishi (武石 この実;...</p>", "Kaussar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kausar</b>.</p><p>Kausar lub Kawthar (arabsko: كَوْثَر) to arabska muzułmańska nazwa zarówno dla mężczyzn, jak i kobiet, co oznacza \"rzeka w raju ozdobioną perlami o zapach słodkiego muszka\", \"biały niż mleko, słodszy niż miód\", \"brąże i złoty banki\", \"obfity\", \"bogaty\", \"obzbrojny\" lub \"obfitoczny\". Nazwa ta jest albo odniesieniem do surah Al-Kawthar lub Hauzu'l-Kausar, świętego jeziora zwanego \"zbiorzem obfitości\" w Raju, wspomnianym w Koranie.</p>", "Kyana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kyan</b>.</p><p>Kyan jest nazwiskiem i nazwiskiem, co oznacza \"starożytne\" lub \"trwałe\". Jest to alternatywne pisownię nazwy Kian, która jest wariantem starożytnego irlandzkiego Cian.</p>", "Krassimira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krasimira</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krasimir</b>.</p><p>Krasimir (bułgarski: Красимир) jest powszechną nazwą męską w Bułgarii. Pochodzi od słów krasi \"piękno, ozdoba\" i mir \"pokój\" lub \"świat\".</p>", "Khrystyna-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Kirstie": "<p>Kirsty lub Kirstie to kobiece imię i nazwa. Jest szkockim diminutiwem Christine w krajach anglojęzycznych i jest również powiązany z Kirsten - skandynawską wersją Christine.</p>", "Khrystyna-Yevheniia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Karen Joy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Khrystyna-Iryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Krystyna Józefa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Karim Mohamed Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karim</b>.</p><b>Karim</b> (<b>كريم</b>) – imię pochodzenia arabskiego, jest czterdziestym trzecim z „Najpiękniejszych imion Allaha”. Oznacza dosłownie „hojny”.", "Kailey": "<p>Kailey () to nowoczesne angielskie imię dla kobiet. Jest to wariant literacki Kaylee, który stał się popularny w USA po wydaniu brytyjskiej grupy rockowej Marillion piosenkę \"Kayleigh\" w 1985 roku.</p>", "Kim Thoa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Kirsi": "<p>Kirsi to fińskie imię dla kobiet. Jego dzień uroczystości obchodzony jest 24 lipca.</p>", "Karya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kari</b>.</p><p>Macromonycha (lat.) - rodzaj żółwiek schildonoznosnych (Cassidini) z rodziny liściżerców. Trzy rodzaje.</p>", "Krystyna Halina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Karolyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karol</b>.</p><b>Karol</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankijskiego</a> oznaczające człowieka mężnego lub wojownika. Staroskandynawskie znaczenie – „człowiek, mąż”. Imię jest również rozpowszechnione w krajach latynoskich.", "Kathi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kathy</b>.</p><p>Kathy to kobiece imię. Często jest skróceniem dla innych nazw.</p>", "Kazina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kaz</b>.</p><p>Kazimieras Gediminas ⁇ Kaz ⁇ Prapuolenis (ang. Kazimieras Gedigiminas ?? Kaz ⁇ Prapuolenis; 31 lipca 1959, Hoboken) - amerykański artysta, ilustrator i scenarzysta pochodzenia litewskiego.</p>", "Krishna Kumari": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krishna</b>.</p><p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Kamiła": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kamyla</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kamila</b>.</p><b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Karol Daniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karol</b>.</p><b>Karol</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankijskiego</a> oznaczające człowieka mężnego lub wojownika. Staroskandynawskie znaczenie – „człowiek, mąż”. Imię jest również rozpowszechnione w krajach latynoskich.", "Ksennia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ksenia</b>.</p><b>Ksenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „gościnna” (Ξενία, dosł. „życzliwa dla obcych”), popularne zwłaszcza w krajach prawosławnych: rosyjskie <b>Ксения</b> (<i><b>Ksienija</b></i>), <b>Аксиния</b> (<i><b>Aksinija</b></i>), ukraińskie <b>Ксенія</b> (<i><b>Ksenija</b></i>), <b>Ксеня</b> (<i><b>Ksenia</b></i>) oraz pochodne <b>Оксана</b> (<i><b>Oksana</b></i>), białoruskie <b>Ксенія</b> (<i><b>Ksenìâ</b></i>), czeskie <b>Xenie</b>, słowackie <b>Xeni</b>.", "Karlie": "<p>Karlie to angielskie i szwedzkie imię żeńskie, które jest kobiecą formą Karla, diminutiwną formą Karli i alternatywną formą karly. Do znanych osób z tej nazwy należą:</p>", "Kesar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Cesar</b>.</p><p>William McNeill (ang. William McNeil; 2 marca 1940, Bellshill, North Lanarkshire, Szkocja - 22 kwietnia 2019, Newton-Mirns, Szkocia), bardziej znany jako Billy McNeill</p>", "Karen Johana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Karen Nataly": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Klaudia Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Klaudia</b>.</p><b>Klaudia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Claudia</em>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego. Wywodzi się od nazwy rzymskiego rodu Klaudiuszów. Imię <a href=\"https://pl.wikipedia.org/wiki/Klaudia_(z_Klaudiusz%C3%B3w)\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudia</a> nosiły wszystkie kobiety z tego rodu. Odnotowano trzy święte katolickie o tym imieniu. Istnieje też pochodna forma tego imienia: <a href=\"https://pl.wikipedia.org/wiki/Klaudyna\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudyna</a>.", "Kehlani": "Kehlani pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Oakland\" target=\"_blank\" rel=\"noopener noreferrer\">Oakland</a> w <a href=\"https://pl.wikipedia.org/wiki/Kalifornia\" target=\"_blank\" rel=\"noopener noreferrer\">Kalifornii</a>, gdzie osiągnęła początkową sławę jako członek grupy popowej Poplyfe, która była finalistą <a href=\"https://pl.wikipedia.org/wiki/America%E2%80%99s_Got_Talent\" target=\"_blank\" rel=\"noopener noreferrer\">America’s Got Talent</a>. W 2014 roku wydała swój pierwszy <a href=\"https://pl.wikipedia.org/wiki/Mixtape\" target=\"_blank\" rel=\"noopener noreferrer\">mixtape</a> <i>Cloud 19</i>. Album ten znalazł się na liście 50 najlepszych albumów w 2014 stworzonej przez Complex&#65279;<a href=\"https://www.wikidata.org/wiki/Q5156550#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>. Drugi <a href=\"https://pl.wikipedia.org/wiki/Mixtape\" target=\"_blank\" rel=\"noopener noreferrer\">mixtape</a> Kehlani, <i>You Should Be Here</i>, zadebiutował jako 5 na amerykańskim rankingu R&amp;B/Hip-Hop w roku 2015. Poprzedził on wyprzedaną trasę koncertową po <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Północnej Ameryce</a>. W 2016 roku jej album <i>You should be here</i> został nominowany do <a href=\"https://pl.wikipedia.org/wiki/Nagroda_Grammy\" target=\"_blank\" rel=\"noopener noreferrer\">nagrody Grammy</a> jako Best Urban Contemporary Album. Debiutancki album studyjny Kehlani, <i>SweetSexySavage</i>, został wydany 27 stycznia 2017 roku.", "Klara-Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Klara</b>.</p><b>Klara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przymiotnika <i>clarus</i> oznaczającego „jasny”, „jaśniejący”, „sławny”.", "Kim Trinh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Kai-Ting": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kai</b>.</p><b>Gerard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „oszczep”, „silny” lub „odważny”.", "Krystyna Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kelly Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kelly</b>.</p><p>Kelly (ang. Kelly, Kelley, Kellie), początkowo O'Kelly (irl.</p>", "Kri̇stína": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kim Hoa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Karen Andrea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Keremet": "<b>Keremet</b> – bóstwo panteonu Finów permskich (<a href=\"https://pl.wikipedia.org/wiki/Udmurci\" target=\"_blank\" rel=\"noopener noreferrer\">Udmurtów</a>). Nazwa zapożyczona od ludów tureckich oznaczająca \"ducha ważnej osobistości\". Nazywany również Łudem lub Szajtenem. Przeciwieństwo dobrego – Inmara, jednak o podobnej mocy. Inmar był prawdopodobnie jego bratem. Keremet jest zły i inteligentny. Panuje nad światem podziemnym i złymi duchami. Razem ze swoim bratem brał czynny udział w stwarzaniu ziemi. Inmar wysłał go po odrobinę gleby z dna morskiego, by z niej stworzyć świat. Rysuje się tu znany motyw kosmogoniczny: świat zostaje stworzony przy współpracy dobrego i złego boga, i to zły dokonuje zanurzenia w morzu, gdyż to on sprawuje nad nim władzę. Z kawałka ziemi ukrytej przed Inmarem w ustach, Keremet stwarza góry. Jest on również przyczyną unicestwienia lub wygnania pierwszych ludzi, gdyż za jego namową spożywają oni napój zabroniony przez Inamara – <a href=\"https://pl.wikipedia.org/wiki/Kumys\" target=\"_blank\" rel=\"noopener noreferrer\">kumys</a>. W świętych gajach (również nazywanych keremetami lub łudami) składano mu w ofierze zwierzęta o czarnej sierści.", "Klaudiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Klaudia</b>.</p><b>Klaudia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Claudia</em>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego. Wywodzi się od nazwy rzymskiego rodu Klaudiuszów. Imię <a href=\"https://pl.wikipedia.org/wiki/Klaudia_(z_Klaudiusz%C3%B3w)\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudia</a> nosiły wszystkie kobiety z tego rodu. Odnotowano trzy święte katolickie o tym imieniu. Istnieje też pochodna forma tego imienia: <a href=\"https://pl.wikipedia.org/wiki/Klaudyna\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudyna</a>.", "Kordiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kordian</b>.</p><b>Kordian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone przez <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a>. Oznacza <i>dający serce</i>. Kordian obchodzi imieniny <a href=\"https://pl.wikipedia.org/wiki/22_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">22 października</a>.", "Katarzyna Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Katarzyna</b>.</p><b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Kazimiera Helena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kazimiera</b>.</p><b>Kazimiera</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kazimierz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kazimierz</a>. W średniowieczu nie występowało. Prawdopodobnie rozpowszechniło się pod koniec XVII wieku, po przyjeździe do Polski <a href=\"https://pl.wikipedia.org/wiki/Maria_Kazimiera_d%E2%80%99Arquien\" target=\"_blank\" rel=\"noopener noreferrer\">Marysieńki</a>, żony króla <a href=\"https://pl.wikipedia.org/wiki/Jan_III_Sobieski\" target=\"_blank\" rel=\"noopener noreferrer\">Jana III Sobieskiego</a>.", "Kristiyana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristiyan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kristian</b>.</p><b>Krystian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Christianus</em>, <i>Cristianus</i> oznaczające „chrześcijanin, wyznawca Chrystusa”.", "Katarzyna Marta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Katarzyna</b>.</p><b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Kayli": "<p>Kaylee (i jego różne pisowni) to imiona żeńskie. Nazwa jest współczesnym angielskim połączeniem elementów imienia Kay i Lee.</p>", "Krystyna Danuta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Koralie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Coralie</b>.</p><p>Coralie to francuskie nazwisko kobiece oznaczające \"koral\", pochodzące od łacińskiego słowa coralium. Było to ósmie najpopularniejsze imię dla dziewczynek w Quebecu w 2007 roku.</p>", "Karen Liceth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kim Phung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Kirra": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kira</b>.</p><b>Cyra</b>, <i>Kira</i> – żeński odpowiednik męskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Cyrus\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrus</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Marana_i_Cyra\" target=\"_blank\" rel=\"noopener noreferrer\">św. Cyra</a> z V wieku.", "Karien": "<p>Karien to afrykaanska i holenderska kobieca nazwa. Do znanych osób z tej nazwy należą: Karien Robbers (ur. 1993), holenderski remnik.</p>", "Kanizja": "<b>Kanizja</b> – imię żeńskie pochodzące od nazwiska św. <a href=\"https://pl.wikipedia.org/wiki/Piotr_Kanizjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Piotra Kanizjusza</a>, doktora Kościoła. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ogos%C5%82awiona\" target=\"_blank\" rel=\"noopener noreferrer\">bł.</a> <a href=\"https://pl.wikipedia.org/wiki/Maria_Kanizja\" target=\"_blank\" rel=\"noopener noreferrer\">Maria Kanizja</a> (Eugenia Mackiewicz), siostra nazaretanka, wspominana razem z bł. Marią Stellą i innymi towarzyszkami.", "Klymentyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Klimentina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kliment</b>.</p><p>Kliment (cyrylicki: Климент) to męskie imię, słowiańska forma późnolatynskiej nazwy Klement. Klim jest formą mniejszą.</p>", "Karen Sofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Karol Sofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karol</b>.</p><b>Karol</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankijskiego</a> oznaczające człowieka mężnego lub wojownika. Staroskandynawskie znaczenie – „człowiek, mąż”. Imię jest również rozpowszechnione w krajach latynoskich.", "Kalie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kali</b>.</p><p>Kali (lat. Kali) - rodzaj promieniowanych ryb z rodziny żółtych (Chiasmodontidae).</p>", "Karen Vanesa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kelly-Ann": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kelly</b>.</p><p>Kelly (ang. Kelly, Kelley, Kellie), początkowo O'Kelly (irl.</p>", "Krishna Maya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krishna</b>.</p><p>Krishna (/ˈkrɪʃnə/, św. Krishna; IAST: Kṛṣṇa) jest głównym bogiem w hinduizmie. Jest czczony jako członek wiosny i sam jest wielkim bogiem.</p>", "Kim Xuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Karen Fernanda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kameela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kameel</b>.</p><p>Kamil to imię używane w wielu językach. Kamil to polskie, czeskie i słowackie imię, równoważne włoskiemu Camillo, hiszpańsko-portugalskiemu Camilo i francuskiemu Camille.</p>", "Kim Ngọc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Kim Hai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Krystyna Aleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Krystyna Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kelly Rocio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kelly</b>.</p><p>Kelly (ang. Kelly, Kelley, Kellie), początkowo O'Kelly (irl.</p>", "Karen Liseth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kamila-Kateryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kamila</b>.</p><b>Kamila</b>, <i><b>Kamilla</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kamil\" target=\"_blank\" rel=\"noopener noreferrer\">Kamil</a>, pochodzenia łacińskiego. Wśród imion nadawanych nowo narodzonym dzieciom, Kamila w 2009 r. zajmowała 41. miejsce w grupie imion żeńskich. W 2001 roku imię z podwójnym L nosiło 4107 osób, z pojedynczym – 90 900. Forma Kamilla budzi wątpliwości normatywistów; jest notowana w Nowym Słowniku poprawnej polszczyzny pod redakcją <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Markowski_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja Markowskiego</a>, z zastrzeżeniem, że jest to forma niezalecana. Jednocześnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> odnotowała tę formę w aneksie do listy pn. <i>Obowiązujący wykaz imion</i> jako zgodną z zasadami ortograficznymi polszczyzny. Obecnie <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> nie wydaje już obowiązujących wykazów imion.", "Keerti": "<p>Keerthi, również pisane Keerti, Keerthy lub Kirti, to indyjskie imienne. Może odnosić się do: Keerti Gaekwad Kelkar (ur. 1974), indyjska aktorka i modelka Keerti Nagpure (ur.</p>", "Kayley": "<p>Kaylee (i jego różne pisowni) to imiona żeńskie. Nazwa jest współczesnym angielskim połączeniem elementów imienia Kay i Lee.</p>", "Karina Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karina</b>.</p><b>Karina</b>, <b>Karyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z jęz. niemieckiego; forma zdrobniała od imienia <i>Katarina</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Katarzyna\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna</a>). Inna hipoteza mówi, że wywodzi się od słowa <i>cara</i>, które po <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacinie</a> oznacza \"kochana, droga\" lub w galickim \"przyjaciel\". Jeszcze inna hipoteza mówi, że pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">konstelacji</a> <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Kila\" target=\"_blank\" rel=\"noopener noreferrer\">Kil</a>, nazwanej w związku kilem statku <a href=\"https://pl.wikipedia.org/wiki/Jazon_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jazona</a>.", "Krzysztosława": "Etymologia imienia nie jest jasna, podawane są dwie hipotezy dotyczące jego pochodzenia. Według pierwszej jest to imię wywodzące się z czasów pogańskich i z tradycji słowiańskiej, które do dziś przetrwało w lekko zmienionej formie. Druga mówi, że pochodzi ono od imienia <i>Krzysztof</i>, które na terenach Grecji we wczesnych czasach chrześcijańskich oznaczało gorliwego wyznawcę religii chrystusowej, człowieka nawróconego, co mogłoby sugerować, że znaczenie imienia <i>Krzysztosława</i> to <i>sławiąca wyznawców Chrystusa</i>.", "Kjersti": "<p>Kjersti jest norweską nazwą żeńską, norweską formą Christina. Znanymi osobami z nazwiska są: Kjersti Alveberg (ur. 1948), norweska choreografka i tancerka Kjersti Bale (ur. 1959), norweski filolog Kjersti Beck (ur. 1979), norweskiej piłkarz handbalowy Kjersti Buaas (ur. 1982), norweskowy snowboarder Kjersti Døvigen (1943-2021), norweską aktorkę Kjersti Engan (ur. 1971), norweskie badacz w dziedzinie sygnału i...</p>", "Kim Phuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kim</b>.</p><p>⁇ Kim ⁇ - piosenka amerykańskiego repera Eminema z jego trzeciego albumu studiowego ⁇ The Marshall Mathers LP ⁇ (2000). Piosenka odzwierciedla silny gniew i nienawiść wobec jego żony Kim Matters.</p>", "Krystyna Irena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Karen Juliana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kassylda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kasylda</b>.</p><b>Kasylda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od imienia <a href=\"https://pl.wikipedia.org/wiki/Kasja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasja</a>. Jego patronką jest św. <a href=\"https://pl.wikipedia.org/wiki/Kasylda_z_Toledo\" target=\"_blank\" rel=\"noopener noreferrer\">Kasylda z Toledo</a>.", "Khrystyna-Olena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Krysten": "<p>Krysten Anderson, amerykański profesjonalny kierowca ciężarówki. Krysten Boogaard, kanadyjski centrum koszykówki Krysten Cummings, amerykańska aktorka sceniczna i filmowa Krysten Moore, amerykański nastolatek aktywistka Krysten Ritter, amerykańskiej aktorki</p>", "Kumi": "<b>Kumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;くみ, クミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Kotono": "<p>Kotono (pisanie 琴乃) jest kobiece japońskie imię. Znanymi osobami z tej nazwy są: Kotono Mitsuishi (三石 琴乃; ur. 1967), japońska aktorka głosowa i narrator Kotono Shibuya (渋谷 琴乃, ur. 1975), japońską aktorkę i śpiewaczkę Kotono Shirai (白井琴望, ur. 2002), japoński aktorka i disk jockey i były członek grupy idoli SKE48 Kotono Tanaka (田中 琴乃 , ur. 1991), japowski gimnast rytmiczny</p>", "Kaytlyn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kaitlin</b>.</p><p>Caitlin to żeńskie imię pochodzenia irlandzkiego. Historycznie irlandzka nazwa Caitlín była anglicizowana jako Cathleen lub Kathleen.</p>", "Kaitlynn": "<p>Caitlin to żeńskie imię pochodzenia irlandzkiego. Historycznie irlandzka nazwa Caitlín była anglicizowana jako Cathleen lub Kathleen.</p>", "Klelia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Clelia</b>.</p><p>Mussurany lub klelia (lat. Clelia) - rodzaj węży z rodziny już podobnych.</p>", "Karmella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Carmella</b>.</p><p>Lia Van Dale (ang. Leah Van Dale; rodzaj.</p>", "Kwieta": "<b>Kwieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „spokojna”. Patronką tego imienia jest św. Kwieta, wspominana według jednych źródeł wspólnie ze św. Teodorą, zaś zgodnie z innymi – ze św. Hilarym, swoim mężem.", "Karenn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Krysa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Krys</b>.</p><p>Krys to przede wszystkim męskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Krystyna Elżbieta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Karrin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karin</b>.</p><p>Karin (jap. かりん Karin) - 24-seryjny anime-serial, nadawany w Japonii od 3 listopada 2005 r. do 11 maja 2006 r.</p>", "Krystyna Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Kiyoko": "<b>Kiyoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;きよこ, キヨコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Kirsti": "<p>Kirsti to kobiece imię. Wśród powiązanych nazw Kersti, Kirsten, Kjersti.</p>", "Krisi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kris</b>.</p><p>Chris (pol. Kris; prawdziwe imię - Kshshштоf Piotrovski, płeć.</p>", "Katarzyna Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Katarzyna</b>.</p><b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Kandida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kandyda</b>.</p><b>Kandyda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Kandyd_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kandyd</a>, oznaczające \"jasna, błyszcząca, biała\", czyli \"dziecko o jasnych włosach\" lub \"dziecko o jasnej <a href=\"https://pl.wikipedia.org/wiki/Karnacja\" target=\"_blank\" rel=\"noopener noreferrer\">cerze</a>\"; jeden z najpopularniejszych <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomków</a> rzymskich. W Polsce notowane od <a href=\"https://pl.wikipedia.org/wiki/1396\" target=\"_blank\" rel=\"noopener noreferrer\">1396</a> roku.", "Khrystyna-Vasylyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Koharu": "<p>Koharu (pisanie: 小春 lub コハル w katakana) jest kobiece japońskie imię, które czasami używane jest dla mężczyzn. Do wybitnych osób z tym nazwiskiem należą:</p>", "Kismet": "<b>Kismet</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">tureckie</a> słowo oznaczające <a href=\"https://pl.wikipedia.org/wiki/Przeznaczenie\" target=\"_blank\" rel=\"noopener noreferrer\">przeznaczenie</a>, <a href=\"https://pl.wikipedia.org/wiki/Fatum\" target=\"_blank\" rel=\"noopener noreferrer\">fatum</a>, los. Używane przez <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmańskie</a> ludy tureckie oraz na terenach pozostających przez wieki pod tureckim panowaniem (<a href=\"https://pl.wikipedia.org/wiki/Bo%C5%9Bnia_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Bośnia</a>, <a href=\"https://pl.wikipedia.org/wiki/Chorwacja\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwacja</a>, <a href=\"https://pl.wikipedia.org/wiki/Serbia\" target=\"_blank\" rel=\"noopener noreferrer\">Serbia</a>, <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgaria</a>).", "Kety": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Keti</b>.</p><p>Qeti jest miastem w prowincji Shirak w Armenii. W 2011 roku liczba ludności wynosiła 1095 osób.</p>", "Kazimiera Wanda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kazimiera</b>.</p><b>Kazimiera</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kazimierz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kazimierz</a>. W średniowieczu nie występowało. Prawdopodobnie rozpowszechniło się pod koniec XVII wieku, po przyjeździe do Polski <a href=\"https://pl.wikipedia.org/wiki/Maria_Kazimiera_d%E2%80%99Arquien\" target=\"_blank\" rel=\"noopener noreferrer\">Marysieńki</a>, żony króla <a href=\"https://pl.wikipedia.org/wiki/Jan_III_Sobieski\" target=\"_blank\" rel=\"noopener noreferrer\">Jana III Sobieskiego</a>.", "Karen Margarita": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Karabo": "<p>Karabo to imię na południu Afryki i może odnosić się do: Karabo Dhlamini (ur. 2001), piłkarz Karabo Makhurubetshi (ur. 1999), piłkaraz Karabo Mathang-Tshabuse, agent piłkarski Karabo Meso (ur. 2007), kryker Karabo Modise (ur. 1988), krykera Motswana Karabo Motlhanka (ur. 1992), krykerowa Motswana Karaba Mothibi (ur. 1996), atleta Motswana Karabu Poppy, południowa...</p>", "Kazimiera Stanisława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kazimiera</b>.</p><b>Kazimiera</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kazimierz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kazimierz</a>. W średniowieczu nie występowało. Prawdopodobnie rozpowszechniło się pod koniec XVII wieku, po przyjeździe do Polski <a href=\"https://pl.wikipedia.org/wiki/Maria_Kazimiera_d%E2%80%99Arquien\" target=\"_blank\" rel=\"noopener noreferrer\">Marysieńki</a>, żony króla <a href=\"https://pl.wikipedia.org/wiki/Jan_III_Sobieski\" target=\"_blank\" rel=\"noopener noreferrer\">Jana III Sobieskiego</a>.", "Kazyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kaz</b>.</p><p>Kazimieras Gediminas ⁇ Kaz ⁇ Prapuolenis (ang. Kazimieras Gedigiminas ?? Kaz ⁇ Prapuolenis; 31 lipca 1959, Hoboken) - amerykański artysta, ilustrator i scenarzysta pochodzenia litewskiego.</p>", "Khrystyna-Anastasiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khrystyna</b>.</p><p>Chrystyna (ukraina: Христина) to ukraińskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą: Chrystyna Alchevska, ukraińska nauczycielka i wybitny działacz na rzecz edukacji narodowej w cesarskiej Rosji.</p>", "Klimentina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kliment</b>.</p><p>Kliment (cyrylicki: Климент) to męskie imię, słowiańska forma późnolatynskiej nazwy Klement. Klim jest formą mniejszą.</p>", "Kłaudia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Claudia</b>.</p><p>Klawdii (lat. Claudia; I wiek) - matka św. Lin, papieża Rzymu.</p>", "Kiyara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kiara</b>.</p><p>Kiara (ang. Kiara, Ciara) lub Hier (ang.</p>", "Katlego": "<p>Katlego (zwany również Katleho w północnym Sotho) jest unisex nazwisko pochodzenia Sotho-Tswana oznaczające sukces lub dobrobyt. Wśród znanych osób z imieniem są: Katlego Danke (ur. 1978), aktorka z Południowej Afryki Katlego Kai Kolanyane-Kesupile (ur. 1988), artysta z Botswany i aktywistka LGBT Katlego Maboe (ur. 1986), prezenter telewizyjny z Połedniowej Afrii Katlego Maphathe (ur. 1993), piłkarz z Połodniowej Afriki Katlego Mashego (ur. 1982), South...</p>", "Karyna-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karyna</b>.</p><b>Karina</b>, <b>Karyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z jęz. niemieckiego; forma zdrobniała od imienia <i>Katarina</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Katarzyna\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna</a>). Inna hipoteza mówi, że wywodzi się od słowa <i>cara</i>, które po <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacinie</a> oznacza \"kochana, droga\" lub w galickim \"przyjaciel\". Jeszcze inna hipoteza mówi, że pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">konstelacji</a> <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Kila\" target=\"_blank\" rel=\"noopener noreferrer\">Kil</a>, nazwanej w związku kilem statku <a href=\"https://pl.wikipedia.org/wiki/Jazon_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jazona</a>.", "Khanyisile": "<p>Khanyisile to imiona żeńskie, pochodzące od słowa Nguni khanya, co oznacza \"światło\".</p>", "Karen Valentina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kaliope": "Imieniem muzy została nazwana jedna z planetoid – <a href=\"https://pl.wikipedia.org/wiki/(22)_Kalliope\" target=\"_blank\" rel=\"noopener noreferrer\">(22) Kalliope</a>.", "Ka̋the": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kate</b>.</p><p>Kate (KDE Advanced Text Editor) - redaktor tekstu w skład środowiska pracy KDE. Rozprzestrzegana jest na podstawie GNU General Public License.</p>", "Karen Mae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Kwietosława": "<b>Florianna</b>, <b>Floriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Florian\" target=\"_blank\" rel=\"noopener noreferrer\">Florian</a>, które z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>florus</i> – „kwitnący” i oznacza „należący do <i>Florusa</i>”. <b>Florianna</b> jest nadawana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>, a po raz pierwszy zapisana była w formie <i><b>Floryjana</b></i>. Zanotowano także zdrobnienie Floszka, oraz drugie, Tworka, które mogło pochodzić od Florianny z substytucją polską (jak Florian → Tworzyjan), lub też od imion rodzimych zaczynających się na <i>Tworzy-</i>.", "Kallista": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kalista</b>.</p><b>Kalista</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego \"najpiękniejsze\". Jest odpowiednikiem męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Kalikst\" target=\"_blank\" rel=\"noopener noreferrer\">Kalikst</a>. Istnieją dwie święte o tym imieniu.", "Kelsie": "<p>Kelsie to unisex. Do znanych osób z imieniem Kelsie B.</p>", "Katarzyna Józefa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Katarzyna</b>.</p><b>Katarzyna</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;καθαρός, „czysta”, „bez skazy”. Do Polski imię to trafiło za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>.", "Kartini": "Pochodziła z jawajskiej rodziny <a href=\"https://pl.wikipedia.org/wiki/Arystokracja\" target=\"_blank\" rel=\"noopener noreferrer\">arystokratycznej</a>, otrzymała zachodnie wykształcenie. Podkreślała konieczność <a href=\"https://pl.wikipedia.org/wiki/Edukacja_kobiet\" target=\"_blank\" rel=\"noopener noreferrer\">edukacji kobiet</a>, występowała przeciwko <a href=\"https://pl.wikipedia.org/wiki/Poligamia\" target=\"_blank\" rel=\"noopener noreferrer\">poligamii</a> i <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82%C5%BCe%C5%84stwa_dzieci\" target=\"_blank\" rel=\"noopener noreferrer\">dziecięcym małżeństwom</a>. Zmarła przy porodzie. Opublikowano, pod tytułem <i>Z ciemności w jasność</i>, zbiór listów jej autorstwa. Książka ta przyczyniła się do popularyzacji poglądów Kartini. Powstały również, z inicjatywy jej zwolenników, szkoły dla kobiet, zwane szkołami Kartini.", "Karen Milena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karen</b>.</p><p>Karen może odnosić się do: Karen Angle Karen Brucene Smith Karen Dianne Baldwin</p>", "Karolina Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Karolina</b>.</p><b>Karolina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>. Innym żeńskim odpowiednikiem imienia Karol jest <a href=\"https://pl.wikipedia.org/wiki/Karola\" target=\"_blank\" rel=\"noopener noreferrer\">Karola</a>. Imię Karolina jest pochodzenia starogermańskiego, od słowa charal, carl.", "Khalid I": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Khalid</b>.</p><p>Khalid Donnel Robinson - amerykański piosenkarz, laureat i nominac wielu nagród muzycznych.</p>", "Kazimiera Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kazimiera</b>.</p><b>Kazimiera</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Kazimierz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kazimierz</a>. W średniowieczu nie występowało. Prawdopodobnie rozpowszechniło się pod koniec XVII wieku, po przyjeździe do Polski <a href=\"https://pl.wikipedia.org/wiki/Maria_Kazimiera_d%E2%80%99Arquien\" target=\"_blank\" rel=\"noopener noreferrer\">Marysieńki</a>, żony króla <a href=\"https://pl.wikipedia.org/wiki/Jan_III_Sobieski\" target=\"_blank\" rel=\"noopener noreferrer\">Jana III Sobieskiego</a>.", "Krystyna Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Krystyna</b>.</p><b>Krystyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Krystyn\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyn</a> (<i>Christinus</i>). Oznacza „należącą do Chrystusa”.", "Károlyné": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Karolyn</b>.</p><p>Karolyn to angielskie i szwedzkie imię żeńskie, które jest diminutiwną formą Carolina i Caroline, a także alternatywną formą Karolin. Do wybitnych osób, o których mowa w tej nazwie, należą:</p>", "Kaaya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kaya</b>.</p><p>Kaya - dziesiąty album studiowy jamajskiego zespołu reggae Bob Marley &amp; The Wailers, wydany w 1978 roku. Album składa się z kompozycji zapisanego w tym samym czasie z materiałem dla poprzedniego albumu Exodus.</p>", "Ksenna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ksena</b>.</p><p>Avksenty (rosyjski: Авксе́нтий) to rosyjskie imię chrześcijańskie męskie. Nazwa pochodzi od greckiego imienia Auxentios, które z kolei pochodzi od słowa auxano, co oznacza wzrost, wzrost.</p>", "Khawlah": "<p>Khawlah lub Khawla (arabicko: خولة) to kobiece arabskie imię, co oznacza \"żółta. \"</p>", "Katiusza": "<i>Katiusza</i> to zdrobnienie popularnego w Rosji żeńskiego imienia Jekatierina (<a href=\"https://pl.wikipedia.org/wiki/Katarzyna\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna</a>), „Kasieńka”, „Kaśka” – taki też tytuł nosiła popularna podczas wojny w Związku Radzieckim <a href=\"https://pl.wikipedia.org/wiki/Katiusza_(utw%C3%B3r)\" target=\"_blank\" rel=\"noopener noreferrer\">piosenka</a> mówiąca o tęsknocie dziewczyny do ukochanego, który odbywa służbę wojskową.", "Kerrie": "<p>Kerrie to kobiece imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Kelly Tatiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Kelly</b>.</p><p>Kelly (ang. Kelly, Kelley, Kellie), początkowo O'Kelly (irl.</p>", "Kalya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Kalia</b>.</p><b>Cantedeskia</b>, kalijka, kalia (<i>Zantedeschia</i> Spreng.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Obrazkowate\" target=\"_blank\" rel=\"noopener noreferrer\">obrazkowatych</a>, obejmujący 8 <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a> pochodzących ze środkowo-południowej <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>, z jednym gatunkiem introdukowanym na wszystkich kontynentach z wyjątkiem Antarktydy. Z uwagi na bardzo atrakcyjne kwiatostany i ulistnienie cantedeskie, zarówno gatunki botaniczne, jak i ich <a href=\"https://pl.wikipedia.org/wiki/Kultywar\" target=\"_blank\" rel=\"noopener noreferrer\">kultywary</a>, są szeroko uprawiane na świecie jako <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny_ozdobne\" target=\"_blank\" rel=\"noopener noreferrer\">rośliny ozdobne</a>."};
